// CRITICAL GUARDRAIL ERROR HANDLER
window.handleSyncError = function(e, context) {
  if (e instanceof ReferenceError || e instanceof TypeError || e instanceof SyntaxError) {
    console.error('CRITICAL SYSTEM FAULT [' + context + ']:', e);
    alert('CRITICAL SYSTEM ERROR in ' + context + ': ' + e.message + '\n\nPlease refresh the page.');
    throw e;
  }
  if (typeof toast !== 'undefined') toast(context + ': ' + e.message, 'warn');
};

// ============================================================ STATE
const ST={portal:null,hView:'h-dashboard',aView:'a-overview',sView:'s-dashboard',xView:'x-dashboard',curFid:'test-a',hFid:'test-a',curSystemId:null,aTab:'all',facTab:'staff',charts:{},user:null,staffId:null};

function killChart(k){ if(ST.charts[k]){ST.charts[k].destroy();delete ST.charts[k];} }
function mkChart(k,el,cfg){ killChart(k); ST.charts[k]=new Chart(el,cfg); return ST.charts[k]; }

// ============================================================ AUTH STYLES HELPER
function switchAuthTab(tab){
  document.getElementById('tab-signin').classList.toggle('active',tab==='signin');
  document.getElementById('tab-register').classList.toggle('active',tab==='register');
  document.getElementById('auth-signin').style.display=tab==='signin'?'block':'none';
  document.getElementById('auth-register').style.display=tab==='register'?'block':'none';
  const forgotEl=document.getElementById('auth-forgot');
  const sentEl=document.getElementById('auth-forgot-sent');
  if(forgotEl) forgotEl.style.display='none';
  if(sentEl) sentEl.style.display='none';
  document.getElementById('auth-error').style.display='none';
  document.getElementById('reg-error').style.display='none';
}

function showLogin(){
  document.getElementById('pending-screen').classList.add('hidden');
  const resetOvl = document.getElementById('auth-reset-overlay');
  if(resetOvl) resetOvl.classList.add('hidden');
  document.getElementById('login').classList.remove('hidden');
}

function fillCreds(email, pass){
  switchAuthTab('signin');
  document.getElementById('si-email').value=email;
  document.getElementById('si-pass').value=pass;
  document.getElementById('auth-error').style.display='none';
}

async function doLogin(preAuthSession=null){
  let email, pass;
  const errEl = document.getElementById('auth-error');

  if (!preAuthSession) {
    if(!Security.rateLimit('login',5,60000)){
      if(errEl){
        errEl.textContent='Too many sign-in attempts. Please wait 60 seconds.';
        errEl.style.display='block';
      }
      return;
    }
    email=(document.getElementById('si-email').value||'').trim().toLowerCase();
    pass=(document.getElementById('si-pass').value||'').trim();
    if(!email||!pass){if(errEl){errEl.textContent='Please enter your email and password.';errEl.style.display='block';}return;}
  }

  const btn = document.querySelector('button[onclick="doLogin()"]');
  const orgBtnHTML = btn ? btn.innerHTML : '';
  if(btn){ btn.disabled = true; btn.innerHTML = '<span class="spinner" style="border-width:2px;width:14px;height:14px;margin-right:6px;display:inline-block"></span> Authenticating...'; }

  window.SBD_LOGIN_IN_PROGRESS = true;
  try {
    const sessionRes = preAuthSession || await SB_AUTH.signIn(email, pass);
    if (!sessionRes || !sessionRes.user) throw new Error("Invalid credentials");

    
    // Fetch profile from LIVE db
    const profiles = await SB.getUserProfile(sessionRes.user.id);
    let userProfile = profiles && profiles.length > 0 ? profiles[0] : null;

    if(!userProfile) throw new Error('Your user profile could not be found. Please contact support.');

    if(btn){ btn.innerHTML = '<span class="spinner" style="border-width:2px;width:14px;height:14px;margin-right:6px;display:inline-block"></span> Signing in...'; }
    
    // Map user profile BEFORE hydration so ST.user is set when initAppData's
    // refreshDashboard fires — preventing the `if(!ST.user) return logout()` guard
    // from nuking state mid-login.
    if(typeof mapUserFromBackend === 'function') {
      userProfile = mapUserFromBackend(userProfile);
    } else {
      userProfile.fid = userProfile.facility_id;
      userProfile.systemId = userProfile.system_id;
      userProfile.assignedFids = userProfile.assigned_fids;
    }
    ST.user = userProfile;

    // -- HYDRATE MEMORY CACHE WITH LIVE DATA --
    await initAppData();

    errEl.style.display='none';
    
    const roleMap={
      'master_admin':'admin','staff_admin':'admin',
      'hospital':'hospital','facility_admin':'hospital',
      'system_admin':'system_admin','staff_member':'staff_member'
    };
    enterPortal(roleMap[ST.user.role]||'hospital');
  } catch(e) {
    errEl.textContent = e.message || 'Invalid email or password. Please try again.';
    errEl.style.display='block';
  } finally {
    window.SBD_LOGIN_IN_PROGRESS = false;
    if(btn){ btn.disabled = false; btn.innerHTML = orgBtnHTML; }
  }
}

function doRegister(){
  const fname=(document.getElementById('reg-fname').value||'').trim();
  const loc=(document.getElementById('reg-loc').value||'').trim();
  const dept=(document.getElementById('reg-dept').value||'').trim();
  const reqRole=(document.getElementById('reg-requested-role').value||'staff_member');
  const contact=(document.getElementById('reg-contact').value||'').trim();
  const email=(document.getElementById('reg-email').value||'').trim();
  const pass=(document.getElementById('reg-pass').value||'').trim();
  const pass2=(document.getElementById('reg-pass2').value||'').trim();
  const errEl=document.getElementById('reg-error');
  if(!fname||!loc||!dept||!contact||!email){errEl.textContent='Please fill in all required fields.';errEl.style.display='block';return;}
  if(!pass||pass.length<6){errEl.textContent='Password must be at least 6 characters.';errEl.style.display='block';return;}
  if(pass!==pass2){errEl.textContent='Passwords do not match.';errEl.style.display='block';return;}
  if(DB.users.find(u=>u.email.toLowerCase()===email.toLowerCase())||DB.pendingRegs.find(r=>r.email.toLowerCase()===email.toLowerCase())){errEl.textContent='An account with this email already exists or is pending review.';errEl.style.display='block';return;}
  
  // Disable submit button to prevent double-submissions
  const btn=document.querySelector('#auth-register .btn-gold');
  const orgBtnHTML=btn?btn.innerHTML:'';
  if(btn){btn.disabled=true;btn.innerHTML='<span class="spinner" style="border-width:2px;width:14px;height:14px;margin-right:6px;display:inline-block"></span> Submitting...';}

  // Map fields to match registrations table: name, email, facility, requested_at, location, department, password, requested_role
  const reg={
    name: contact, 
    email: email, 
    facility: fname, 
    location: loc,
    department: dept,
    requested_role: reqRole,
    requested_at: new Date().toISOString(),
    status:'pending',
    password: pass // Included for the Edge Function to create the auth user
  };

  SB.submitRegistration(reg).then(()=>{
    if(btn){btn.disabled=false;btn.innerHTML=orgBtnHTML;}
    document.getElementById('login').classList.add('hidden');
    document.getElementById('pending-screen').classList.remove('hidden');
  }).catch(e=>{
    if(btn){btn.disabled=false;btn.innerHTML=orgBtnHTML;}
    let userMsg='Submission failed: '+e.message;
    // Translate known backend errors into user-friendly messages
    if(e.message&&e.message.includes('registrations_email_key')){
      userMsg='This email address has already been used in a previous registration. If your prior request was denied, please contact SIPS Healthcare at support@sipsconsults.com or use a different email address.';
    } else if(e.message&&(e.message.includes('Load failed')||e.message.includes('timed out')||e.message.includes('Failed to fetch')||e.message.includes('NetworkError'))){
      userMsg='Network error — please check your internet connection and try again.';
    }
    errEl.textContent=userMsg;
    errEl.style.display='block';
  });
}

// ============================================================ TOAST
let _saveTmr=null;
function toast(msg,type='info'){
  const t=document.getElementById('toast');
  const d=document.createElement('div');
  d.className=`toast-item toast-${type}`;
  d.innerHTML=msg;
  t.appendChild(d);
  setTimeout(()=>d.remove(),3200);
}

// ============================================================ MODAL
function openModal(title,html,size='modal-md'){
  document.getElementById('modal-title').textContent=title;
  document.getElementById('modal-content').innerHTML=html;
  const box=document.getElementById('modal-box');
  box.className='modal '+size;
  document.getElementById('modal-overlay').classList.add('open');
}
function closeModal(e){
  if(!e||e.target===document.getElementById('modal-overlay'))
    document.getElementById('modal-overlay').classList.remove('open');
}

// ============================================================ MOBILE SIDEBAR
function toggleSidebar(portal){
  const sidebar=document.getElementById(portal+'-sidebar');
  const overlay=document.getElementById(portal+'-overlay');
  const hamburger=document.getElementById(portal+'-hamburger');
  if(!sidebar) return;
  const isOpen=sidebar.classList.contains('open');
  if(isOpen){
    sidebar.classList.remove('open');
    if(overlay) overlay.classList.remove('open');
    if(hamburger) hamburger.classList.remove('open');
  } else {
    sidebar.classList.add('open');
    if(overlay) overlay.classList.add('open');
    if(hamburger) hamburger.classList.add('open');
  }
}

function closeSidebar(portal){
  const sidebar=document.getElementById(portal+'-sidebar');
  const overlay=document.getElementById(portal+'-overlay');
  const hamburger=document.getElementById(portal+'-hamburger');
  if(sidebar) sidebar.classList.remove('open');
  if(overlay) overlay.classList.remove('open');
  if(hamburger) hamburger.classList.remove('open');
}

function initSwipeClose(portal){
  let startX=0;
  const sidebar=document.getElementById(portal+'-sidebar');
  if(!sidebar) return;
  sidebar.addEventListener('touchstart',e=>{startX=e.touches[0].clientX;},{passive:true});
  sidebar.addEventListener('touchend',e=>{
    if(startX-e.changedTouches[0].clientX>60) closeSidebar(portal);
  },{passive:true});
}

// ============================================================ NAVIGATION
function logout(){
  // Guard: don't allow logout to fire during login/hydration
  if(window.SBD_INITIALIZING || window.SBD_LOGIN_IN_PROGRESS) {
    console.warn('SBD: Blocked logout during active login/initialization');
    return;
  }
  if(IS_LIVE){
    try { fetch(`${SB_API_URL}/auth/v1/logout`,{method:'POST',headers:{'apikey':SB_ANON_KEY,'Authorization':'Bearer '+(ST.session?.access_token||'')}}).catch(e => { if (e instanceof ReferenceError || e instanceof TypeError || e instanceof SyntaxError) throw e; }); } catch(e){}
  }
  try { localStorage.removeItem('sbd_session'); localStorage.removeItem('sb-sbd-session'); sessionStorage.removeItem('sbd_demo_view'); } catch(e){}
  
  // SECURE STATE CLEARING
  if(typeof resetDB === 'function') resetDB();
  
  ST.session=null;
  ['h-portal','a-portal','s-portal','x-portal'].forEach(id=>{
    const el=document.getElementById(id);
    if(el) el.classList.add('hidden');
  });
  document.getElementById('login').classList.remove('hidden');
  document.getElementById('pending-screen').classList.add('hidden');
  if(document.getElementById('si-email')) document.getElementById('si-email').value='';
  if(document.getElementById('si-pass')) document.getElementById('si-pass').value='';
  switchAuthTab('signin');
  if(ST.charts) Object.values(ST.charts).forEach(c=>c.destroy());
  ST.charts={};
  ST.user=null;

  // CLEANUP UI MODALS/OVERLAYS
  if(typeof closeModal === 'function') closeModal();
  document.getElementById('welcome-overlay')?.classList.remove('open');
  document.getElementById('tour-overlay')?.classList.remove('open');
  document.getElementById('skip-reminder')?.classList.remove('show');
}

function enterPortal(type){
  document.getElementById('login').classList.add('hidden');
  ST.portal=type;
  const u=ST.user;

  if(type==='staff_member'){
    // Individual staff login
    const sid=u.sid;
    console.log('[enterPortal] staff_member sid=', sid, 'DB.staff.length=', DB.staff.length, 'DB.staff IDs=', DB.staff.map(x=>x.id));
    const s=getStaff(sid);
    console.log('[enterPortal] getStaff result=', s);
    ST.staffId=sid;
    ST.hFid=u.fid;
    const fac=getFac(u.fid)||{};
    document.getElementById('s-sb-orgname').textContent=fac.name||'--';
    document.getElementById('s-uav-name').textContent=s?fullName(s):(u.name||u.email||'--');
    document.getElementById('s-uav-role').textContent=s?s.role:(u.title||u.role||'Staff');
    document.getElementById('s-uav-initials').textContent=u.initials||(u.name?u.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase():'--');
    if(s) document.getElementById('s-topbar-pts').textContent=calcPoints(s)+' pts';
    initSwipeClose('s');
    document.querySelectorAll('#s-portal .nav-item').forEach(n=>n.classList.remove('active'));
    // Restore saved view or default to dashboard
    let _sv='s-dashboard',_st='My Dashboard';
    try{const v=JSON.parse(sessionStorage.getItem('sbd_demo_view')||'{}');if(v.view&&v.view.startsWith('s-')){_sv=v.view;_st=v.title||_st;}}catch(e){}
    const _sEl=document.querySelector('#s-portal .nav-item[data-view="'+_sv+'"]');
    if(_sEl) _sEl.classList.add('active'); else document.querySelector('#s-portal .nav-item[data-view="s-dashboard"]').classList.add('active');
    document.getElementById('s-topbar-title').textContent=_st;
    document.getElementById('s-portal').classList.remove('hidden');
    renderSView(_sv);
    return;
  }

  try{const v=JSON.parse(sessionStorage.getItem('sbd_demo_view')||'{}');if(v.staffId) ST.staffId=v.staffId;}catch(e){}

  if(type==='system_admin'){
    const sys=getSystem(u.systemId);
    ST.curSystemId=u.systemId;
    document.getElementById('x-sb-sysname').textContent=sys?sys.name:'My System';
    document.getElementById('x-uav-name').textContent=u.name||u.email||'System Admin';
    document.getElementById('x-uav-role').textContent=u.title||u.role||'System Admin';
    document.getElementById('x-uav-initials').textContent=u.initials||(u.name?u.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase():'--');
    initSwipeClose('x');
    document.querySelectorAll('#x-portal .nav-item').forEach(n=>n.classList.remove('active'));
    let _xv='x-dashboard',_xt='System Overview';
    try{const v=JSON.parse(sessionStorage.getItem('sbd_demo_view')||'{}');if(v.view&&v.view.startsWith('x-')){_xv=v.view;_xt=v.title||_xt;}}catch(e){}
    const _xEl=document.querySelector('#x-portal .nav-item[data-view="'+_xv+'"]');
    if(_xEl) _xEl.classList.add('active'); else document.querySelector('#x-portal .nav-item[data-view="x-dashboard"]').classList.add('active');
    document.getElementById('x-topbar-title').textContent=_xt;
    document.getElementById('x-portal').classList.remove('hidden');
    renderXView(_xv);
    return;
  }

  if(type==='hospital'){
    const fid=u?u.fid:'test-a';
    ST.hFid=fid;
    ST.curFid=fid;
    const fac=getFac(fid);
    document.getElementById('h-sb-orgname').textContent=fac?fac.name:'--';
    document.getElementById('h-topbar-sub').textContent=fac?(fac.name+' \u2022 '+fac.dept):'--';
    document.getElementById('h-uav-name').textContent=u?(u.name||u.email||'--'):'--';
    const _isFacAdmin = u&&u.role==='facility_admin';
    const _hroleDisplay=_isFacAdmin?'Facility Admin':(u?(u.title||u.role||'Dept. Manager'):'Dept. Manager');
    document.getElementById('h-uav-role').textContent=_hroleDisplay;
    const initials=u?(u.initials||(u.name?u.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase():'--')):'--';
    document.getElementById('h-uav-initials').textContent=initials;
    // Update topbar role pill
    const _hPill=document.getElementById('h-topbar-role-pill');
    if(_hPill){
      _hPill.textContent=_isFacAdmin?'Facility Admin':'Hospital Portal';
      _hPill.className='pill topbar-pill-hide '+(_isFacAdmin?'p-gold':'p-blue');
    }
    // Show facility admin nav items if applicable
    const _hFacAdminNav=document.getElementById('h-nav-assessments');
    if(_hFacAdminNav) _hFacAdminNav.style.display=_isFacAdmin?'flex':'none';
    const _hFacAdminProgNav=document.getElementById('h-nav-progression');
    if(_hFacAdminProgNav) _hFacAdminProgNav.style.display=_isFacAdmin?'flex':'none';
    const _facAdminLbl=document.getElementById('h-nav-fadmin-lbl');
    if(_facAdminLbl) _facAdminLbl.style.display=_isFacAdmin?'block':'none';
    document.querySelectorAll('#h-portal .nav-item').forEach(n=>n.classList.remove('active'));
    let _hv='h-dashboard',_ht='Department Dashboard';
    try{const v=JSON.parse(sessionStorage.getItem('sbd_demo_view')||'{}');if(v.view&&v.view.startsWith('h-')){_hv=v.view;_ht=v.title||_ht;}}catch(e){}
    const _hEl=document.querySelector('#h-portal .nav-item[data-view="'+_hv+'"]');
    if(_hEl) _hEl.classList.add('active'); else document.querySelector('#h-portal .nav-item[data-view="h-dashboard"]').classList.add('active');
    document.getElementById('h-topbar-title').textContent=_ht;
    document.getElementById('h-portal').classList.remove('hidden');
    renderHView(_hv);
    return;
  }

  // admin / staff_admin / master_admin
  const isMaster=u&&u.role==='master_admin';
  document.getElementById('a-sb-role-label').textContent=isMaster?'Master Admin':'Staff Admin';
  document.getElementById('a-uav-name').textContent=u?(u.name||u.email||'Admin'):'Admin';
  document.getElementById('a-uav-role').textContent=u?(u.title||u.role||'SIPS Admin'):'SIPS Admin';
  document.getElementById('a-uav-initials').textContent=u?(u.initials||(u.name?u.name.split(' ').map(n=>n[0]).join('').slice(0,2).toUpperCase():'AD')):'AD';
  document.getElementById('a-topbar-pill').textContent=isMaster?'Master Admin':'Staff Admin';
  document.getElementById('admin-mgmt-lbl').style.display=isMaster?'block':'none';
  document.getElementById('nav-adminusers').style.display=isMaster?'flex':'none';
  const _navDavidDash = document.getElementById('nav-daviddashboard');
  if (_navDavidDash) _navDavidDash.style.display = isMaster ? 'flex' : 'none';
  document.getElementById('nav-freeagents').style.display=isMaster?'flex':'none';
  document.getElementById('nav-systems').style.display=isMaster?'flex':'none';
  const _navDavid = document.getElementById('nav-david');
  if (_navDavid) {
    const isIzzy = u && u.email && u.email.toLowerCase() === 'izambrano@sipsconsults.com';
    _navDavid.style.display = isIzzy ? 'flex' : 'none';
  }
  // Placement reviews visible to all SIPS admins (master + staff_admin)
  const _navPlacement=document.getElementById('nav-placementreviews');
  if(_navPlacement) _navPlacement.style.display='flex';
  if(typeof updatePlacementBadge === 'function') updatePlacementBadge();
  // Promo queue visible to all SIPS admins (master + assessors)
  const _navPromo=document.getElementById('nav-promoqueue');
  if(_navPromo) _navPromo.style.display='flex';
  updatePromoNB();
  updateFANB();
  const pendingCnt=DB.pendingRegs.filter(r=>r.status==='pending').length;
  const nb=document.getElementById('reg-nb');
  if(nb){nb.textContent=pendingCnt;nb.style.display=pendingCnt>0?'inline-block':'none';}
  const sel=document.getElementById('fac-switcher-sel');
  // For staff_admin, only show assigned facilities
  const hasFilter=(u.assignedFids||[]).length>0;
  const facList=(isMaster?DB.facilities:(hasFilter?DB.facilities.filter(f=>u.assignedFids.includes(f.id)):DB.facilities)).filter(f=>f.active!==false);
  if(sel) sel.innerHTML=facList.map(f=>`<option value="${f.id}">${f.name}</option>`).join('');
  ST.curFid=facList[0]?.id||'test-a';
  document.querySelectorAll('#a-portal .nav-item').forEach(n=>n.classList.remove('active'));
  let _av='a-overview',_at='Network Overview';
  try{
    const pathRoute = window.location.pathname.substring(1);
    const possibleView = pathRoute ? 'a-' + pathRoute : null;
    const v=JSON.parse(sessionStorage.getItem('sbd_demo_view')||'{}');
    if(possibleView && document.querySelector('#a-portal .nav-item[data-view="'+possibleView+'"]')) {
      _av = possibleView;
      _at = document.querySelector('#a-portal .nav-item[data-view="'+possibleView+'"]').textContent.trim() || _at;
    } else if(v.view&&v.view.startsWith('a-')){_av=v.view;_at=v.title||_at;}
  }catch(e){}
  const _aEl=document.querySelector('#a-portal .nav-item[data-view="'+_av+'"]');
  if(_aEl) _aEl.classList.add('active'); else document.querySelector('#a-portal .nav-item[data-view="a-overview"]').classList.add('active');
  document.getElementById('a-topbar-title').textContent=_at;
  document.getElementById('a-portal').classList.remove('hidden');
  renderAView(_av);
}


window.addEventListener('popstate', function(e) {
  if (e.state && e.state.view) {
    // Determine the portal type based on the view prefix
    const v = e.state.view;
    if (v.startsWith('h-') && ST.portal === 'hospital' || ST.portal === 'facility_admin') renderHView(v);
    else if (v.startsWith('x-') && ST.portal === 'system_admin') renderXView(v);
    else if (v.startsWith('a-') && (ST.portal === 'master_admin' || ST.portal === 'staff_admin')) renderAView(v);
    else if (v.startsWith('s-') && ST.portal === 'staff_member') renderSView(v);
  }
});

function _pushState(view, title) {
  try {
    const route = '/' + view.substring(2);
    if (window.location.pathname !== route) {
      window.history.pushState({ view: view, title: title }, title, route);
    }
  } catch (e) {
    console.warn('History pushState failed:', e);
  }
}

function hNav(el,view,title){
  document.querySelectorAll('#h-portal .nav-item').forEach(n=>n.classList.remove('active'));
  el.classList.add('active');
  document.getElementById('h-topbar-title').textContent=title;
  closeSidebar('h');
  try{sessionStorage.setItem('sbd_demo_view',JSON.stringify({view,title,staffId:ST.staffId}));}catch(e){}
  _pushState(view, title);
  renderHView(view);
}

