function renderADavidView() {
  const container = document.getElementById('a-david');
  if (!container) return;
  if (!window.DAVID) {
    if (typeof DavidChat === 'undefined') {
      container.innerHTML = '<div style="padding:40px; color:var(--txt2); text-align:center">Initializing DAVID Intelligence Terminal...</div>';
      return;
    }
    window.DAVID = new DavidChat({ containerId: 'a-david' });
  } else {
    window.DAVID.renderIn('a-david');
  }
}

function renderADavidDashboardView() {
  const container = document.getElementById('a-daviddashboard');
  if (!container) return;
  // Load the premium Command Center UI directly
  container.innerHTML = `<iframe src="/david-command-center.html" style="width:100%;height:calc(100vh - 64px);border:none;border-radius:12px;background:var(--bg);" allowfullscreen></iframe>`;
}

window.refreshDashboard = function() {
  if (!ST.portal) return;
  
  // Refresh global badges and element counts unconditionally
  try {
    if (typeof updatePromoNB === 'function') updatePromoNB();
    if (typeof updateFANB === 'function') updateFANB();
    if (typeof updatePlacementBadge === 'function') updatePlacementBadge();
    const pendingCnt = DB.pendingRegs?.filter(r=>r.status==='pending').length || 0;
    const nb = document.getElementById('reg-nb');
    if(nb){ nb.textContent=pendingCnt; nb.style.display=pendingCnt>0?'inline-block':'none'; }
    // Multi-facility re-calc if it exists
    const sel=document.getElementById('fac-switcher-sel');
    if(sel && ST.portal === 'staff_admin' && ST.user) {
      const hasFilter=(ST.user.assignedFids||[]).length>0;
      const facList=(hasFilter?DB.facilities.filter(f=>ST.user.assignedFids.includes(f.id)):DB.facilities).filter(f=>f.active!==false);
      const prevVal = sel.value;
      sel.innerHTML=facList.map(f=>`<option value="${f.id}">${f.name}</option>`).join('');
      if(facList.find(f=>f.id===prevVal)) sel.value = prevVal;
    }
  } catch (e) {
    console.warn('Dashboard badge refresh failed:', e);
  }

  if (ST.portal === 'system_admin' && ST.xView) renderXView(ST.xView);
  else if ((ST.portal === 'master_admin' || ST.portal === 'staff_admin') && ST.aView) renderAView(ST.aView);
  else if ((ST.portal === 'hospital' || ST.portal === 'facility_admin') && ST.hView) renderHView(ST.hView);
  else if (ST.portal === 'staff_member' && ST.sView) renderSView(ST.sView);
};

function switchFacility(fid){
  if(!fid) return;
  ST.curFid=fid;
  const f=getFac(fid);
  document.getElementById('fac-switcher-name').textContent=f?f.name:'';
  renderAFacility();
}

function goFacility(fid){
  ST.curFid=fid;
  ST.facTab='overview';
  // Update facility switcher
  const sel=document.getElementById('fac-switcher-sel');
  sel.value=fid;
  document.getElementById('fac-switcher-name').textContent=getFac(fid)?.name||'';
  document.getElementById('fac-switcher').classList.remove('hidden');
  document.getElementById('download-btn').style.display='flex';
  document.querySelectorAll('#a-portal .nav-item').forEach(n=>n.classList.remove('active'));
  document.getElementById('a-topbar-title').textContent=getFac(fid)?.name||'Facility';
  renderAView('a-facility');
}


// ── Shared admin staff filter state ──────────────────────────────────────────
const adminStaffFilter = {
  belt: 'All',
  fid:  'all',
  q:    '',
  initFromUrl() {
    try {
      const saved = localStorage.getItem('sbd_admin_filter');
      if (saved) {
        const p = JSON.parse(saved);
        if(p.belt !== undefined) this.belt = p.belt;
        if(p.fid !== undefined) this.fid = p.fid;
        if(p.q !== undefined) this.q = p.q;
      }
      const p = new URLSearchParams(window.location.search);
      if(p.has('f_belt')) this.belt = p.get('f_belt');
      if(p.has('f_fid')) this.fid = p.get('f_fid');
      if(p.has('f_q')) this.q = p.get('f_q');
    } catch(e) {}
  },
  syncToUrl() {
    try {
      const url = new URL(window.location);
      if(this.belt !== 'All') url.searchParams.set('f_belt', this.belt); else url.searchParams.delete('f_belt');
      if(this.fid !== 'all') url.searchParams.set('f_fid', this.fid); else url.searchParams.delete('f_fid');
      if(this.q !== '') url.searchParams.set('f_q', this.q); else url.searchParams.delete('f_q');
      window.history.replaceState(window.history.state, '', url);
      localStorage.setItem('sbd_admin_filter', JSON.stringify({belt:this.belt, fid:this.fid, q:this.q}));
    } catch(e) {}
  },
  reset(){ this.belt='All'; this.fid='all'; this.q=''; this.syncToUrl(); }
};
adminStaffFilter.initFromUrl();

// Build filter bar HTML for admin staff views
// showFacility = true for multi-facility views (network / system-level)
function adminFilterBar(showFacility, facList, onChangeFn){
  adminStaffFilter.syncToUrl();
  const beltChips=['All',...BELT_ORDER].map(b=>`
    <div class="fchip ${adminStaffFilter.belt===b?'on':''}"
      style="${adminStaffFilter.belt===b?'border-color:'+BELT_CLR[b]+'!important;':''}"
      onclick="adminStaffFilter.belt='${b}';${onChangeFn}()">
      ${b==='All'?'All Belts':`<span style="width:8px;height:8px;border-radius:50%;background:${BELT_CLR[b]};display:inline-block;margin-right:4px"></span>${b}`}
    </div>`).join('');

  const sortedFacs = facList ? [...facList].sort((a,b)=>(a.name||'').toLowerCase().localeCompare((b.name||'').toLowerCase())) : [];
  const facSelect = showFacility && sortedFacs.length?`
    <select class="form-select" style="width:auto;max-width:200px;padding:5px 11px;font-size:12px;height:32px"
      onchange="adminStaffFilter.fid=this.value;${onChangeFn}()">
      <option value="all" ${adminStaffFilter.fid==='all'?'selected':''}>All Facilities</option>
      ${sortedFacs.map(f=>`<option value="${f.id}" ${adminStaffFilter.fid===f.id?'selected':''}>${f.name}</option>`).join('')}
    </select>`:'';

  return`
    <div style="display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-bottom:14px">
      <div class="search-wrap" style="min-width:180px;flex:1;max-width:280px">
        <div class="search-ico"><svg viewBox="0 0 18 18" fill="none" width="14" height="14"><circle cx="7.5" cy="7.5" r="5" stroke="currentColor" stroke-width="1.5"/><path d="M12 12l3.5 3.5" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg></div>
        <input class="search-inp" placeholder="Search by name or role..." value="${adminStaffFilter.q}"
          oninput="adminStaffFilter.q=this.value;${onChangeFn}()">
      </div>
      ${facSelect}
      <div class="filter-bar" style="margin:0;flex-wrap:nowrap;overflow-x:auto;padding-bottom:0">
        ${beltChips}
      </div>
      ${adminStaffFilter.belt!=='All'||adminStaffFilter.fid!=='all'||adminStaffFilter.q?
        `<button class="btn btn-ghost btn-xs" onclick="adminStaffFilter.reset();${onChangeFn}()" style="white-space:nowrap">Clear</button>`:''}
    </div>`;
}

// Filter a staff array by the current adminStaffFilter
function applyAdminFilter(staffArr){
  return staffArr.filter(s=>{
    const matchBelt = adminStaffFilter.belt==='All' || s.belt===adminStaffFilter.belt;
    const matchFid  = adminStaffFilter.fid==='all' || s.fid===adminStaffFilter.fid;
    const term      = adminStaffFilter.q.toLowerCase();
    const matchQ    = !term || fullName(s).toLowerCase().includes(term) || (s.role||'').toLowerCase().includes(term);
    return matchBelt && matchFid && matchQ;
  });
}


