// Ensure ps.tracks exists on a staff record
function ensurePSTracks(staff){
  if(!staff.ps) staff.ps = {};
  if(!staff.ps.tracks) staff.ps.tracks = {};
}

// Get status of a specific PS track for a staff member
// Returns: 'locked' | 'eligible' | 'active' | 'testing' | 'complete'
function getTrackStatus(staff, tid){
  ensurePSTracks(staff);
  const t = PS_TRACKS[tid];
  if(!t) return 'locked';
  const bIdx = beltIdx(staff.belt);
  // Belt gate  --  must meet tier requirement
  if(t.tier==='green' && bIdx < 2) return 'locked';
  if(t.tier==='blue'  && bIdx < 3) return 'locked';
  // Sequential prerequisite  --  prereq must be assessor-awarded complete
  if(t.prereq){
    const prereqStatus = getTrackStatus(staff, t.prereq);
    if(prereqStatus !== 'complete') return 'locked';
  }
  // Track-specific status
  const td = staff.ps.tracks[tid];
  if(!td) return 'eligible';
  return td.status || 'eligible';
}

// Stars earned at a specific belt tier from PS completions
function getPSStarsAtBelt(staff, belt){
  const tracks = belt==='Green' ? PS_GREEN_TRACKS : belt==='Blue' ? PS_BLUE_TRACKS : [];
  if(!tracks.length) return staff.stars||0;
  return tracks.filter(tid => getTrackStatus(staff, tid)==='complete').length;
}

// Total PS-earned stars (Green + Blue track completions)
function calcTotalPSStars(staff){
  return [...PS_GREEN_TRACKS,...PS_BLUE_TRACKS].filter(tid => getTrackStatus(staff, tid)==='complete').length;
}

// Tracks that are available to start or resume (eligible or active)
function getEligibleTracks(staff){
  return Object.keys(PS_TRACKS).filter(tid => {
    const s = getTrackStatus(staff, tid);
    return s === 'eligible' || s === 'active' || s === 'testing';
  });
}

// Staff action: begin a track
function beginPSTrack(staffId, tid){
  const s = getStaff(staffId);
  if(!s) return;
  ensurePSTracks(s);
  const status = getTrackStatus(s, tid);
  if(status !== 'eligible') return;
  s.ps.tracks[tid] = {status:'active', promptedAt: s.ps.tracks[tid]?.promptedAt||new Date().toISOString().slice(0,10), startedAt: new Date().toISOString().slice(0,10), completedAt: null};
  s.ps.enrolled = true;
  toast('Position School track started. Complete all 5 criteria to earn your star.');
  if (IS_LIVE && typeof SB !== 'undefined' && SB.updateStaff) {
    SB.updateStaff(staffId, { ps: s.ps }).catch(e=>console.warn('Sync failed:', e));
  }
  if(typeof renderSPosSchool === 'function') renderSPosSchool();
}

// Staff action: signal ready to test
function readyToTestPS(staffId, tid){
  const s = getStaff(staffId);
  if(!s) return;
  ensurePSTracks(s);
  if(getTrackStatus(s, tid) !== 'active') return;
  s.ps.tracks[tid].status = 'testing';
  toast('Marked as ready to test. Your assessor has been notified.');
  if (IS_LIVE && typeof SB !== 'undefined' && SB.updateStaff) {
    SB.updateStaff(staffId, { ps: s.ps }).catch(e=>console.warn('Sync failed:', e));
  }
  if(typeof renderSPosSchool === 'function') renderSPosSchool();
}

// Admin/Assessor action: award star (complete a track)
function completePSTrack(staffId, tid){
  const s = getStaff(staffId);
  if(!s) return;
  ensurePSTracks(s);
  const ts = getTrackStatus(s, tid);
  if(ts === 'locked' || ts === 'complete') return;
  if(!s.ps.tracks[tid]) s.ps.tracks[tid] = {};
  s.ps.tracks[tid].status = 'complete';
  s.ps.tracks[tid].completedAt = new Date().toISOString().slice(0,10);
  if(!s.ps.tracks[tid].startedAt) s.ps.tracks[tid].startedAt = s.ps.tracks[tid].completedAt;
  if(!s.ps.tracks[tid].promptedAt) s.ps.tracks[tid].promptedAt = s.ps.tracks[tid].completedAt;
  // Update legacy stars field
  s.stars = calcTotalPSStars(s);
  // Update legacy ps.done for any completed track
  s.ps.done = [...PS_GREEN_TRACKS,...PS_BLUE_TRACKS].some(t => getTrackStatus(s,t)==='complete');
  s.ps.enrolled = [...PS_GREEN_TRACKS,...PS_BLUE_TRACKS].some(t => ['active','testing'].includes(getTrackStatus(s,t)));
  toast('Position School track complete! Star awarded.');
  
  if (IS_LIVE && typeof SB !== 'undefined' && SB.updateStaff) {
    SB.updateStaff(staffId, { ps: s.ps, stars: s.stars }).catch(e=>console.warn('Sync failed:', e));
  }

  // Refresh whichever view is active (includes drawer redrawing or scoreboard re-rendering)
  if(ST.portal==='a') renderAView(ST.aView);
  if(ST.portal==='h') renderHView(ST.hView);
}

// Seed/migrate PS tracks for legacy staff records
function seedPSTracks(){
  DB.staff.forEach(staff => {
    ensurePSTracks(staff);
    const existing = staff.ps.tracks;
    const bIdx = beltIdx(staff.belt);
    const stars = staff.stars || 0;
    const done  = staff.ps.done;
    const enrolled = staff.ps.enrolled;
    const track = (staff.ps.track||'').toLowerCase();

    // ---- Green tier migration ----------------------------------------
    if(bIdx >= 2){
      // If ps.done or enough stars, complete green tracks
      if(done || stars >= 1){
        if(!existing['01']) existing['01'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      if(done || stars >= 2){
        // Assign 02A as first choice, 02B if stars >= 3
        if(!existing['02A']) existing['02A'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      if(done || stars >= 3){
        if(!existing['02B']) existing['02B'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      // If enrolled but not done, mark QA as complete + 02A in progress
      if(!done && enrolled && !existing['01']){
        existing['01'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
        existing['02A'] = {status:'active', promptedAt:staff.since, startedAt:staff.since, completedAt:null};
      }
      // Eligible but not enrolled: set promptedAt
      if(!done && !enrolled && !existing['01']){
        existing['01'] = {status:'eligible', promptedAt:staff.since, startedAt:null, completedAt:null};
      }
    }

    // ---- Blue tier migration ----------------------------------------
    if(bIdx >= 3){
      if(done || track.includes('lead') || track.includes('supervisor') || track.includes('director')){
        if(!existing['03']) existing['03'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      if(done && (track.includes('supervisor') || track.includes('director'))){
        if(!existing['04']) existing['04'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      if(done && track.includes('director')){
        if(!existing['05']) existing['05'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
        if(!existing['06']) existing['06'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
      }
      // Lead track in progress
      if(!done && enrolled && track.includes('lead') && !existing['03']){
        if(!existing['03']) existing['03'] = {status:'active', promptedAt:staff.since, startedAt:staff.since, completedAt:null};
      }
      if(!done && enrolled && track.includes('supervisor') && !existing['04']){
        if(!existing['03']) existing['03'] = {status:'complete', promptedAt:staff.since, startedAt:staff.since, completedAt:staff.since};
        if(!existing['04']) existing['04'] = {status:'active', promptedAt:staff.since, startedAt:staff.since, completedAt:null};
      }
      // Eligible for Blue tier if no tracks yet
      if(!existing['03']){
        existing['03'] = {status:'eligible', promptedAt:staff.since, startedAt:null, completedAt:null};
      }
    }

    // Update derived fields
    staff.stars = calcTotalPSStars(staff);
  });
}
// Run migration once on load
seedPSTracks();

