// Answer order: A=S, B=St, C=Su, D=A
const OIP_ANSWER_MAP = ['S','St','Su','A'];

// Role compatibility target profiles
const OIP_ROLE_TARGETS = {
  'SPD Tech Level I':      {S:40,St:25,Su:20,A:15},
  'SPD Tech Level II':     {S:35,St:25,Su:25,A:15},
  'Lead Technician':       {S:25,St:30,Su:25,A:20},
  'Shift Supervisor':      {S:20,St:35,Su:25,A:20},
  'Department Supervisor': {S:15,St:30,Su:25,A:30},
  'SPD Manager':           {S:10,St:30,Su:20,A:40},
  'Director':              {S:10,St:25,Su:20,A:45},
};

// Resolve role label from staff.role to compatibility key
function oipRoleKey(role){
  const r=(role||'').toLowerCase();
  if(r.includes('director')) return 'Director';
  if(r.includes('manager')) return 'SPD Manager';
  if(r.includes('dept supervisor')||r.includes('department supervisor')) return 'Department Supervisor';
  if(r.includes('shift supervisor')||r.includes('spd supervisor')||r.includes('cs supervisor')) return 'Shift Supervisor';
  if(r.includes('lead tech')||r.includes('lead technician')||r.includes('spd lead')) return 'Lead Technician';
  if(r.includes('tech ii')||r.includes('tech 2')||r.includes('instrument processing tech ii')||r.includes('spd technician ii')||r.includes('technician ii')) return 'SPD Tech Level II';
  return 'SPD Tech Level I';
}

// Calc compatibility % given oip scores vs target role
function oipCompatibility(oipScores, targetRole){
  const target = OIP_ROLE_TARGETS[targetRole] || OIP_ROLE_TARGETS['SPD Tech Level I'];
  const pS  = oipScores.S  / 30 * 100;
  const pSt = oipScores.St / 30 * 100;
  const pSu = oipScores.Su / 30 * 100;
  const pA  = oipScores.A  / 30 * 100;
  const dev = (Math.abs(pS-target.S)+Math.abs(pSt-target.St)+Math.abs(pSu-target.Su)+Math.abs(pA-target.A))/4;
  return Math.round(100-dev);
}

