// Ensure OIP field on staff record
function ensureOIP(staff){
  if(!staff.oip) staff.oip={completed:false,completedAt:null,primaryType:null,secondaryType:null,scores:{S:0,St:0,Su:0,A:0},answers:[]};
}

// Score answers array and return result
function scoreOIP(answers){
  const scores={S:0,St:0,Su:0,A:0};
  answers.forEach(a=>{ if(a!==null) scores[OIP_ANSWER_MAP[a]]++; });
  const sorted=Object.entries(scores).sort((x,y)=>y[1]-x[1]);
  return {scores, primaryType:sorted[0][0], secondaryType:sorted[1][0]};
}

// Save completed OIP to staff record
function submitOIP(staffId, answers){
  // [CRITICAL GUARDRAIL - DO NOT REMOVE OR BREAK]
  // Relies on globally defined `sbFetch` for syncing OIP blobs via PATCH.
  // Never break this payload mapping or module linking.
  const s=getStaff(staffId);
  if(!s) return;
  ensureOIP(s);

  // Archive previous OIP result before overwriting (retake safety)
  if(s.oip.completed && s.oip.primaryType){
    if(!s.oip.history) s.oip.history = [];
    s.oip.history.unshift({
      completedAt: s.oip.completedAt,
      primaryType: s.oip.primaryType,
      secondaryType: s.oip.secondaryType,
      scores: {...s.oip.scores},
      answers: s.oip.answers ? [...s.oip.answers] : []
    });
  }

  const result=scoreOIP(answers);
  s.oip.completed=true;
  s.oip.completedAt=new Date().toISOString().slice(0,10);
  s.oip.primaryType=result.primaryType;
  s.oip.secondaryType=result.secondaryType;
  s.oip.scores=result.scores;
  s.oip.answers=answers;
  closeOIPQuiz();
  document.getElementById('modal-overlay').classList.remove('open');
  if(IS_LIVE){
    sbFetch(`/rest/v1/staff?id=eq.${s.id}`, {
      method:'PATCH',
      body: {oip: s.oip}
    }).catch(e => handleSyncError(e, 'OIP sync'));
  } else {
    /* saveDemoData() removed */
  }
  toast('Operator Intelligence Profile complete! Results saved.','ok');
  if(ST.portal==='staff_admin'||ST.portal==='master_admin'){
    const plNav=document.getElementById('nav-placementreviews');
    if(plNav) plNav.style.display='';
    updatePlacementBadge();
  }
  if(ST.portal==='staff_member'||ST.sView) {
    setTimeout(() => {
      if (ST.sView) renderSView(ST.sView);
      else renderSDashboard();
    }, 100);
  }
  if(ST.aView==='a-facility') setTimeout(renderFacTab, 100);
  if(ST.hView==='h-staff'||ST.hView==='h-profile') setTimeout(()=>renderHView(ST.hView), 100);
}

