// ============================================================ REPORT ENGINE  --  SHARED UTILITIES

// Mini stat cell for report headers
function rptStat(label, value, sub, color){
  return `<div style="text-align:center;padding:12px 8px">
    <div style="font-size:22px;font-weight:800;color:${color||'var(--txt1)'}">${value}</div>
    <div style="font-size:10px;font-weight:700;color:var(--txt3);letter-spacing:.05em;text-transform:uppercase;margin-top:2px">${label}</div>
    ${sub?`<div style="font-size:10px;color:var(--txt3);margin-top:1px">${sub}</div>`:''}
  </div>`;
}

// Belt distribution bar set
function rptBeltBars(staffArr){
  const n = staffArr.length;
  if(!n) return '<div style="font-size:12px;color:var(--txt3);text-align:center;padding:10px">No staff data</div>';
  return BELT_ORDER.slice().reverse().map(b=>{
    const cnt = staffArr.filter(s=>s.belt===b).length;
    const pct = Math.round(cnt/n*100);
    return `<div style="display:flex;align-items:center;gap:8px;margin-bottom:5px">
      <div style="width:52px;font-size:10.5px;color:${BELT_CLR[b]};font-weight:600;flex-shrink:0">${b}</div>
      <div style="flex:1;height:7px;background:var(--s3);border-radius:4px;overflow:hidden">
        <div style="height:100%;width:${Math.max(pct,1)}%;background:${BELT_CLR[b]};border-radius:4px"></div>
      </div>
      <div style="width:36px;font-size:10.5px;color:var(--txt3);text-align:right">${cnt} <span style="color:var(--txt4);font-size:9px">${pct}%</span></div>
    </div>`;
  }).join('');
}

// Assessment pass rate from history
function rptPassRate(staffArr){
  let pass=0, total=0;
  staffArr.forEach(s=>{ (s.history||[]).forEach(h=>{ total++; if(h.res==='pass') pass++; }); });
  return total>0?Math.round(pass/total*100):null;
}

// Stagnation analysis  --  staff longest at current belt vs expected cycle
function rptStagnation(staffArr){
  return staffArr.map(s=>{
    const exp = BELT_WINDOWS[s.belt]? (BELT_WINDOWS[s.belt].open + BELT_WINDOWS[s.belt].closed)*2 : 0;
    const actual = daysAt(s.since);
    return {s, actual, expected: exp*7, over: exp>0 ? actual - exp*7 : 0};
  }).filter(x=>x.over>30).sort((a,b)=>b.over-a.over);
}

// Gate failure pattern  --  staff with any failed gates
function rptGateFailures(staffArr){
  return staffArr.filter(s=>{
    const gates=[s.cur?.c,s.cur?.s,s.cur?.o,s.nxt?.c,s.nxt?.s,s.nxt?.o];
    return gates.some(g=>g==='fail');
  });
}

// OIP type distribution for a staff pool
function rptOIPDist(staffArr){
  const counts={S:0,St:0,Su:0,A:0,none:0};
  staffArr.forEach(s=>{ if(s.oip&&s.oip.completed&&s.oip.primaryType) counts[s.oip.primaryType]++; else counts.none++; });
  return counts;
}

// Section header for reports
function rptSection(title, badge){
  return `<div style="display:flex;align-items:center;gap:10px;margin:20px 0 10px;padding-bottom:8px;border-bottom:2px solid var(--bdr)">
    <div style="font-size:12px;font-weight:800;letter-spacing:.07em;text-transform:uppercase;color:var(--txt1)">${title}</div>
    ${badge?`<span class="pill p-muted" style="font-size:9.5px">${badge}</span>`:''}
  </div>`;
}

// Handoff condition checker (from the Operators Guide  --  7 conditions)
function rptHandoffStatus(staffArr){
  const brownPlus = staffArr.filter(s=>beltIdx(s.belt)>=4).length;
  const blueTracks = staffArr.filter(s=>PS_BLUE_TRACKS.some(t=>getTrackStatus(s,t)==='complete')).length;
  const educatorDone = staffArr.some(s=>getTrackStatus(s,'02B')==='complete');
  const managerDone = staffArr.some(s=>getTrackStatus(s,'06')==='complete');
  const oipPopulated = staffArr.filter(s=>s.oip&&s.oip.completed).length / Math.max(staffArr.length,1) > 0.8;
  const conditions = [
    {label:'Brown Belt on site and active', met: brownPlus>=1, detail: brownPlus+' Brown+ belts'},
    {label:'All 6 Leadership Circle positions PS-verified', met: blueTracks>=4, detail: blueTracks+' Blue tier tracks complete'},
    {label:'Educator/Preceptor Track 02B complete', met: educatorDone, detail: educatorDone?'Yes':'Not yet'},
    {label:'Full Blue Belt track through Manager School', met: managerDone, detail: managerDone?'Yes':'Not yet'},
    {label:'OIP profiles populated (80%+ staff)', met: oipPopulated, detail: staffArr.filter(s=>s.oip&&s.oip.completed).length+' of '+staffArr.length+' complete'},
    {label:'Belt advancement decisions led by Educator', met: educatorDone, detail: educatorDone?'Capable':'Needs 02B first'},
  ];
  const metCount = conditions.filter(c=>c.met).length;
  return {conditions, metCount, total: conditions.length};
}


