function getRankInSystem(s){
  // Rank by points across all staff in the same system
  const fac=getFac(s.fid);
  const sysId=fac?fac.systemId:null;
  const pool=sysId?systemStaff(sysId):DB.staff;
  const sorted=[...pool].sort((a,b)=>calcPoints(b)-calcPoints(a));
  return sorted.findIndex(x=>x.id===s.id)+1;
}

// ── Apply for assessment modal ───────────────────────────────────────────────
function openApplyModal(sid){
  const s=getStaff(sid);
  if(!s)return;
  const nb=nextBelt(s.belt);
  if(!nb){toast('Already at maximum belt level.','info');return;}
  const win=getWindowStatus(s);
  if(win.status!=='open'){toast('Assessment window is not currently open.','err');return;}
  const gatesNeeded=[{key:'c',label:'Competency'},{key:'s',label:'Simulation'},{key:'o',label:'Observation'}].filter(g=>s.nxt[g.key]!=='pass');
  openModal(`Apply for ${nb} Belt Assessment`,`
    <div class="modal-body">
      <div style="padding:12px;background:var(--ok-bg);border:1px solid var(--ok-bd);border-radius:var(--rs);margin-bottom:16px;font-size:12.5px;color:var(--ok);line-height:1.5">
        Your assessment window is currently <strong>OPEN</strong> – ${win.daysLeft} day${win.daysLeft!==1?'s':''} remaining.
      </div>
      <div style="font-size:13px;font-weight:600;margin-bottom:8px">Select the gate you want to apply for:</div>
      ${gatesNeeded.map(g=>`
        <div style="padding:12px;background:var(--s2);border:1px solid var(--bdr2);border-radius:var(--rs);margin-bottom:8px;cursor:pointer;transition:.15s" onclick="submitApply(${sid},'${g.key}','${nb}')" onmouseover="this.style.borderColor='var(--gold)'" onmouseout="this.style.borderColor='var(--bdr2)'">
          <div style="font-weight:700;margin-bottom:3px">${g.label} Assessment</div>
          <div style="font-size:11.5px;color:var(--txt3)">For ${nb} Belt certification. Conducted by an SBD-certified assessor.</div>
        </div>`).join('')}
      ${gatesNeeded.length===0?`<div style="text-align:center;padding:20px;color:var(--ok);font-weight:700">All gates passed! Awaiting belt certification review.</div>`:''}
    </div>
    <div class="modal-ft"><button class="btn btn-ghost" onclick="closeModal()">Cancel</button></div>`,'modal-md');
}

function submitApply(sid,gate,targetBelt){
  const s=getStaff(sid);
  if(!s)return;
  const gateLabel={c:'Competency',s:'Simulation',o:'Observation'}[gate];
  const qid='q'+Date.now();
  const newQItem={id:qid,sid,fid:s.fid,type:gateLabel,targetBelt,date:new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'})};
  if(IS_LIVE){ SB.submitAssessmentQueue(mapQueueToBackend(newQItem)).catch(e => handleSyncError(e, 'Queue sync')); }
  DB.queue.push(newQItem);
  const nb=document.getElementById('assess-nb');
  if(nb) {
    nb.textContent=DB.queue.length;
    nb.style.display = DB.queue.length > 0 ? 'inline-flex' : 'none';
  }
  closeModal();
  toast(`Applied for ${gateLabel} assessment (${targetBelt} Belt). An SBD assessor will be in touch.`,'ok');
}

