// ============================================================
// SIPS INTELLIGENCE FULL QUESTION BANKS  --  100 per belt per mode
// Sources: SBD Belt System Learner Guides, Facilitator Guides, 
// Practice Workbooks (White through Black)
// ============================================================

const FULL_QUESTION_BANKS = {

// ────────────────────────────────────────────────────────────
// WHITE BELT  --  100 Knowledge + 100 Simulation
// ────────────────────────────────────────────────────────────
White: {
knowledge: [
  {q:'What is the approved opening line for Script 1?',a:'"Sterile Processing, this is [your name]. How can I help you?"',diff:'easy'},
  {q:'What is the approved response when a runner arrives to pick up instruments?',a:'"I\'ll get the Lead right away." Then immediately locate and brief your Lead. Never accept, release, or redirect any item without Lead authorization.',diff:'easy'},
  {q:'What does "zero improvisation" mean at White Belt?',a:'If a situation is not covered by Script 1 or Script 2, you do not respond with information. You route to your Lead immediately.',diff:'easy'},
  {q:'Name the two scripts a White Belt must master.',a:'Script 1 – Phone Answer, Script 2 – Runner / Delivery Response',diff:'easy'},
  {q:'Why can a White Belt never release instruments without Lead authorization?',a:'Unauthorized instrument movement creates chain-of-custody failures, count errors, and patient harm risk.',diff:'easy'},
  {q:'What is the first thing you do after answering Script 1?',a:'Listen completely. Do not volunteer information, guess, or answer questions outside your two scripts.',diff:'easy'},
  {q:'What is the White Belt identity statement?',a:'Foundation operator. Zero improvisation. Route and document.',diff:'easy'},
  {q:'What does the protection principle mean at White Belt?',a:'The scripts are not bureaucracy. They are protection. A White Belt who improvises is exposed. A White Belt who follows the script is protected.',diff:'easy'},
  {q:'How long does White Belt typically take to complete?',a:'4 to 8 weeks.',diff:'easy'},
  {q:'What is the patient safety rationale for Script 1 forbidden phrases like "I think..."?',a:'Guessing introduces unverified information into the surgical workflow. A wrong answer about instrument status can cause OR to proceed with incomplete information and put a patient at risk.',diff:'easy'},
  {q:'List three forbidden phrases for Script 1.',a:'"Sure, let me check on that" / "I think..." / "Probably..." / "Hold on" / "I\'m not sure but..."',diff:'easy'},
  {q:'Who authorizes instrument movement in the SPD department?',a:'The Lead. No instrument is accepted, released, or redirected by a White Belt without Lead authorization.',diff:'easy'},
  {q:'What three things does a White Belt never do after answering a call?',a:'Volunteer information, answer questions outside Script 1 and 2, or improvise any response.',diff:'easy'},
  {q:'What is the White Belt documentation requirement?',a:'Document every communication exchange: date, time, your name, what was communicated, action taken.',diff:'medium'},
  {q:'Why is the White Belt description "Foundation operator" accurate?',a:'Every belt above White depends on the White Belt\'s discipline. If the foundation is weak – if a White Belt improvises or moves instruments without authorization – the entire operational chain is compromised.',diff:'medium'},
  {q:'What happens to a question you cannot answer as a White Belt?',a:'You route it to the Lead immediately. "Let me get the Lead for you right away." No delay, no attempt to answer.',diff:'medium'},
  {q:'A surgeon calls SPD. You are a White Belt alone. The surgeon asks about their case cart. What do you do?',a:'Script 1 to receive the call, then "Let me get the Lead for you right away." Do not answer the question. Locate Lead immediately.',diff:'medium'},
  {q:'Explain why "Should be fine" is a forbidden phrase for Script 2.',a:'It implies you have made a judgment about the instrument or item that you are not authorized to make. You do not have the training or authority to determine if an instrument "should be fine."',diff:'medium'},
  {q:'What must you do if your Lead is unavailable when a runner arrives?',a:'Inform the runner that the Lead is temporarily unavailable. Ask the runner to wait. Locate the Lead. Do NOT release any item. Document the interaction.',diff:'medium'},
  {q:'What is the difference between the two White Belt scripts in terms of trigger?',a:'Script 1 is triggered by any incoming phone call. Script 2 is triggered by any person physically arriving at SPD to pick up or drop off instruments.',diff:'medium'},
  {q:'Why does White Belt have only two scripts?',a:'Two scripts done perfectly builds the discipline of zero improvisation. White Belt is not simple because the job is easy. It is narrow because the habit of not improvising must be built before authority is expanded.',diff:'medium'},
  {q:'What does "route and document" mean in the White Belt identity?',a:'Route: every question outside your authority goes to Lead immediately. Document: every exchange is recorded with date, time, your name, and what happened.',diff:'medium'},
  {q:'What is the three-year development philosophy?',a:'The SBD belt system is a three-year journey from White Belt to Black Belt. People build processes, processes create systems, systems create automation, automation promotes technology.',diff:'medium'},
  {q:'A White Belt is working alone and OR calls asking if a tray is ready. The White Belt says "Should be about 10 minutes." Why is this wrong?',a:'The White Belt has made a time commitment they cannot verify. If the tray is not ready in 10 minutes, OR has been given false information and has planned around it. This is a Script 1 violation and a chain-of-custody issue.',diff:'medium'},
  {q:'Define "chain of custody" as it applies to White Belt.',a:'Chain of custody means every movement of an instrument or set is authorized, documented, and traceable. A White Belt breaking chain of custody by releasing an item without Lead authorization eliminates the traceability of that item.',diff:'medium'},
  {q:'What is the White Belt assessment Level 1 standard?',a:'50-question knowledge test. Must demonstrate: Scripts 1-2 approved and forbidden language, vocabulary, instrument identification, and patient safety rationale for zero improvisation.',diff:'medium'},
  {q:'What is the White Belt assessment Level 2 standard?',a:'Simulation – 10 scenarios. Assessor evaluates correct script selection, exact approved language, professional tone, and no use of forbidden phrases.',diff:'medium'},
  {q:'What is the White Belt assessment Level 3 standard?',a:'Full shift observation. Mandatory behaviors: Script 1 on every call, never accept/release without Lead authorization, document all exchanges, route all questions to Lead.',diff:'medium'},
  {q:'Explain why a White Belt following Script 2 perfectly is doing more than answering a door.',a:'By routing the runner to the Lead, the White Belt is protecting the chain of custody of every instrument in the department. Any untracked movement of an instrument can result in it reaching a patient at the wrong time or in the wrong condition.',diff:'hard'},
  {q:'A vendor arrives and says they need to retrieve their loaner set immediately for a case at another hospital. You are a White Belt. Walk through your complete response.',a:'Script 2: "I\'ll get the Lead right away." Do not allow the vendor to enter. Do not touch the set. Do not give any information about where the set is. Locate the Lead immediately and communicate the urgency to them. The Lead decides.',diff:'hard'},
  {q:'Why is zero improvisation described as the "foundational discipline" of the entire SBD communication system?',a:'Every belt above White is given additional scripts and authority. But the discipline of staying within your authorized scope -- never inventing a response, never guessing -- begins at White Belt. A Black Belt who improvises a script revision without SIPS approval is violating the same principle a White Belt violates when they improvise a phone answer.',diff:'hard'},
  {q:'What does the White Belt protection principle mean specifically for a tech who is new to the department?',a:'A new tech does not know what they do not know. Improvising an answer to OR during their first weeks -- even with good intentions -- could cause them to give wrong case cart information, make false commitments, or misidentify instruments. Script 1 protects the patient. It also protects the tech from professional exposure for information they gave without qualification.',diff:'hard'},
  {q:'A peer White Belt tells you "I always just answer OR\'s questions directly, it\'s faster." How do you respond and why?',a:'You explain that the script is not about speed. It is about authorization. The White Belt is not trained to answer questions about case cart status, instrument availability, or sterilization release. Answering directly does not make you faster. It makes you unprotected. If the answer is wrong, the documentation will show you gave unauthorized information.',diff:'hard'},
  {q:'Describe the documentation standard for a White Belt communication exchange.',a:'Date, time, your name, description of the exchange (factual, specific), action taken, Lead notified (yes/no). No opinions, no assumptions, only facts.',diff:'hard'},
  {q:'What is the patient safety risk of a White Belt accepting a delivery from a runner without Lead authorization?',a:'An unauthorized delivery bypasses the chain-of-custody system. The item has not been logged in, not been inspected, not been assigned to a queue. If that item reaches a patient without proper processing verification, the White Belt\'s unauthorized acceptance is part of the failure chain.',diff:'hard'},
  {q:'Explain why Script 1 says "How can I help you?" rather than just "Hello, Sterile Processing."',a:'The full script establishes three things: (1) the caller knows they reached the right department, (2) the caller knows who they are speaking with, (3) the tech has opened a service interaction. "Hello, SPD" alone does not open a service channel and creates ambiguity about whether the caller has been received properly.',diff:'hard'},
  {q:'A call comes in and the person immediately says "Don\'t put me on hold, I need an answer right now." You are alone. What do you do?',a:'Script 1 is already active. Acknowledge the urgency: "I understand. Let me get the Lead to help you right now." Then locate Lead immediately. Do not put them on hold without notification. Communicate the urgency to your Lead.',diff:'hard'},
  {q:'What makes the White Belt assessment harder than it appears?',a:'The assessment tests script delivery under pressure, not just memorization. Assessors use interruptions, pushback, and urgency to test whether the candidate maintains zero improvisation when it is uncomfortable. Most failures come from a candidate who knows the script but abandons it under pressure.',diff:'hard'},
  {q:'Why does the SBD system not allow White Belt techs to grow into "helping more" before earning Yellow Belt?',a:'The White Belt scope is not a limitation placed on the tech. It is a protection for the patient. Every additional response type added without assessment verification is an unverified competency entering the communication chain. Belt advancement is the mechanism that verifies additional competency.',diff:'hard'},
  {q:'How does a White Belt handle a situation where a caller begins to argue after being told the Lead will call back?',a:'Script 1 remains in effect. "I understand you need this urgently. The Lead will call you back within [timeframe]. Let me get your name and number." Do not engage in the argument. Do not expand your answer. Document the call and the urgency immediately so Lead can respond.',diff:'hard'},
  // Questions 41-100
  {q:'What instrument identification is required at White Belt?',a:'30 White Belt instruments must be identified by sight.',diff:'easy'},
  {q:'What happens at the end of White Belt assessment if Level 2 is passed but Level 3 is failed?',a:'Level 3 must be completed before White Belt is awarded. All three levels – Knowledge, Simulation, Observation – must be passed.',diff:'medium'},
  {q:'What is the key difference between "routing a question" and "answering a question" at White Belt?',a:'Routing means directing the caller to someone authorized to answer. Answering means providing information. White Belts route. They do not answer questions outside their two scripts.',diff:'easy'},
  {q:'What does a White Belt say when they cannot find the Lead and OR is holding on the line?',a:'"I\'m having difficulty locating the Lead right now. Can I take your number and have the Lead call you back within [X] minutes?" Document everything. Escalate to next available supervisor.',diff:'medium'},
  {q:'Why is "Let me find out" different from "Let me get the Lead"?',a:'"Let me find out" implies you will find the answer yourself – which may involve improvising. "Let me get the Lead" routes correctly and does not create the impression you will return with information.',diff:'hard'},
  {q:'What is a White Belt\'s first priority when receiving a call?',a:'Deliver Script 1 exactly as written, then listen completely without interrupting.',diff:'easy'},
  {q:'Define "zero improvisation" in one sentence.',a:'You do only what your belt authorizes, in the exact language your scripts specify, every time.',diff:'easy'},
  {q:'Why is documentation not optional at White Belt?',a:'Documentation creates a traceable record of every exchange. Without it, there is no evidence of what was communicated, no ability to investigate discrepancies, and no protection for the tech in a compliance review.',diff:'medium'},
  {q:'What patient outcome is prevented by Script 1?',a:'Script 1 prevents unauthorized information from entering the surgical workflow, which could cause incorrect instrument preparation, case delays, wrong-site setups, or retained items.',diff:'medium'},
  {q:'What makes a White Belt assessment Level 2 scenario "hard" versus "easy"?',a:'Hard scenarios add pressure: the caller is frustrated, the Lead is unavailable, the caller provides false urgency. Easy scenarios are direct: script trigger is obvious, no resistance.',diff:'medium'},
  {q:'Can a White Belt ever give a case cart status update?',a:'No. Case cart status is Lead-level information. A White Belt routes any status question to the Lead immediately.',diff:'easy'},
  {q:'What does the assessor look for in Level 3 observation that they cannot test in Level 2 simulation?',a:'Real-time behavior under actual working conditions: does the tech maintain Script 1 discipline when the phone rings mid-task, does the tech call the Lead immediately for every runner, does the tech document consistently throughout the shift.',diff:'hard'},
  {q:'How does the White Belt "protect" the department operationally?',a:'By containing the flow of information. If every call gets routed to the Lead, OR always speaks with someone who has the authority and knowledge to give accurate information. A White Belt who improvises creates a hole in that containment.',diff:'hard'},
  {q:'What is the role of the Lead when a White Belt routes a call?',a:'The Lead takes the call, provides accurate information, and documents the exchange. The Lead is accountable for the response.',diff:'easy'},
  {q:'Why does zero improvisation at White Belt protect the patient more than a "helpful" White Belt who tries to answer questions?',a:'A White Belt who "tries to help" creates two risks: they may give wrong information that affects case preparation, and they create an undocumented exchange that cannot be audited if something goes wrong.',diff:'hard'},
  {q:'What is the standard for passing the White Belt knowledge test?',a:'The actual assessment standard is 90%. The practice test standard is 80% before a candidate may request the real assessment.',diff:'medium'},
  {q:'A White Belt passes Level 1 and Level 2 but is nervous about Level 3. What should they focus on?',a:'Focus on two behaviors: delivering Script 1 the moment any call comes in, and never touching an instrument handoff without Lead authorization. Every other Level 3 requirement flows from those two.',diff:'medium'},
  {q:'What does "your scope" mean in the context of White Belt communication authority?',a:'Your scope is Scripts 1 and 2. Any communication not covered by those two scripts is outside your scope and must be routed to your Lead.',diff:'easy'},
  {q:'What information can a White Belt legally give to a caller under Script 1?',a:'Your name and that they have reached Sterile Processing. That is all. Anything beyond that requires Lead involvement.',diff:'easy'},
  {q:'What happens if a White Belt answers a clinical question about an instrument correctly but without authorization?',a:'Even a correct answer given without authorization is a protocol violation. The issue is not whether the answer was right. The issue is that an unauthorized person provided clinical information that they are not certified to provide.',diff:'hard'},
  {q:'How does the three-year development arc begin with White Belt?',a:'White Belt installs the first principle: operate within your certified scope. Every belt above White adds more scope. But the discipline of staying within your scope -- installed at White Belt -- governs all of them.',diff:'hard'},
  {q:'What is the White Belt vocabulary expectation?',a:'15 core terms must be understood and applied correctly: Decontamination, Sterilization, Reprocessing, Count sheet, Chain of custody, SPD, Lead Tech, Assembly, Sterilizer, Biological indicator, Chemical indicator, Load recall, Tray, Instrument set, High-level disinfection.',diff:'medium'},
  {q:'Why does Script 2 say "I\'ll get the Lead right away" rather than "The Lead will be right with you"?',a:'"I\'ll get the Lead" commits you to finding the Lead immediately. "The Lead will be right with you" makes a commitment on behalf of the Lead without their knowledge. If the Lead is not available, you have already set a false expectation.',diff:'hard'},
  {q:'What is the single biggest cause of White Belt assessment failures?',a:'Abandoning the script under pressure. The candidate knows Script 1 but reverts to natural conversation when a caller pushes back, expresses frustration, or creates urgency.',diff:'hard'},
  {q:'Describe the mindset difference between a tech who sees the script as a limitation versus one who sees it as protection.',a:'The tech who sees it as limitation is frustrated by what they cannot do. The tech who sees it as protection understands that staying in their script protects the patient, protects themselves from unauthorized information liability, and protects the department from unchecked communication errors.',diff:'hard'},
  {q:'What is the relationship between White Belt discipline and Black Belt mastery?',a:'Black Belt owns all 70 scripts and is the standard for the entire system. But Black Belt mastery is built on the same foundation as White Belt: operate within your scope, execute the approved language exactly, never improvise. The identity is the same at both ends. Only the scope is different.',diff:'hard'},
  {q:'In your own words, explain why White Belt is described as "the most important belt in the system" even though it has the least authority.',a:'Without a solid White Belt, every gate above it is unreliable. If White Belts improvise, give wrong information, or move instruments without authorization, the errors they create travel upward through the system. Green Belt Universal Protocol cannot catch an error that never got documented. Black Belt RCA cannot trace a problem that was never reported.',diff:'hard'},
  {q:'What is the patient safety rationale for Script 2 specifically?',a:'Unauthorized instrument movement by a runner creates a break in chain of custody. An instrument that moves without documentation may reach a sterile field without being properly processed, counted, or verified.',diff:'medium'},
  {q:'Can a White Belt ask clarifying questions before routing to Lead?',a:'Yes, one: "Who may I say is calling?" to give the Lead context. That is the only addition permitted within Script 1. No clinical questions, no case questions, no status questions.',diff:'medium'},
  {q:'What is the White Belt relationship to the Observation assessment?',a:'The Observation is a full-shift watch by an assessor. The tech does not know which specific moments will be evaluated. Consistency throughout the shift is required.',diff:'medium'},
  {q:'Why is "I\'m not sure but..." a forbidden phrase?',a:'It signals to the caller that you are about to answer a question you are not sure about. In healthcare communication, uncertain information delivered to OR can be acted upon with the same confidence as certain information.',diff:'medium'}
],

simulation: [
  {s:'The SPD phone rings. You are the only tech in assembly.',belt:'WHITE BELT',diff:'easy',answer:'Script 1: "Sterile Processing, this is [your name]. How can I help you?" Listen. Do not provide information. Route any question to Lead.'},
  {s:'A runner knocks and says "I need to pick up the total hip for OR 4."',belt:'WHITE BELT',diff:'easy',answer:'Script 2: "I\'ll get the Lead right away." Do not touch the set. Do not direct the runner anywhere. Find the Lead immediately.'},
  {s:'You answer the phone and the caller immediately says "Is my case cart ready?"',belt:'WHITE BELT',diff:'easy',answer:'Script 1 is already active. "Let me get the Lead for you right away." Locate Lead. Do not answer the status question.'},
  {s:'A surgeon calls SPD personally and demands to know where their instrument set is.',belt:'WHITE BELT',diff:'medium',answer:'Script 1 received the call. "Let me get the Lead for you right away." Do not tell the surgeon anything about the set\'s location. Locate Lead urgently and communicate the caller is a surgeon.'},
  {s:'The phone rings and the caller says "Don\'t give me the standard answer, just tell me if the spinal is ready."',belt:'WHITE BELT',diff:'medium',answer:'Script 1 still applies. "I understand. Let me get the Lead for you right now who can answer that directly." Do not break from the script. The pressure to break is exactly what this test is measuring.'},
  {s:'A runner arrives and says they are from the vendor and need their loaner set for an emergency at another facility.',belt:'WHITE BELT',diff:'medium',answer:'Script 2: "I\'ll get the Lead right away." Do not release the set. Do not confirm the set is here. Locate Lead immediately. The urgency of the request does not change the protocol.'},
  {s:'You are alone in decontam. Someone walks in through the staff entrance and starts heading toward assembly without stopping at the window.',belt:'WHITE BELT',diff:'medium',answer:'This is not a Script 2 scenario yet but you must intervene: "Can I help you?" If they are picking up instruments, Script 2 applies. Alert Lead immediately regardless.'},
  {s:'OR charge nurse calls and opens with "Your department is out of control. Where is our cart for OR 2?"',belt:'WHITE BELT',diff:'hard',answer:'Script 1 still applies. "Sterile Processing, this is [name]." You have already received the call. Now: "Let me get the Lead for you right away." Do not respond to the complaint. Do not defend. Route immediately.'},
  {s:'It is the end of your shift and you have not yet documented a call from an hour ago.',belt:'WHITE BELT',diff:'medium',answer:'Document immediately before leaving the shift. Date, time, your name, what was communicated, action taken, Lead notified. Undocumented exchanges are protocol violations regardless of when they are documented.'},
  {s:'The phone rings while you are in the middle of a tray assembly. You have gloves on and wet hands.',belt:'WHITE BELT',diff:'easy',answer:'Stop. Remove gloves. Answer with Script 1. Safety and documentation protocols always take priority over production activity.'},
  {s:'You answer Script 1 and the caller asks "Can I just leave a message for the Lead?" You have no paper nearby.',belt:'WHITE BELT',diff:'medium',answer:'Ask them to hold one moment. Find paper or a log. "What is your name and number and I will make sure the Lead gets this right away." Document immediately. Alert Lead.'},
  {s:'A delivery driver arrives at the dock with a sealed box addressed to SPD. There is no Lead currently on the floor.',belt:'WHITE BELT',diff:'hard',answer:'Script 2: "I\'ll get the Lead right away." Find the Lead or the next available supervisor. Do not sign for the package. Do not accept the delivery. No item enters SPD without Lead authorization.'},
  {s:'You answer the phone. The caller says they are from hospital administration and need to speak with whoever is in charge.',belt:'WHITE BELT',diff:'easy',answer:'Script 1 received the call. "Let me get the Lead for you right away." Route immediately. This is still a routing situation.'},
  {s:'A runner arrives and says "The Lead already knows I\'m coming. I can just grab the set myself."',belt:'WHITE BELT',diff:'hard',answer:'Script 2 applies regardless of what the runner claims. "I\'ll get the Lead to confirm and assist you." Do not release. Do not allow self-retrieval. If the Lead authorized it, the Lead can confirm it in person.'},
  {s:'You are answering Script 1 and the caller begins spelling out a long instrument name and asking if you have it.',belt:'WHITE BELT',diff:'medium',answer:'Allow them to finish speaking. Then: "Let me get the Lead for you right away -- they will be best able to confirm that for you." Do not attempt to answer or search while on the call.'},
  {s:'You receive a call at 3 AM and there is no Lead immediately available. A runner is also waiting at the window.',belt:'WHITE BELT',diff:'hard',answer:'Prioritize the call: Script 1. Tell the runner: "One moment please." Call comes first. After handling the call routing (locate Lead for phone), address the runner: Script 2. Document both interactions immediately.'},
  {s:'A peer White Belt asks you to cover their station while they go on break. Two minutes later the phone rings.',belt:'WHITE BELT',diff:'easy',answer:'Script 1 still applies regardless of whose station it is. "Sterile Processing, this is [your name]." You are the operator in that moment.'},
  {s:'You answer Script 1 and the caller says "Just transfer me to the Lead directly."',belt:'WHITE BELT',diff:'medium',answer:'"Absolutely. One moment." Locate Lead. If your system has a transfer, use it. If not: "I\'ll have the Lead call you back at this number within [X] minutes." Do not attempt to answer while finding the transfer.'},
  {s:'OR calls and the caller says "I just need a yes or no -- is the laparotomy set sterilized?"',belt:'WHITE BELT',diff:'hard',answer:'Script 1 has received the call. "Let me get the Lead for that information right away." A yes/no about sterilization status is clinical information you are not certified to confirm. Even if you see the set and it looks fine, you cannot verify its sterilization status.'},
  {s:'You are in the break room and hear the SPD phone ringing with no one else around.',belt:'WHITE BELT',diff:'medium',answer:'Go answer it. Script 1. You are staff in this facility. An unanswered SPD phone is an OR communication failure waiting to happen.'},
  {s:'A runner arrives with instruments to drop off, not pick up. No Lead is present.',belt:'WHITE BELT',diff:'hard',answer:'Script 2 applies to deliveries as well as pickups. "I\'ll get the Lead right away." Do not accept the delivery. No item enters without Lead sign-off on intake.'},
  {s:'You answer a call and the person hangs up without speaking after you deliver Script 1.',belt:'WHITE BELT',diff:'easy',answer:'Document: date, time, "incoming call, no response from caller." No action required beyond documentation.'},
  {s:'A runner arrives and is clearly a hospital employee you recognize. They say they just need to grab two forceps for a quick case.',belt:'WHITE BELT',diff:'hard',answer:'Script 2 regardless of relationship. Recognition does not equal authorization. "I\'ll get the Lead right away." Every instrument movement requires Lead authorization every time.'},
  {s:'The phone rings and caller ID shows "Operating Room 7." You know OR 7 is the orthopedic suite.',belt:'WHITE BELT',diff:'easy',answer:'Script 1 exactly as written. Caller ID does not change the script or give you authority to pre-answer based on assumption.'},
  {s:'You complete Script 1 and route the caller to the Lead. The Lead handles the call. Do you document it?',belt:'WHITE BELT',diff:'easy',answer:'Yes. You document the receipt of the call, the time, who called, what they asked (if stated), that you routed to Lead, and the Lead\'s name. The documentation responsibility does not transfer entirely to the Lead.'},
  // 26-100
  {s:'A supervisor from another department calls and asks if SPD can rush a tray for their procedure.',belt:'WHITE BELT',diff:'medium',answer:'Script 1 has received the call. Route to Lead. Do not make any commitment. Do not say "I\'ll tell the Lead to rush it." Only: "Let me get the Lead for you right away."'},
  {s:'You are delivering trays to a holding area outside SPD. Your phone rings. You are away from your station.',belt:'WHITE BELT',diff:'medium',answer:'Answer your phone. Script 1. If you cannot take the call safely at your location, return to a safe place before answering. But answer.'},
  {s:'A runner arrives and the Lead is on the phone. The runner is impatient.',belt:'WHITE BELT',diff:'hard',answer:'Signal to the Lead that a runner is waiting. Do not authorize the runner to wait inside. Do not give them information. "The Lead will be right with you -- just one moment." Wait for Lead to become available.'},
  {s:'The phone rings, you answer Script 1, and the caller immediately puts you on hold.',belt:'WHITE BELT',diff:'easy',answer:'Wait. When they return: maintain your identity. "Sterile Processing, this is [name]." If they ask a question, route to Lead.'},
  {s:'OR charge calls and says "I just want to give you a heads up about an add-on case."',belt:'WHITE BELT',diff:'medium',answer:'Script 1 has already been delivered. "Thank you -- let me get the Lead right away so they can take this information and respond." Route. Do not attempt to note details and pass them to Lead yourself. Lead needs to hear it directly.'},
  {s:'A tech from another department walks into SPD through the staff entrance without stopping.',belt:'WHITE BELT',diff:'medium',answer:'Intercept: "Can I help you?" If they have any instrument business, Script 2 applies. No one moves instruments in SPD without Lead authorization, regardless of what department they are from.'},
  {s:'You answer Script 1 and the caller asks "Who is the Lead right now?"',belt:'WHITE BELT',diff:'easy',answer:'You may provide the Lead\'s name if known. "The Lead today is [name]. Let me get them for you." This is within the scope of routing.'},
  {s:'A runner says they have a "critical" item that cannot wait for the Lead.',belt:'WHITE BELT',diff:'hard',answer:'Script 2 applies regardless of declared urgency. "I\'ll get the Lead right away." Find the Lead urgently. The runner\'s claim of criticality is not authorization. Only the Lead can authorize the movement.'},
  {s:'The phone rings and you are told to never answer calls by a peer who says "the Lead handles all calls."',belt:'WHITE BELT',diff:'hard',answer:'This is incorrect instruction. Every SPD phone call must be answered according to Script 1. If the Lead is available immediately and takes calls directly, the Lead answers. But you cannot leave a call unanswered. Clarify with your Lead.'},
  {s:'OR calls asking about an instrument that was loaned to another facility. You have no information about this.',belt:'WHITE BELT',diff:'medium',answer:'Script 1 has received the call. "Let me get the Lead for you right away." Your lack of information about the loaned instrument is exactly why you cannot answer. The Lead will have or find the information.'},
  {s:'You complete Level 2 simulation at 91%. Can you request your real assessment?',belt:'WHITE BELT',diff:'easy',answer:'No. You must pass both the knowledge test AND simulation scenarios at 80% or above. If both are at 80%+, you may request the real assessment through the system.'},
  {s:'A courier arrives from a medical device company with a tray to be processed. They say it is urgent.',belt:'WHITE BELT',diff:'medium',answer:'Script 2. "I\'ll get the Lead right away." External couriers have zero authorization to enter SPD or place items in the processing queue without Lead sign-off.'},
  {s:'The phone rings. Caller says "I know this isn\'t SPD business but can you page Dr. Smith for me?"',belt:'WHITE BELT',diff:'medium',answer:'Script 1 has been delivered. "I\'m not able to page from this department. You can reach the operator at [number]." This is a routing and redirect -- within scope because it does not involve clinical information.'},
  {s:'An administrator calls and says they are doing a compliance audit and need to speak with you directly.',belt:'WHITE BELT',diff:'hard',answer:'Script 1 received the call. "Let me get the Lead for you right away." Even compliance audits go through Lead. You do not grant an auditor access to your department or answer their questions without Lead presence.'},
  {s:'You are in the middle of Script 1 and the caller begins giving you detailed case information unprompted.',belt:'WHITE BELT',diff:'medium',answer:'Listen completely. Do not interrupt. When they finish: "Thank you for that information -- let me get the Lead right away so they can act on this." Document what was shared before finding the Lead.'},
  {s:'OR calls and you recognize the voice as the OR supervisor you work with every day.',belt:'WHITE BELT',diff:'medium',answer:'Script 1 regardless. Recognition does not change your scope or authorize you to answer clinical questions. The relationship matters socially; it does not expand your authority.'},
  {s:'The Lead is tied up in an RCA meeting and has left a note saying "hold all calls." The phone rings.',belt:'WHITE BELT',diff:'hard',answer:'Answer with Script 1. Tell the caller the Lead is in a meeting and ask if they can hold or provide a callback number. Locate the Lead or next supervisor to inform them of the call. Do not go silent on the phone.'},
  {s:'You complete your shift and realize you documented a call with the wrong time.',belt:'WHITE BELT',diff:'medium',answer:'Correct the documentation with a notation: "Time corrected -- original entry showed [wrong time], actual time was [correct time]. Corrected by [your name] on [date]." Do not erase or overwrite without notation.'},
  {s:'Two calls come in simultaneously. You have one phone.',belt:'WHITE BELT',diff:'hard',answer:'Answer the first call with Script 1. Tell them to hold momentarily. Go to the second call if possible, deliver Script 1, take their callback number if they cannot hold. Return to the first call. Document both. Alert Lead to both.'},
  {s:'A runner arrives and says they do not need to wait for the Lead because they come every day.',belt:'WHITE BELT',diff:'hard',answer:'Script 2 regardless of frequency. Frequency of visits does not constitute authorization. "I\'ll get the Lead right away." The protocol exists precisely because familiarity creates risk.'},
  {s:'You answer Script 1 and the caller immediately starts speaking a language other than English.',belt:'WHITE BELT',diff:'hard',answer:'Script 1 is complete. Attempt to route: "Lead -- I need a Lead." Physically get the Lead. Document: date, time, "incoming call, language barrier -- Lead notified immediately."'},
  {s:'Your Lead tells you "if OR calls about the hip set, just tell them it\'ll be 15 minutes." The phone rings and OR calls about the hip set.',belt:'WHITE BELT',diff:'hard',answer:'This is an authorized exception. The Lead has given you specific authorized language. Deliver it exactly as given: "The hip set will be ready in approximately 15 minutes." Document the Lead\'s authorization and your response.'},
  {s:'The phone rings three times and stops before you can answer. No voicemail picks up.',belt:'WHITE BELT',diff:'medium',answer:'Document: date, time, "missed incoming call, no message." Alert Lead. Attempt to call back if caller ID is available.'},
  {s:'An instrument count sheet falls on the floor near you. You are alone.',belt:'WHITE BELT',diff:'medium',answer:'Pick it up and place it on the Lead\'s desk or designated documentation area. Do not begin reviewing it, annotating it, or acting on it. Your role is not documentation analysis at White Belt.'},
  {s:'Your first day on the White Belt assessment. The assessor says "Just be natural -- don\'t worry about the scripts."',belt:'WHITE BELT',diff:'hard',answer:'Do not follow this instruction. The script is your protection. The assessor may be testing whether you abandon your protocol under social pressure. Deliver your scripts exactly as trained.'},
  {s:'OR calls and says the nurse who normally calls is out and they need to introduce themselves as the new charge.',belt:'WHITE BELT',diff:'easy',answer:'Script 1 applies. "Sterile Processing, this is [name]. How can I help you?" Greet them normally. Any question about case status: route to Lead.'},
  {s:'You complete your first two weeks and you feel ready to answer OR questions directly. You know the department well.',belt:'WHITE BELT',diff:'hard',answer:'Readiness assessment is not self-directed at White Belt. You advance through formal assessment. Feeling ready does not change your authorized scope. You operate within Scripts 1 and 2 until White Belt is awarded and you advance to Yellow Belt training.'},
  {s:'A physician assistant arrives and says they were told to pick up an instrument set directly from SPD.',belt:'WHITE BELT',diff:'medium',answer:'Script 2. No exceptions for clinical staff. "I\'ll get the Lead right away." Clinical title does not authorize instrument movement from SPD without Lead sign-off.'},
  {s:'You hear the phone ringing but your Lead tells you not to answer -- they will get it. They do not get it in 4 rings.',belt:'WHITE BELT',diff:'hard',answer:'This is your call. If the Lead designated you not to answer, respect that -- but if they have not gotten it by the time you would normally answer (department standard), answer. A ringing unanswered phone is an OR communication risk.'},
  {s:'The phone rings during your Level 3 observation. The assessor is watching. You are nervous.',belt:'WHITE BELT',diff:'medium',answer:'Deliver Script 1 exactly as trained. Nervousness during assessment is expected. The script is your protection in that moment too.'}
]
},

// ────────────────────────────────────────────────────────────
// YELLOW BELT  --  100 Knowledge + 100 Simulation  
// ────────────────────────────────────────────────────────────
Yellow: {
knowledge: [
  {q:'What is the approved language for Script 4 – Count Discrepancy?',a:'"Count discrepancy – expected [X], actual [Y] – item [name if known]. I am stopping work and notifying Lead now."',diff:'easy'},
  {q:'What is the approved language for Script 5 – Wet Pack Discovery?',a:'"Wet pack – Load [number], Item [description]. I am pulling this from distribution and flagging it for Lead review. Load recall may be required."',diff:'easy'},
  {q:'What does "stop-work authority" mean at Yellow Belt?',a:'The authority and obligation to halt your current work and notify Lead immediately when a patient safety event occurs: count discrepancy, wet pack, sterilizer abort, damaged instrument, or any protocol deviation.',diff:'easy'},
  {q:'What is the Yellow Belt identity statement?',a:'Single-area mastery. Report upward. Stop work, preserve, notify.',diff:'easy'},
  {q:'What is AAMI ST79?',a:'The AAMI ST79 standard is the primary technical document governing the processing of flexible and rigid endoscopes and other heat-sensitive patient care equipment. It establishes the standard for high-level disinfection and sterilization.',diff:'easy'},
  {q:'Name the 9 Yellow Belt scripts (Scripts 3-11).',a:'Script 3: Decontam Handoff. Script 4: Count Discrepancy. Script 5: Wet Pack. Script 6: Sterilizer Abort. Script 7: Instrument Damage. Script 8: Missing Instrument. Script 9: Priority Flag from OR. Script 10: Documentation Entry. Script 11: End-of-Shift Zone Report.',diff:'easy'},
  {q:'What is the approved documentation format for Script 10?',a:'Date, time, your name, event description (factual, specific), action taken, Lead notified (yes/no), outcome. No opinions. No assumptions. Only facts.',diff:'easy'},
  {q:'What patient safety risk makes a wet pack a mandatory stop-work event?',a:'A wet pack means moisture compromised the sterilization packaging, which may allow microbial re-contamination. The item can no longer be confirmed sterile and must never be used.',diff:'easy'},
  {q:'What is the Yellow Belt coverage area?',a:'Single assigned area (decontam, assembly, or sterilization). Yellow Belt must demonstrate mastery of their assigned area before advancing to Green Belt multi-area proficiency.',diff:'easy'},
  {q:'What happens to an instrument you flag for damage under Script 7?',a:'It is removed from service, tagged for biomedical review, and documented in the log. It does not return to use until cleared by biomedical and Lead.',diff:'easy'},
  {q:'Why can\'t a Yellow Belt make timeline commitments when OR calls with a priority request (Script 9)?',a:'The Yellow Belt does not have operational visibility or authority to confirm timelines. A false commitment causes OR to plan around a time that may not be met. The Lead holds timeline authority.',diff:'easy'},
  {q:'What is a sterilizer abort and why is it a stop-work event?',a:'A sterilizer abort occurs when a sterilizer cycle terminates before completing all required phases. Sterility cannot be confirmed for any item in that load. All items are quarantined and treated as non-sterile.',diff:'easy'},
  {q:'What does "load recall" mean and when is it required?',a:'A load recall is the retrieval of all items from a specific sterilizer load due to a sterilization failure (abort, wet pack, biological indicator failure). Required when the integrity of the entire load is in question.',diff:'medium'},
  {q:'What is the difference between a stop-work event and a notify-Lead event?',a:'Stop-work: immediately halt current work and notify Lead -- triggered by anything that is a direct patient safety risk. Notify-Lead: communicate to Lead without stopping work -- triggered by operational issues that need oversight but do not create immediate risk.',diff:'medium'},
  {q:'What six elements must appear in a Yellow Belt documentation entry (Script 10)?',a:'Date, time, your name, factual event description, action taken, Lead notified (yes/no).',diff:'easy'},
  {q:'Why does the Yellow Belt documentation standard prohibit opinions and assumptions?',a:'Documentation that contains opinions ("it seemed fine") or assumptions ("probably just condensation") is not auditable. In a compliance review or legal proceeding, opinion language is inadmissible and creates professional exposure.',diff:'medium'},
  {q:'What is the approved format for Script 11 – End-of-Shift Zone Report?',a:'"[Area name] – [X] trays completed, [X] in queue, [X] pending issues, any unresolved counts: [specify], any open leads: [specify]. Equipment status: [normal/issue]. Everything documented."',diff:'medium'},
  {q:'What makes an end-of-shift report inadequate at Yellow Belt?',a:'Vague language: "Things are mostly good," "I think we\'re caught up," "A few things to watch." These do not give the incoming Lead actionable information.',diff:'medium'},
  {q:'What is the patient safety rationale for Script 8 – Missing Instrument?',a:'A missing instrument sent to OR creates a retained item risk. If the instrument is in the tray but was supposed to be documented as missing, the count in OR will not match, leading to an emergency instrument search mid-surgery.',diff:'medium'},
  {q:'What instruments must a Yellow Belt identify by sight?',a:'25 Yellow Belt instruments, cumulative with 30 White Belt instruments = 55 total instruments at Yellow Belt level.',diff:'easy'},
  {q:'What is the approved action for Script 6 – Sterilizer Abort?',a:'"Sterilizer [number] – cycle abort on Load [number]. Instruments quarantined. Lead notified. Load recall initiated." Do not attempt to restart without Lead authorization.',diff:'easy'},
  {q:'Why is "it\'s probably just condensation" dangerous when applied to a wet pack?',a:'The Yellow Belt is not qualified to make sterility determinations. "Probably" introduces a patient safety gamble. If the instrument reaches a patient and causes an infection, the documentation will show the Yellow Belt identified a wet pack and dismissed it.',diff:'medium'},
  {q:'What does "single-area mastery" mean at Yellow Belt?',a:'Yellow Belt must demonstrate complete competency in their assigned zone: all 9 scripts triggered correctly, all equipment in that zone operated properly, all documentation maintained, and all stop-work events handled immediately.',diff:'medium'},
  {q:'What is the decontam handoff standard (Script 3)?',a:'"Instruments from [location], count of [number], [clean/not clean status], any concerns: [specific issue or none]. Lead notified: [yes/no]." All six elements required.',diff:'medium'},
  {q:'What is the Yellow Belt assessment Level 2 – Simulation standard?',a:'15 scenarios. Must demonstrate: correct script for each trigger, correct stop-work triggers, appropriate tone, documentation intent, and Lead notification. Includes scenarios for count discrepancy, wet pack, sterilizer abort, priority request, and shift handoff.',diff:'medium'},
  {q:'What is pitting on a surgical instrument and why does it require removal from service?',a:'Pitting is small surface corrosion craters on instrument metal. Pits harbor biofilm that can survive sterilization and transfer to a patient. A pitted instrument cannot be reliably sterilized.',diff:'medium'},
  {q:'Why does the decontam handoff (Script 3) include "Lead notified: yes/no"?',a:'Lead notification status creates accountability for whether the Lead is aware of any issues with the load. If there is a subsequent problem with instruments from that load, the documentation establishes whether the Lead was informed.',diff:'medium'},
  {q:'What is the Yellow Belt vocabulary requirement?',a:'15 core terms beyond White Belt: Load recall, Biological indicator, Biofilm, AAMI ST79, Wet pack, Cycle abort, Count discrepancy, Stop-work authority, Chain of custody, Tray assembly sheet, Pull sheet, Instrument tracking, Decon, Assembly, Sterilization release.',diff:'medium'},
  {q:'What is the Level 3 observation standard for Yellow Belt?',a:'Full shift in assigned area. Mandatory behaviors: all scripts delivered correctly, stop-work executed on any qualifying event, every event documented, Lead notified on all required triggers.',diff:'medium'},
  {q:'Explain the relationship between Script 11 and patient safety.',a:'An incomplete or vague shift report leaves the incoming Lead without critical information. If there are pending counts, open equipment issues, or unresolved discrepancies that are not communicated, the incoming shift begins with unknown risks.',diff:'hard'},
  {q:'What is the patient safety rationale for Script 7 – Instrument Damage?',a:'Damaged instruments can fail mid-surgery, cause patient injury, or harbor biofilm that survives sterilization. A damaged instrument that reaches a sterile field creates both immediate injury risk and infection risk.',diff:'medium'},
  {q:'When should a Yellow Belt initiate a load recall independently versus waiting for Lead?',a:'A Yellow Belt does not initiate a load recall independently. They quarantine the affected instruments and notify Lead immediately. The Lead makes the load recall decision. Script 6 documents this: "Instruments quarantined. Lead notified. Load recall initiated."',diff:'hard'},
  {q:'What is the Yellow Belt stop-work trigger hierarchy?',a:'Any event that may compromise the sterility or integrity of an item that could reach a patient. The five primary triggers: count discrepancy, wet pack, sterilizer abort, instrument damage, decontam handoff with contamination concern.',diff:'hard'},
  {q:'How does a Yellow Belt\'s documentation at Level 10 protect them in a Joint Commission audit?',a:'Factual, dated, timed, signed entries with specific event descriptions and actions taken create an auditable record of compliance. Vague or missing entries suggest undocumented deviations, which create compliance violations.',diff:'hard'},
  {q:'What is the difference between a "priority flag" in Script 9 and a STAT case?',a:'A priority flag is OR notifying SPD of an urgent need -- it may still be non-emergent. A STAT case is an emergent surgical situation where OR needs instruments immediately. Both are routed to Lead. Yellow Belt makes no time commitment in either case.',diff:'hard'},
  {q:'What happens if a Yellow Belt stops work on a count discrepancy and the count turns out to be correct?',a:'Nothing negative. Stopping work on a count discrepancy is correct protocol regardless of outcome. The protocol exists because the risk of proceeding with an incorrect count (retained item) is far greater than the cost of stopping work.',diff:'hard'},
  {q:'Describe what "factual event description" means in Script 10 and give an example.',a:'Factual means observational only -- what you saw, not what you interpret. Example: "Found instrument count 13, expected 14. Needle driver not located in tray." Not: "The count seemed off, probably because someone was careless."',diff:'hard'},
  {q:'What is the cumulative script count a Yellow Belt must know?',a:'11 scripts: Scripts 1-2 from White Belt plus Scripts 3-11 from Yellow Belt.',diff:'easy'},
  {q:'Why is the end-of-shift zone report a patient safety document?',a:'The incoming shift Lead uses the zone report to establish department status immediately. If the report is incomplete, the incoming Lead may not know about an open count, a quarantined load, or pending equipment issues -- all of which can reach a patient.',diff:'hard'},
  {q:'What is the relationship between Script 8 and OR communication authority?',a:'Script 8 places instrument status information with the Lead, not the Yellow Belt. The Yellow Belt flags the missing instrument, checks the pull sheet, and notifies Lead. The Lead communicates to OR. The Yellow Belt never contacts OR about instrument status.',diff:'hard'},
  {q:'What is Script 9\'s forbidden phrase "Should be 10 minutes" and why is it dangerous?',a:'It is a time commitment made without operational authority or information. If the tray is not ready in 10 minutes, OR has been given false information and may have staged cases around it. The Lead holds time commitment authority.',diff:'medium'},
  {q:'What is the 80% practice threshold and what does it unlock?',a:'When a staff member scores 80% or above on both the knowledge test and simulation scenarios for their current belt, they may request the real gate assessment from the system. Admins review and approve or deny the request.',diff:'medium'},
  {q:'What must happen before a Yellow Belt tray is distributed from sterilization?',a:'Biological indicator must be confirmed negative (for implant loads), chemical indicator must be confirmed change, sterilizer cycle data must be reviewed, documentation must be complete.',diff:'medium'},
  {q:'What is the Yellow Belt practice test 80% requirement specifically?',a:'80% on the knowledge test AND 80% on the simulation scenarios. Both thresholds must be met independently. 85% knowledge and 70% simulation does not qualify.',diff:'easy'},
  {q:'Define biofilm and explain its patient safety significance.',a:'Biofilm is a protective matrix produced by microorganisms that adheres to instrument surfaces. Biofilm can survive sterilization and transfer to a patient during surgery, causing healthcare-associated infections.',diff:'medium'},
  {q:'What is the Yellow Belt response to discovering a biological indicator failure?',a:'Immediately quarantine all items from that load. Document. Notify Lead. Do not release any item from that load. Lead initiates load recall and notifications.',diff:'medium'},
  {q:'Describe the complete sequence of actions when a Yellow Belt discovers an aborted sterilizer cycle.',a:'1) Open sterilizer door (if safe). 2) Identify load number. 3) Do not remove items for use. 4) Quarantine all items in the load. 5) Script 6: state the abort, quarantine status, and Lead notification. 6) Document. 7) Wait for Lead authorization before any restart attempt.',diff:'hard'},
  {q:'What does a Yellow Belt document if they are unable to locate a missing instrument after checking the pull sheet?',a:'"Instrument [name] missing from [tray name], pull sheet reviewed, instrument not located. Tray flagged as incomplete. Lead notified at [time]. Tray held -- not distributed."',diff:'hard'},
  {q:'What is the practice assessment completion requirement before requesting a real Yellow Belt gate?',a:'80% on both the SIPS Intelligence knowledge test and the simulation scenario test for Yellow Belt. Both tests must meet the threshold.',diff:'easy'},
  {q:'What does "preserve" mean in the Yellow Belt identity "Stop work, preserve, notify"?',a:'"Preserve" means do not alter, move, discard, or modify any item involved in a stop-work event before Lead reviews it. Preserve the exact state of the finding for Lead assessment.',diff:'medium'},
  {q:'Why is the Yellow Belt Zone Report more important than a personal update to the Lead?',a:'A Zone Report is a documentation artifact, not just a verbal update. If there is a subsequent incident, the Zone Report provides evidence that relevant information was communicated at shift end.',diff:'hard'}
],

simulation: [
  {s:'During assembly you count a basic set and find 12 instruments. Expected count is 14.',belt:'YELLOW BELT',diff:'easy',answer:'Script 4: "Count discrepancy – expected 14, actual 12. I am stopping work and notifying Lead now." Stop all work on the tray. Do not continue. Document immediately. Lead makes the tray decision.'},
  {s:'You open the sterilizer after a completed cycle and find one wrapped set with visible moisture inside the packaging.',belt:'YELLOW BELT',diff:'easy',answer:'Script 5: "Wet pack – Load [number], [item description]. I am pulling this from distribution and flagging it for Lead review. Load recall may be required." Pull immediately. Do not send out. Notify Lead. Document.'},
  {s:'OR calls during your shift and says they need a tray urgently. You are the only one in your area.',belt:'YELLOW BELT',diff:'easy',answer:'Script 9: "I have a priority request from OR [number] for [item]. Documenting and routing to Lead immediately. Lead will communicate back to OR with timeline." Do not make a time commitment.'},
  {s:'You are running instrument inspection and discover a needle driver with visible pitting on the jaw.',belt:'YELLOW BELT',diff:'easy',answer:'Script 7: "Instrument – needle driver – visible pitting on jaw surface. Removing from service, tagging for biomedical review, documenting in log." Pull the instrument immediately.'},
  {s:'Your sterilizer mid-cycle suddenly aborts with an error code. Load 6 is inside.',belt:'YELLOW BELT',diff:'easy',answer:'Script 6: "Sterilizer [number] – cycle abort on Load 6. Instruments quarantined. Lead notified. Load recall initiated." Quarantine all items in Load 6. Do not restart. Notify Lead.'},
  {s:'End of shift. Your queue has 3 sets remaining, 2 counts open from the last hour, and Sterilizer 2 is showing a fault light.',belt:'YELLOW BELT',diff:'medium',answer:'Script 11: "[Area] – [X] trays completed, 3 in queue, 2 open counts pending investigation, open leads: Sterilizer 2 fault light. Equipment status: fault on Sterilizer 2. Everything documented." Specific. No vague language.'},
  {s:'During decontam handoff to assembly you find instruments from OR 4 are not fully cleaned -- visible soil on the jaws of a clamp.',belt:'YELLOW BELT',diff:'medium',answer:'Script 3 with concern flagged: "Instruments from OR 4, count of [X], NOT clean -- visible soil on [instrument]. Lead notified: immediately. Returning to decontam for reprocessing." Do not pass dirty instruments to assembly.'},
  {s:'You are completing a tray and realize one instrument listed on the assembly sheet is not in the tray or in any of the trays on the cart.',belt:'YELLOW BELT',diff:'medium',answer:'Script 8: "[Instrument name] missing from [tray name], count [X of Y]. Pull sheet reviewed -- not located. Flagging tray as incomplete. Notifying Lead. Not distributing this tray."'},
  {s:'You finish your entire shift without a single count discrepancy or equipment issue. Do you still complete a Zone Report?',belt:'YELLOW BELT',diff:'easy',answer:'Yes. Script 11 is mandatory regardless of shift status. The incoming Lead needs to know the queue is clear, counts are clean, and equipment is normal. "All clear" is still a report.'},
  {s:'An OR tech calls and says they need the spinal set for a case starting in 5 minutes. The set is in the sterilizer.',belt:'YELLOW BELT',diff:'hard',answer:'Script 9: route to Lead. Do NOT tell them the set is in the sterilizer. Do NOT give a timeline. Lead communicates status and options. You document the call and time of Lead notification.'},
  {s:'A runner arrives and asks for a tray you cannot find in the distribution area.',belt:'YELLOW BELT',diff:'medium',answer:'Do not tell the runner "it must be here somewhere." Script 8 logic: flag it as unlocated. Notify Lead. Do not release until Lead confirms location and status. Runner waits.'},
  {s:'You discover that a tray you processed yesterday was released with an incorrect count -- you are just now noticing the discrepancy in the documentation.',belt:'YELLOW BELT',diff:'hard',answer:'This is a retrospective count discrepancy. Notify Lead immediately. Document: "Retrospective count discrepancy identified -- [tray], [date], [count issue]. Lead notified at [time]." Lead determines if a case is already using this tray and whether OR notification is needed.'},
  {s:'During sterilization you notice the biological indicator incubating in the incubator has turned yellow after 3 hours.',belt:'YELLOW BELT',diff:'hard',answer:'Biological indicator failure. This is a stop-work, quarantine, notify event. Script 5 logic applies to the load associated with this indicator. "Biological indicator positive -- Load [number]. Quarantining load. Notifying Lead immediately. Load recall required." Document.'},
  {s:'You are documenting an event and are not sure of the exact time it happened. It was "around 2:30."',belt:'YELLOW BELT',diff:'medium',answer:'Document with your best estimate and note it: "Approximately 14:30." Do not document "sometime in the afternoon" or leave the time blank. Approximate but documented is better than undocumented.'},
  {s:'A tray comes through decontam with a note attached saying "Use as-is, OR says it\'s fine."',belt:'YELLOW BELT',diff:'hard',answer:'Ignore the note. Process the instruments according to decontam protocol. A note from OR does not bypass SPD processing standards. If instruments are not clean, Script 3 applies. Document the note and notify Lead.'},
  {s:'You notice during assembly that the count sheet attached to a tray is from a different tray entirely.',belt:'YELLOW BELT',diff:'hard',answer:'Script 8 logic: count cannot be verified because the sheet is wrong. Flag as incomplete. Notify Lead. Do not proceed with assembly using the wrong count sheet. Document: "Wrong count sheet attached to [tray name]. Assembly stopped. Lead notified."'},
  {s:'OR calls and the caller says "I just need you to tell the Lead that we need everything rushed today."',belt:'WHITE BELT + YELLOW BELT',diff:'medium',answer:'Script 9: "I have a priority request from OR [caller name/number]. Documenting and routing to Lead immediately." Route. Document the request.'},
  {s:'You complete assembly on a complex tray and your count is correct. But one instrument has a cracked ratchet.',belt:'YELLOW BELT',diff:'medium',answer:'Script 7 for the cracked ratchet. Remove it from service. Tag it. Document it. The tray is now one instrument short -- Script 8 applies. Notify Lead about both the damaged instrument and the incomplete tray.'},
  {s:'Sterilizer abort occurs. You restart the sterilizer and begin the next cycle without notifying Lead.',belt:'YELLOW BELT',diff:'hard',answer:'This is a protocol violation. Script 6 is mandatory before any restart. Lead must authorize the restart. The load from the aborted cycle must be quarantined first.'},
  {s:'Your zone report at end of shift includes "Everything was fine today." Is this complete?',belt:'YELLOW BELT',diff:'medium',answer:'No. Script 11 requires: trays completed, queue status, open counts, open leads, equipment status. "Everything was fine" is not auditable and provides no specific information to the incoming Lead.'},
  {s:'You are handing off to the next shift Yellow Belt and you notice their documentation is behind. What do you do?',belt:'YELLOW BELT',diff:'medium',answer:'Complete your own Zone Report (Script 11). If you can, alert the incoming Lead that the documentation is behind. You are not responsible for completing another tech\'s documentation, but you are responsible for flagging the gap.'},
  {s:'A runner arrives while you are documenting a count discrepancy. You are in the middle of an active stop-work event.',belt:'YELLOW BELT',diff:'hard',answer:'Finish the stop-work documentation. The runner waits. "One moment -- I\'m in the middle of a documentation requirement." Then: Script 2 for the runner. Alert Lead for both the count discrepancy and the runner simultaneously.'},
  {s:'Your Lead tells you "If OR calls about the hip tray, just tell them it\'ll be ready in 30 minutes." OR calls about the hip tray.',belt:'YELLOW BELT',diff:'medium',answer:'This is Lead-authorized language. You may deliver it: "The hip tray will be ready in approximately 30 minutes." This is within your scope because the Lead has specifically authorized this response.'},
  {s:'During decontam you find a tray with a broken sterilization indicator -- the indicator changed color but the tape that seals the bag is torn.',belt:'YELLOW BELT',diff:'hard',answer:'Compromised packaging integrity is a stop-work event. The color change of the indicator does not confirm sterility if the package is not intact. Script 5 logic: pull from distribution, flag for Lead review. Document.'},
  {s:'You realize mid-shift that you forgot to document a count discrepancy from two hours ago. You resolved it with the Lead.',belt:'YELLOW BELT',diff:'hard',answer:'Document it now with a notation: "Delayed entry -- event occurred at approximately [time]. Count discrepancy: [details]. Lead notified at [time], resolved [how]." Late documentation is better than no documentation.'},
  // 26-100
  {s:'An instrument is returned from OR with a note saying "sterilize ASAP." You are in decontam.',belt:'YELLOW BELT',diff:'medium',answer:'Do not skip decontam processing to fast-track sterilization. The instrument must complete decontam before sterilization regardless of urgency. Notify Lead of the urgency request via Script 9 logic.'},
  {s:'You find 3 instruments in a loose tray with no count sheet attached.',belt:'YELLOW BELT',diff:'medium',answer:'Do not add them to any tray or process them without a count sheet. Document: "Three loose instruments found with no count sheet. Flagged for Lead review. Not processed." Notify Lead.'},
  {s:'OR sends back a tray saying "there was a count discrepancy in the OR." You processed this tray.',belt:'YELLOW BELT',diff:'hard',answer:'Do not argue or defend. Accept the tray return. Script 8 logic: recount under Lead supervision. Document: "Tray returned from OR with reported count discrepancy -- [tray name], [date]. Recount initiated with Lead present." Full investigation follows.'},
  {s:'You are behind on your zone and you rush through the last two counts without fully verifying.',belt:'YELLOW BELT',diff:'hard',answer:'This is a protocol violation. Every count must be fully verified regardless of shift time pressure. If you cannot complete counts fully, notify Lead and request help. Do not cut corners on count verification.'},
  {s:'A runner arrives for a tray and the Lead is in an assessment meeting. The tray is clearly tagged and ready.',belt:'YELLOW BELT',diff:'hard',answer:'Script 2 regardless. The Lead\'s physical availability matters. The Lead must authorize even a clearly ready tray. Interrupt the meeting briefly if needed. Runner waits.'},
  {s:'The phone rings. The caller asks for the count of a specific tray you just completed.',belt:'YELLOW BELT',diff:'medium',answer:'This is clinical information outside Script 9. Route to Lead. "Let me get the Lead for that information right away." You verified the count. You do not report the count to outside parties.'},
  {s:'You complete a sterilizer load and release it before the biological indicator has been read.',belt:'YELLOW BELT',diff:'hard',answer:'This is a patient safety violation for any implant load. Retrieve the distributed items if possible. Notify Lead immediately. Document. For non-implant loads: your facility policy applies -- notify Lead and document regardless.'},
  {s:'An instrument comes back from decontam with insulation intact but the instrument is bent at a non-standard angle.',belt:'YELLOW BELT',diff:'medium',answer:'Script 7: physical damage. Remove from service. Tag for biomedical review. Document. A bent instrument cannot be assumed functional.'},
  {s:'You have 8 minutes left in your shift and 3 undocumented entries to complete.',belt:'YELLOW BELT',diff:'medium',answer:'Document all 3 before leaving. Do not leave undocumented events for the next shift. If you need to stay a few minutes, you stay. Undocumented events are protocol violations.'},
  {s:'OR calls asking where their delayed tray is. You know it\'s in sterilization.',belt:'YELLOW BELT',diff:'hard',answer:'Script 9: route to Lead. Do not tell OR the tray location. Do not give a timeline. You do not have Lead authority to give case cart status. Document and notify Lead urgently of the call.'},
  {s:'You find a tray with a chemical indicator that did not change color after sterilization.',belt:'YELLOW BELT',diff:'hard',answer:'Chemical indicator failure = potential sterilization failure for this item. Script 5 logic. Pull from distribution. Flag for Lead review. Document. Do not use the item.'},
  {s:'Your count comes up short by one and after 15 minutes you find the instrument in a clean but unprocessed area.',belt:'YELLOW BELT',diff:'medium',answer:'Update Script 4 documentation: "Count discrepancy resolved -- [instrument] located in [area] at [time]. Lead notified." Document the resolution fully. The original stop-work entry remains.'},
  {s:'A new tech asks you to show them how to skip the handoff script during a busy period.',belt:'YELLOW BELT',diff:'hard',answer:'Do not demonstrate this. Explain: the handoff script is not optional during busy periods. The documentation is most important during high-volume periods because that is when errors are most likely.'},
  {s:'You are handing off to the next shift and realize you never ran Script 11 at end of your last three shifts.',belt:'YELLOW BELT',diff:'hard',answer:'Run it now. Then retroactively document the gap: "Zone reports not completed for [dates]. Corrective action: Zone report completed today; Lead notified of documentation gap." Self-correct and report.'},
  {s:'A tray passes through your area multiple times in one shift due to reprocessing needs.',belt:'YELLOW BELT',diff:'medium',answer:'Document each pass. Each reprocessing cycle is a separate documentation entry. Script 3 is delivered each time a handoff occurs.'},
  {s:'You receive instruments from decontam with a count of 18 but no count sheet.',belt:'YELLOW BELT',diff:'medium',answer:'Do not proceed. You cannot verify the count without the count sheet. Script 3 logic: flag, hold, notify Lead. The instruments cannot be assembled without a verified count sheet.'},
  {s:'OR calls during a sterilizer abort event and you are in the middle of quarantining the load.',belt:'YELLOW BELT',diff:'hard',answer:'Script 9: route to Lead. "I have a priority request from OR -- routing to Lead immediately." Continue quarantine simultaneously. Document both events with exact times.'},
  {s:'You find an instrument that passed your count but you notice it has a hairline crack in the handle not listed on any damage log.',belt:'YELLOW BELT',diff:'hard',answer:'Script 7: pull from service, tag for biomedical review, document. The fact that prior counts passed does not validate the instrument. The crack is a new finding.'},
  {s:'Your zone report at end of shift shows everything clear. But you forgot to mention that Sterilizer 1 ran slow today.',belt:'YELLOW BELT',diff:'medium',answer:'Equipment anomalies belong in the zone report. Retroactively add it: "Addendum to zone report: Sterilizer 1 ran slow throughout shift -- Lead notified." Alert Lead to the gap in the report.'},
  {s:'You open a package to inspect an instrument and cannot reseal it properly. The seal is compromised.',belt:'YELLOW BELT',diff:'hard',answer:'The packaging integrity is compromised. This item cannot be considered sterile. Document. Notify Lead. Reprocess if appropriate per facility policy.'},
  {s:'A runner arrives and the tray they are requesting has a yellow "Hold" tag on it from the previous shift.',belt:'YELLOW BELT',diff:'hard',answer:'Do not release a tray tagged as Hold. Script 2 routes to Lead. The Lead reviews the hold reason before releasing. Hold tags exist for patient safety reasons.'},
  {s:'Your sterilizer completes its cycle but the printout is blank -- no cycle data printed.',belt:'YELLOW BELT',diff:'hard',answer:'No printout means no verifiable cycle record. This is a potential documentation failure. Do not release the load. Notify Lead. Document: "Sterilizer [number], Load [number] -- no cycle printout. Lead notified. Load held."'},
  {s:'You complete decontam on a complex scope and hand it off to assembly. Assembly sends it back saying it is still dirty.',belt:'YELLOW BELT',diff:'hard',answer:'Accept the scope back without argument. Reprocess. Notify Lead. Document: "Scope reprocessed -- assembly returned [scope name] for redecontamination. Second pass completed. Lead notified." Root cause should be investigated.'},
  {s:'You receive an instrument tray with someone else\'s initials already on the count sheet.',belt:'YELLOW BELT',diff:'medium',answer:'Verify the count yourself. Do not assume the prior tech\'s count is correct. If your count matches, countersign with your initials. If not, Script 4.'},
  {s:'All clear at end of shift. Queue is empty. Equipment is normal. No issues. How long should your Script 11 report take?',belt:'YELLOW BELT',diff:'easy',answer:'Two minutes maximum. Script 11 still covers all required elements even when everything is clear. Do not skip it because it is a good shift.'},
  {s:'You are working decontam and you notice a tech in assembly rushing through counts. They are at Yellow Belt.',belt:'YELLOW BELT',diff:'hard',answer:'At Yellow Belt you are not in a coaching role. You document what you observe and notify Lead. "Observed [tech] rushing count verification in assembly at [time]. Lead notified." You do not correct the tech directly.'},
  {s:'You complete your Yellow Belt knowledge practice test at 76%. What happens next?',belt:'YELLOW BELT',diff:'easy',answer:'76% is below the 80% threshold. You cannot request the real assessment yet. Review the questions you missed and retake the test. Both knowledge and simulation must reach 80% before requesting the real gate assessment.'},
  {s:'You score 82% knowledge and 83% simulation on your Yellow Belt practice tests.',belt:'YELLOW BELT',diff:'easy',answer:'Both tests exceed 80%. You may now use the system to request your real Yellow Belt gate assessment. Your Lead and the SIPS admin will be notified to review and approve or deny your request.'}
]
},

// ────────────────────────────────────────────────────────────
// GREEN BELT  --  100 Knowledge + 100 Simulation
// ────────────────────────────────────────────────────────────
Green: {
knowledge: [
  {q:'What is Universal Protocol and when does it apply?',a:'The final verification before any set leaves assembly for surgical use. Count verified against build sheet, critical instruments verified, sterilization indicator confirmed, documentation complete. Applies to every single set, every time.',diff:'easy'},
  {q:'What is the approved language for Script 13 – Universal Protocol Verification?',a:'"Universal Protocol check – tray [name], count verified [X of X], critical instruments verified [list], sterilization indicator confirmed, documentation complete. Releasing."',diff:'easy'},
  {q:'What is the Green Belt identity statement?',a:'Multi-area proficiency. Universal Protocol. Cross-area verification.',diff:'easy'},
  {q:'Why is Green Belt the mandatory competency level for all SPD staff?',a:'Green Belt means a tech can work every area in the department, execute Universal Protocol on every set, and verify the work of others. This is the minimum standard for a functioning SPD department.',diff:'easy'},
  {q:'What is the coaching standard at Green Belt (Script 15)?',a:'Private, specific, immediate. Approach the tech privately. Describe the specific behavior. State the standard. Show correct method. Have them practice. No public correction.',diff:'easy'},
  {q:'What are the three areas a Green Belt must be able to work independently?',a:'Decontamination, Assembly, Sterilization.',diff:'easy'},
  {q:'What is Script 14 – Tray Deviation?',a:'"Tray deviation – [tray name], deviation: [specific description]. Tray held. Lead notified. Build sheet reviewed. Not releasing until corrected and re-verified."',diff:'easy'},
  {q:'Why does implant processing require a biological indicator before release?',a:'Implants are placed inside a patient\'s body permanently or for extended duration. A chemical indicator only confirms a cycle ran. A biological indicator confirms all microorganisms were actually killed. Implant infections require explant surgery.',diff:'easy'},
  {q:'What is Script 19 – Recall Notification?',a:'"Recall notification received – [item/equipment], [lot/serial number if applicable]. Initiating search and pull protocol. Lead notified. Documentation started."',diff:'easy'},
  {q:'What is a "backlog alert" trigger at Green Belt (Script 18)?',a:'When queue volume reaches a level where cases may be at risk of delay. Not just when you are busy -- when projected completion time exceeds OR need time.',diff:'easy'},
  {q:'What is the cumulative script count at Green Belt?',a:'20 scripts: Scripts 1-2 (White), Scripts 3-11 (Yellow), Scripts 12-20 (Green).',diff:'easy'},
  {q:'How many instruments must a Green Belt identify by sight?',a:'80 total: 30 White Belt + 25 Yellow Belt + 25 Green Belt.',diff:'easy'},
  {q:'What is the coaching approach difference between Green Belt and Blue Belt?',a:'Green Belt coaches White and Yellow Belt staff on script adherence and standard execution. Blue Belt Leads coach at a higher level -- script tone, compound situations, and leadership behavior. Green Belt coaching is technique-focused; Blue Belt coaching is leadership-focused.',diff:'medium'},
  {q:'What makes a tray deviation a stop-work event at Green Belt?',a:'A tray built incorrectly against the build sheet may be missing a critical instrument needed during surgery. A missing instrument during surgery is a retained item risk and a patient safety event.',diff:'medium'},
  {q:'What is Script 12 – Cross-Area Transition?',a:'"Transitioning to [area]. Documenting time of transition, current queue status of originating area, and opening status of receiving area. Lead briefed."',diff:'medium'},
  {q:'Why does "close enough" fail the Green Belt Universal Protocol standard?',a:'Build sheets exist because surgeons have specific instrument preferences built from patient outcome experience. A substituted instrument can fail intraoperatively, cause technique errors, or require the surgeon to stop and wait -- all creating patient risk.',diff:'medium'},
  {q:'What is the complete Universal Protocol verification sequence?',a:'(1) Count verified against build sheet -- number by number. (2) Critical instruments identified and confirmed. (3) Sterilization indicator confirmed changed. (4) Documentation complete. All four must be confirmed before releasing.',diff:'medium'},
  {q:'What does Script 20 – Cross-Area Verification Report include?',a:'"Cross-area verification complete – [areas covered], [X] trays verified, [X] deviations found and corrected, [X] open items for Lead review. All documented."',diff:'medium'},
  {q:'What is the patient safety rationale for Script 15 – coaching privately?',a:'Public correction creates defensive behavior that prevents the tech from learning. Private, specific correction allows the tech to process the feedback and practice correctly. Publicly embarrassing a tech makes the correction about the relationship, not the standard.',diff:'medium'},
  {q:'What is Script 16 – Implant Tray Protocol?',a:'"Implant set – [name/number], vendor notified: [yes/no], implant log updated, biological indicator required: [yes], Lead notified of release timing."',diff:'medium'},
  {q:'When does a Green Belt use Script 17 – Post-Sterilization Contamination?',a:'When visible contamination is found on an instrument that has already been through sterilization. This is a sterilization failure for that item.',diff:'medium'},
  {q:'What is the post-sterilization contamination approved response?',a:'"Post-sterilization contamination – [instrument], [load number]. Instrument removed from service. Load quarantined pending Lead review. Documented."',diff:'medium'},
  {q:'What is Script 18 backlog alert approved language?',a:'"Backlog alert – [area], current queue: [X sets], projected completion: [time], cases at risk: [yes/no – specify if yes]. Notifying Lead for resource assessment."',diff:'medium'},
  {q:'Why is "We\'re getting behind" insufficient for Script 18?',a:'It is not specific. Lead cannot make a resource decision based on "getting behind." They need: how many sets in queue, projected completion time, whether specific cases are at risk.',diff:'medium'},
  {q:'What is the Green Belt Level 2 simulation standard?',a:'20 scenarios including multi-area compound scenarios. Assessor evaluates all 20 scripts plus cross-area decision-making.',diff:'medium'},
  {q:'What is the Green Belt Level 3 observation standard?',a:'Full cross-area shift. Mandatory: Universal Protocol on every tray, all scripts delivered correctly, coaching delivered when applicable, documentation complete at shift end.',diff:'medium'},
  {q:'Explain why "I wiped it off" is a forbidden response to post-sterilization contamination.',a:'Wiping visible contamination off a sterile instrument does not re-sterilize it. The contamination indicates the sterilization process failed for that item. Wiping it creates the appearance of a clean instrument that is not verified sterile.',diff:'medium'},
  {q:'What is the implant log and when must it be updated?',a:'The implant log is the record of every implant processed, including lot number, sterilizer load, biological indicator result, and release authorization. It must be updated before release of any implant set.',diff:'medium'},
  {q:'What is the Green Belt coaching obligation when observing a White Belt tech who is not following Script 1?',a:'Private, immediate correction per Script 15. Approach privately after the interaction. Describe the specific script violation. State the standard. Demonstrate correct delivery. Have them practice.',diff:'medium'},
  {q:'What is cross-contamination and why is it a Green Belt priority?',a:'Cross-contamination occurs when microorganisms transfer from contaminated instruments to clean instruments during the reprocessing process. A Green Belt working across all three areas must maintain strict contamination barriers at every transition.',diff:'medium'},
  {q:'What does "multi-area proficiency" require at Green Belt?',a:'The ability to work decontam, assembly, and sterilization competently and independently, including all 20 scripts, Universal Protocol on every set, and correct stop-work behavior in any area.',diff:'medium'},
  {q:'Why is a recall notification (Script 19) a stop-work event?',a:'A recall means specific items may be defective or non-sterile. Every second of delay increases the probability that a recalled item reaches a patient. Immediate action is required.',diff:'medium'},
  {q:'What makes a Green Belt\'s coaching authority different from a Yellow Belt\'s?',a:'Yellow Belt has no coaching authority. They document and report. Green Belt has coaching authority for White and Yellow Belt staff on standard execution. The scope of coaching is limited to their belt-authorized behaviors.',diff:'hard'},
  {q:'Describe a compound scenario a Green Belt might face in Level 2 simulation.',a:'Simultaneous events: a backlog alert in assembly while an implant set is being processed in sterilization requiring biological indicator confirmation. The Green Belt must handle both the Script 18 backlog notification and the Script 16 implant protocol simultaneously.',diff:'hard'},
  {q:'What is the Green Belt 80% practice threshold system?',a:'When a Green Belt staff member scores 80%+ on both the knowledge test and simulation scenarios, they may request their real Green Belt gate assessment from the system. The request routes to their Lead and SIPS admin for approval.',diff:'easy'},
  {q:'What is a "critical instrument" in the context of Universal Protocol?',a:'An instrument designated on the tray build sheet as essential for the surgical procedure and not substitutable. Absence of a critical instrument stops case setup in OR.',diff:'medium'},
  {q:'What is the Green Belt vocabulary requirement?',a:'10 additional terms: Universal Protocol, Implant log, Biological indicator release, Cross-contamination, Set deviation, Recall protocol, Quarantine, Backlog threshold, Tray build sheet, Coaching authority.',diff:'medium'},
  {q:'Why does Green Belt require cross-area proficiency when Yellow Belt was single-area?',a:'Yellow Belt builds deep single-area competency. Green Belt builds breadth. A department where technicians can only work one area is operationally fragile -- any absence creates a coverage crisis. Green Belt is the minimum for operational flexibility.',diff:'hard'},
  {q:'What is the difference between an instrument being "on the build sheet" and being "critical"?',a:'All instruments are on the build sheet. Critical instruments are specifically designated as essential to the surgical procedure -- their absence stops or delays surgery. Not all instruments are critical, but all must be counted.',diff:'hard'},
  {q:'What does the Green Belt coaching model accomplish that verbal reprimand does not?',a:'The coaching model (private, specific, demonstrate, practice) creates behavioral change. Verbal reprimand creates defensiveness or compliance without understanding. Green Belt coaching builds operators who understand the standard, not just comply with it.',diff:'hard'},
  {q:'When should a Green Belt initiate a recall pull independently?',a:'Immediately upon receipt of Script 19 trigger. They do not wait for the Lead. They initiate the search and pull while simultaneously notifying Lead. Speed matters in a recall.',diff:'hard'},
  {q:'What is the difference between the Level 1, Level 2, and Level 3 assessments at Green Belt?',a:'Level 1: 50-question knowledge test. Level 2: 20 scenarios including compound cross-area events. Level 3: full cross-area shift observation with Universal Protocol verified on every set.',diff:'medium'},
  {q:'Explain why Universal Protocol applies to every set, not just complex or high-risk trays.',a:'A minor procedure tray with a missing instrument still creates a patient risk. Universal Protocol is a discipline, not a risk filter. It applies universally because selective application creates inconsistency and human error.',diff:'hard'},
  {q:'What is the Green Belt relationship to the SBD handoff readiness conditions?',a:'Green Belt is the minimum threshold for departmental competency. A facility where all staff are Green Belt or above is considered minimally competent. The SBD handoff requires more than minimum -- it requires leadership circle completion.',diff:'hard'},
  {q:'What is the patient safety risk of a Green Belt who delivers coaching publicly?',a:'Public correction humiliates the tech. A humiliated tech either shuts down learning or retaliates by becoming more secretive about errors. Both outcomes decrease overall department safety. Private correction is not just polite -- it is clinically safer.',diff:'hard'},
  {q:'Why does Script 12 document the current queue status of both the originating and receiving area?',a:'When a Green Belt transitions areas, two areas change status. Lead needs to know both the area being left (queue status) and the area being entered (opening situation) to manage department flow.',diff:'hard'},
  {q:'Describe what happens if a Green Belt discovers a tray deviation after it has already been released.',a:'Immediately notify Lead. Do not retrieve from OR without Lead authorization. Lead determines whether OR needs to be notified of a potential case hold. Document the retrospective deviation with exact details.',diff:'hard'},
  {q:'What is the Green Belt obligation regarding staff below their belt who are not following Universal Protocol?',a:'Script 15: private coaching immediately. If the tech continues to violate Universal Protocol after coaching, notify Lead. Universal Protocol violations must be escalated because they directly affect patient safety.',diff:'hard'},
  {q:'What is the implant vendor notification requirement in Script 16?',a:'Vendor must be notified before release of implant sets that include vendor-specific items. The implant log entry documents whether vendor was notified. This is a regulatory requirement in many facility types.',diff:'medium'},
  {q:'How does the Green Belt practice test interact with the assessment window?',a:'Practice test scores are saved in the staff member\'s record. When both knowledge and simulation reach 80%, the system activates the "Request Assessment" button. The admin sees the practice scores alongside the request.',diff:'easy'},
  {q:'What is the Green Belt position in the SBD belt architecture?',a:'Green Belt is the crossover from operator to multi-area professional. It is the minimum required for the department to function. It is also the entry point for Position School (QA School is available at Green Belt).',diff:'medium'}
],

simulation: [
  {s:'You are completing assembly on a cardiac tray and reach the Universal Protocol check.',belt:'GREEN BELT',diff:'easy',answer:'Script 13: "Universal Protocol check – [tray name], count verified [X of X], critical instruments verified [list], sterilization indicator confirmed, documentation complete. Releasing." Every element. No shortcuts.'},
  {s:'You observe a White Belt tech answering a call and saying "I think it\'ll be about 20 minutes."',belt:'GREEN BELT',diff:'easy',answer:'Script 15 after the call: approach privately. "I noticed you gave a timeline on that call. The standard is Script 1 then route to Lead -- we don\'t make time commitments. Let me show you the correct approach." Demonstrate. Practice together.'},
  {s:'A recall notice comes in for a specific lot number of laparoscopic graspers.',belt:'GREEN BELT',diff:'easy',answer:'Script 19: "Recall notification received – laparoscopic graspers, lot [number]. Initiating search and pull protocol. Lead notified. Documentation started." Immediate action. Begin searching for affected lot.'},
  {s:'Assembly is behind. Your queue shows 18 sets with OR cases starting in 2 hours.',belt:'GREEN BELT',diff:'medium',answer:'Script 18: "Backlog alert – assembly, current queue: 18 sets, projected completion: [calculated time], cases at risk: [yes -- specify which cases]. Notifying Lead for resource assessment."'},
  {s:'You are covering assembly and discover a tray built with the wrong instrument in position 7.',belt:'GREEN BELT',diff:'easy',answer:'Script 14: "Tray deviation – [tray name], deviation: wrong instrument in position 7, build sheet indicates [correct], tray contains [incorrect]. Tray held. Lead notified. Not releasing until corrected and re-verified."'},
  {s:'You transition from decontam to assembly mid-shift.',belt:'GREEN BELT',diff:'easy',answer:'Script 12: "Transitioning to assembly. Current decontam queue: [X sets remaining]. Assembly opening status: [X sets in queue]. Lead briefed." Document the transition.'},
  {s:'An implant set is ready for release but the biological indicator has not completed incubation.',belt:'GREEN BELT',diff:'medium',answer:'Script 16: biological indicator is required. Do not release. "Implant set [name] -- biological indicator incubation incomplete. Not releasing until indicator confirmed. Lead notified of release timing." Hold the set.'},
  {s:'You find visible contamination on a scope that came out of sterilization.',belt:'GREEN BELT',diff:'medium',answer:'Script 17: "Post-sterilization contamination – [scope name], Load [number]. Instrument removed from service. Load quarantined pending Lead review. Documented." Do not wipe it off. Pull it.'},
  {s:'A Yellow Belt tech tells you they skipped the handoff script because they were too busy.',belt:'GREEN BELT',diff:'medium',answer:'Script 15: private coaching. "I understand it was busy. The handoff script is most important during busy periods because that\'s when information gets lost. Let\'s walk through it now." Practice Script 3 with them.'},
  {s:'You complete Universal Protocol on a tray and find one instrument whose sterilization indicator did not change.',belt:'GREEN BELT',diff:'hard',answer:'Universal Protocol check fails for this tray. Do not release. Script 14 logic: tray deviation. Notify Lead. "One indicator not confirmed on [tray name]. Tray held pending Lead review." Document.'},
  {s:'OR calls asking for a specific set. You are covering assembly and you know the set is in sterilization.',belt:'GREEN BELT',diff:'medium',answer:'Script 18 logic applies: this is OR-facing communication. You do not have Blue Belt Lead authority. Route to Lead: "Priority request from OR -- routing to Lead immediately." Document. Do not tell OR where the set is.'},
  {s:'A recall notice comes in and you identify that a recalled item went out in two loads in the last 48 hours.',belt:'GREEN BELT',diff:'hard',answer:'Script 19 applies to both loads. Notify Lead immediately. Document both loads. The Lead determines OR notification and case hold requirements. Begin pulling recalled items from distribution.'},
  {s:'You complete a cross-area verification shift covering all three areas.',belt:'GREEN BELT',diff:'medium',answer:'Script 20: "Cross-area verification complete – decontam, assembly, sterilization. [X] trays verified, [X] deviations found and corrected, [X] open items for Lead review. All documented."'},
  {s:'You are about to do Universal Protocol on a tray when you realize you have not looked at the build sheet.',belt:'GREEN BELT',diff:'easy',answer:'Get the build sheet. Universal Protocol requires count verified against the build sheet. You cannot perform Universal Protocol without the build sheet. Locate it before proceeding.'},
  {s:'You discover that a tray you released yesterday is now being flagged as having a wrong instrument by OR.',belt:'GREEN BELT',diff:'hard',answer:'Do not argue. Accept the report. Notify Lead immediately. Document: "OR reported tray deviation on [tray name] released [date]. Lead notified at [time]." Investigation begins. Your Universal Protocol documentation is evidence.'},
  {s:'You are in assembly and notice a Yellow Belt in decontam rushing through their handoff report on the phone.',belt:'GREEN BELT',diff:'medium',answer:'At Green Belt you have coaching authority. After they complete the call: private coaching per Script 15. Specific: the handoff script elements they rushed through. Standard: Script 3 format. Demonstrate. Practice.'},
  {s:'The implant log for a set processed yesterday cannot be located.',belt:'GREEN BELT',diff:'hard',answer:'This is a documentation gap. Notify Lead. "Implant log for [set name] processed [date] cannot be located. Lead notified." Do not reconstruct the log from memory without Lead authorization. Lead determines next steps.'},
  {s:'You are performing Universal Protocol and the build sheet shows 24 instruments but you only have 23.',belt:'GREEN BELT',diff:'medium',answer:'Universal Protocol fails. Script 14: tray deviation + Script 4 logic. "Tray deviation and count discrepancy -- [tray name], build sheet shows 24, count is 23. [Missing instrument name if known]. Tray held. Lead notified."'},
  {s:'An OR runner arrives and says the case starts in 10 minutes and they need the set now.',belt:'GREEN BELT',diff:'hard',answer:'If the set has passed Universal Protocol and is cleared for release, route to Lead for authorization. If Universal Protocol has not been completed, you do not release it regardless of the 10-minute urgency. Universal Protocol is not skippable.'},
  {s:'You are the only Green Belt on shift and you notice a pattern of count discrepancies in the last 3 days.',belt:'GREEN BELT',diff:'hard',answer:'Script 18 logic: this is beyond a single event -- it is a pattern that requires Lead attention. Document the pattern. Notify Lead: "Pattern of count discrepancies in the last 3 days -- [specific details]. Lead review needed." This is a backlog of quality alerts, not just operational backlog.'},
  {s:'You hear a White Belt tech in assembly say "I can figure this out myself" when encountering an unfamiliar instrument.',belt:'GREEN BELT',diff:'hard',answer:'This is a potential safety issue. Intervene: approach calmly. "Let me help with that -- what instrument is it?" Guide them to the correct identification method or involve Lead. Then Script 15 coaching: "At White Belt, unfamiliar instruments go to Lead, not to independent investigation."'},
  {s:'You are covering decontam and sterilization simultaneously due to staffing shortage.',belt:'GREEN BELT',diff:'hard',answer:'Immediately notify Lead via Script 18 logic: backlog alert with context: "Covering decontam and sterilization simultaneously -- resource gap. Cases may be at risk if volume increases. Lead assessment needed." Do not silently absorb a staffing gap.'},
  {s:'A vendor arrives with an implant set for an emergency case. No biological indicator has been run on the set.',belt:'GREEN BELT',diff:'hard',answer:'Script 16: biological indicator required. "Implant set [name] -- biological indicator required before release. Not releasing without it. Lead notified." The emergency does not waive the biological indicator requirement for implants.'},
  {s:'You complete your Universal Protocol check on a tray and then a colleague asks you to verify one more tray quickly.',belt:'GREEN BELT',diff:'medium',answer:'Yes, but perform a complete Universal Protocol check on the second tray as well. "Quickly" does not modify Universal Protocol. All four elements. Every set.'},
  {s:'You notice a Yellow Belt documenting "seems fine" in the log after a count check.',belt:'GREEN BELT',diff:'medium',answer:'Script 15 coaching: private, specific. "The documentation standard requires factual language, not interpretive language. \'Count verified: 24 of 24\' is correct. \'Seems fine\' is not auditable. Let me show you the format."'},
  // 26-100
  {s:'A tray build sheet has been updated but the old version is in circulation. You discover this during Universal Protocol.',belt:'GREEN BELT',diff:'hard',answer:'Universal Protocol fails -- you cannot verify against an outdated sheet. Hold the tray. Notify Lead. Document: "Outdated build sheet in circulation for [tray]. Tray held pending correct build sheet. Lead notified."'},
  {s:'You are about to run Universal Protocol and realize you have not checked critical instruments specifically.',belt:'GREEN BELT',diff:'medium',answer:'Stop. Do not mark Universal Protocol complete until you have verified all four elements including critical instruments. "Critical instruments verified [list]" must be deliverable before you can say "Releasing."'},
  {s:'A runner arrives for an implant set. The biological indicator is negative. But the implant log is not yet complete.',belt:'GREEN BELT',diff:'hard',answer:'Script 16: do not release until implant log is complete. The biological indicator clearance alone is not sufficient. "Implant set [name] -- biological indicator confirmed negative. Implant log not complete. Not releasing until log is updated. Lead notified of release timing."'},
  {s:'OR calls during your Universal Protocol check.',belt:'GREEN BELT',diff:'medium',answer:'Do not stop Universal Protocol mid-check to answer the call. Complete the current tray\'s Universal Protocol first. If the call continues ringing, signal a colleague. If alone: complete the check, then deliver Script 9 logic to the call or route to Lead.'},
  {s:'You find two instruments in assembly that look identical but have different model numbers on the catalog.',belt:'GREEN BELT',diff:'hard',answer:'Do not assume they are interchangeable. Flag for build sheet verification. "Instrument identification question -- two items appear identical but have different catalog numbers. Lead notified. Not proceeding with assembly until confirmed." Document.'},
  {s:'You score 81% on the Green Belt knowledge test and 78% on simulation.',belt:'GREEN BELT',diff:'easy',answer:'The simulation score of 78% is below the 80% threshold. You cannot request the real assessment yet. Retake the simulation test. Both tests must reach 80% independently.'},
  {s:'You score 84% knowledge and 81% simulation on your Green Belt practice tests.',belt:'GREEN BELT',diff:'easy',answer:'Both exceed 80%. You may now request your real Green Belt gate assessment through the system. Your Lead and SIPS admin will see your practice scores and review your request.'},
  {s:'You are coaching a Yellow Belt on Script 4 and they push back: "I know this already."',belt:'GREEN BELT',diff:'hard',answer:'Script 15 remains private and specific. "I understand. Let me hear you deliver it for this scenario and then we can confirm." If they deliver it correctly, acknowledge it. If not, correct specifically. Their confidence does not waive the coaching obligation.'},
  {s:'A tray passes Universal Protocol and is released. 30 minutes later OR calls to say the count in OR is one short.',belt:'GREEN BELT',diff:'hard',answer:'Do not argue. "I\'ll alert the Lead immediately. Our count documentation will be reviewed." Notify Lead urgently. Pull the Universal Protocol documentation. The Lead handles OR communication. Document: "OR count discrepancy report received for [tray]. Lead notified at [time]."'},
  {s:'You complete a cross-area shift and there are 3 open items for Lead review.',belt:'GREEN BELT',diff:'medium',answer:'Script 20 includes them: "Cross-area verification complete – [areas]. [X] trays verified, [X] deviations corrected, 3 open items for Lead review: [list specifically]. All documented."'},
  {s:'A White Belt comes to you and says they answered a call and gave wrong information. They are scared.',belt:'GREEN BELT',diff:'hard',answer:'Script 15 approach. Calm them first. Then: "Tell me exactly what happened." Listen. Then: "We need to notify Lead immediately." Document the incident together. Your coaching role here is both corrective and supportive.'},
  {s:'You discover that an instrument in a tray has a manufacturer recall that was issued 6 months ago.',belt:'GREEN BELT',diff:'hard',answer:'Script 19 with retrospective implication. Notify Lead immediately. Pull all sets containing that instrument model. Document: "Retrospective recall discovered for [instrument], recall issued [date]. All affected sets pulled pending Lead review."'},
  {s:'You are in assembly during a high-volume period and feel pressure to skip Universal Protocol to keep up.',belt:'GREEN BELT',diff:'hard',answer:'Do not skip Universal Protocol under any circumstance. If volume exceeds your ability to perform complete Universal Protocol on every set, Script 18: backlog alert. Lead must be notified to manage resources.'},
  {s:'A colleague says Universal Protocol is "just a formality" for simple trays.',belt:'GREEN BELT',diff:'hard',answer:'This is incorrect. Correct them -- privately if possible, accurately regardless: "Universal Protocol applies to every set. \'Simple\' is not a Universal Protocol modifier. Let me show you the standard."'},
  {s:'You have two trays that need Universal Protocol simultaneously.',belt:'GREEN BELT',diff:'medium',answer:'Do one at a time. Universal Protocol cannot be split or shortcut. Complete tray 1 fully, release or hold it, then complete tray 2 fully.'},
  {s:'A Yellow Belt asks for your help on an assembly question you are not 100% certain about.',belt:'GREEN BELT',diff:'medium',answer:'Do not guess. "I want to make sure you get the right answer. Let me get the Lead." Route to Lead. Green Belt coaching does not extend to improvising answers about assembly procedures you are uncertain about.'},
  {s:'You complete Universal Protocol but cannot find the sterilization indicator inside the package.',belt:'GREEN BELT',diff:'hard',answer:'Universal Protocol fails without confirmed indicator. Hold the tray. Notify Lead. "Universal Protocol check -- indicator not located on [tray name]. Tray held. Lead notified." Do not release.'},
  {s:'Three sets are in your queue at end of shift and your relief has not arrived.',belt:'GREEN BELT',diff:'hard',answer:'Do not rush Universal Protocol because you want to leave. Notify Lead of the situation. "Three sets remaining in queue, relief has not arrived. Lead notified." Stay until Lead resolves the coverage gap.'},
  {s:'You are coaching a Yellow Belt and they perform the correct script. You realize you were wrong about what the standard was.',belt:'GREEN BELT',diff:'hard',answer:'Acknowledge it honestly: "Actually you did that correctly -- I was mistaken about the standard. Thank you for the delivery." Document nothing negative about the coaching if the tech was correct. Correct your own understanding.'},
  {s:'An implant set passes biological indicator but the vendor was not notified before processing as required.',belt:'GREEN BELT',diff:'hard',answer:'The vendor notification requirement is separate from the biological indicator. Flag this to Lead: "Implant set [name] -- biological indicator negative, but vendor was not notified before processing. Lead notified." Lead determines whether vendor notification is still required retroactively.'}
]
},

// ────────────────────────────────────────────────────────────
// BLUE BELT  --  100 Knowledge + 100 Simulation
// ────────────────────────────────────────────────────────────
Blue: {
knowledge: [
  {q:'What is the Blue Belt identity statement?',a:'Leadership entry. Lead identity. Owns all Lead-side communication.',diff:'easy'},
  {q:'Why must every Blue Belt outbound communication begin with Lead identification?',a:'Lead identification establishes authority and accountability from the first word. It is not optional. OR, surgeons, and administration need to know immediately they are speaking with someone who has decision-making authority.',diff:'easy'},
  {q:'What is the approved opening for Script 21 – Lead Identification?',a:'"This is [name], SPD Lead." Always. Before any content. Tone: calm, direct, authoritative. Never apologetic.',diff:'easy'},
  {q:'What is the difference between proactive and reactive communication at Blue Belt?',a:'Proactive: SPD Lead contacts OR before OR calls to provide status. Reactive: OR calls because they have not received information. Proactive allows OR to adjust. Reactive is damage control.',diff:'easy'},
  {q:'What is the approved language for Script 24 – STAT Case Activation?',a:'"STAT case received – OR [number], case: [type], ETA requested: [time]. Initiating STAT protocol. Lead confirming instrument availability now. Callback in [X] minutes with status." No time promises until availability is confirmed.',diff:'easy'},
  {q:'What is the approved de-escalation response for Script 28 – OR Complaint?',a:'"I hear you. Tell me exactly what you need." Listen completely. Then: "Here is what I can confirm right now: [specific]. Here is what I will do next: [specific action with timeframe]." No defense, no explanation, deliver action.',diff:'easy'},
  {q:'Why is tone an explicit Blue Belt assessment criterion?',a:'Blue Belt communicates with OR, surgeons, and administration in high-pressure situations. A correct script in an apologetic or defensive tone undermines Lead authority and damages the SPD-OR relationship. Words must be right AND tone must be authoritative.',diff:'easy'},
  {q:'How many scripts does Blue Belt add to the cumulative total?',a:'43 new scripts (Scripts 21-63), bringing the cumulative total to 63 scripts.',diff:'easy'},
  {q:'What is the Script 29 vendor communication standard?',a:'"Our vendor contact protocol requires Lead authorization for all vendor activity in this department. I\'ll need to verify your credentials and contact our Supervisor. Please wait here." No access until cleared.',diff:'easy'},
  {q:'What is Script 30 – Lead-Level Shift Handoff format?',a:'"[Incoming Lead name], shift handoff. Department status: [current queue, delays, open issues]. Equipment status: [holds or flags]. Personnel notes: [coaching in progress, attendance]. Cases at risk: [none/specify]. All documented."',diff:'easy'},
  {q:'What is Script 22 – Case Cart Status Proactive?',a:'"This is [name], SPD Lead. OR [number], your case cart for [case/time] – status: [on time / delayed by X minutes]. Reason: [specific]. No action needed / Action needed: [specify]."',diff:'medium'},
  {q:'What is Script 23 – Case Cart Status Delayed?',a:'"This is [name], SPD Lead. OR [number], case cart for [case] – delayed. Current ETA: [time]. Reason: [specific]. Contingency: [specific plan]."',diff:'medium'},
  {q:'What is Script 25 – Missing Instrument Escalation?',a:'"Missing instrument – [name], case: [OR/case], searched: yes, [locations checked]. This requires Lead-to-Lead escalation. I am contacting OR Lead now with confirmed status and alternatives." Provide alternatives before OR calls you.',diff:'medium'},
  {q:'What is Script 26 – Surgeon Preference Card Discrepancy?',a:'"Surgeon preference discrepancy for [surgeon name], case [number]. Preference card indicates [X], cart built with [Y]. Contacting OR charge to confirm surgeon preference and document correction."',diff:'medium'},
  {q:'What is Script 27 – Load Recall Notification (Lead Level)?',a:'"This is [name], SPD Lead. Load recall – Load [number], sterilizer [number], [date/time]. Items affected include [list]. Any instruments from this load currently in use must be flagged. Case holds may be required. Supervisor notified."',diff:'medium'},
  {q:'What is the patient safety risk of a STAT commitment made without confirmed instrument availability?',a:'If instruments are not available and the Lead has committed to a timeline, OR will proceed with preparation that assumes availability. When the instruments are not ready, OR has been given false information during an emergency.',diff:'medium'},
  {q:'What is Script 27\'s "Case holds may be required" element and why is it non-negotiable?',a:'If a load recall affects instruments currently in use or staged for upcoming cases, those cases may need to hold. Omitting this element means OR does not know a case hold may be coming.',diff:'medium'},
  {q:'What is the Blue Belt Level 1 knowledge test standard?',a:'50 questions covering all 63 scripts, Lead identity, proactive/reactive communication, STAT protocols, de-escalation, and 100-instrument identification.',diff:'medium'},
  {q:'What is the Blue Belt Level 2 simulation standard?',a:'25 scenarios including compound events (simultaneous STAT + missing instrument + OR complaint). Tone is an explicit criterion. Neutral tone failures trigger mandatory re-observation.',diff:'medium'},
  {q:'What is the Blue Belt Level 3 observation standard?',a:'Full Lead shift. 12 mandatory leadership behaviors including: Lead ID on every outbound call, proactive cart communication before OR calls, de-escalation on any complaint, complete Lead handoff.',diff:'medium'},
  {q:'What is a "neutral tone" failure and what does it trigger?',a:'Delivering a correct script with a defensive, apologetic, or uncertain tone. At Blue Belt, tone is a graded assessment criterion. A neutral tone failure in Level 2 simulation triggers mandatory re-observation.',diff:'medium'},
  {q:'Explain the patient safety rationale for proactive case cart communication.',a:'Proactive communication gives OR the maximum time window to adjust case sequencing, manage surgeon expectations, and prepare contingencies. A reactive call 5 minutes before a case starts creates a crisis. A proactive call 30 minutes before creates an opportunity.',diff:'medium'},
  {q:'What does "alternatives before OR calls you" mean in Script 25?',a:'A Blue Belt Lead does not call OR to say an instrument is missing. They call OR to say an instrument is missing AND here is what I can do instead. The Lead handles the problem before delivering the problem.',diff:'hard'},
  {q:'Why is "We\'re doing our best" a forbidden phrase for OR de-escalation?',a:'It is a justification that shifts focus from OR\'s need to SPD\'s effort. OR does not need to hear about SPD\'s effort. OR needs to hear a specific action with a specific timeframe. "We\'re doing our best" delivers neither.',diff:'medium'},
  {q:'What is the Blue Belt cumulative instrument mastery requirement?',a:'100 instruments. All four instrument lists: 30 White Belt + 25 Yellow Belt + 25 Green Belt + 20 Blue Belt = 100. Blue Belt adds Lead-level decision notes for each instrument.',diff:'easy'},
  {q:'What is a "compound emergency scenario" at Blue Belt simulation?',a:'A scenario where multiple simultaneous emergency events require multiple scripts: for example, a STAT case activation occurring simultaneously with a missing instrument and an OR complaint.',diff:'medium'},
  {q:'What is the patient safety rationale for Script 26 – Preference Card Discrepancy?',a:'Preference cards exist because surgeons have specific instruments that fit their technique. An unapproved substitution can cause technique errors mid-surgery, intraoperative delays, or surgeon frustration that affects patient outcome.',diff:'medium'},
  {q:'What does "Lead-to-Lead escalation" mean in Script 25?',a:'When a missing instrument cannot be found within SPD resources, it requires a direct communication channel between the SPD Lead and the OR Charge. This bypasses the standard call queue and creates direct accountability.',diff:'medium'},
  {q:'What is the 80% practice threshold requirement at Blue Belt?',a:'Score 80%+ on both the Blue Belt knowledge test and simulation scenarios in SIPS Intelligence. Both must be met before the assessment request is available.',diff:'easy'},
  {q:'What is the difference between Script 28 (OR complaint de-escalation) and Script 24 (STAT)?',a:'Script 24 is operational: receiving and activating an emergent case request. Script 28 is relational: managing OR frustration and re-establishing the working relationship. Both are critical, but they serve different functions.',diff:'hard'},
  {q:'Explain why Script 27 includes "Supervisor notified" as a required element.',a:'A load recall at Lead level has institutional impact beyond the department. Administration and Supervisors must know about any event that may affect multiple cases. Omitting this element means leadership does not know about an active patient safety event.',diff:'hard'},
  {q:'What is the proactive vs reactive framework for all 43 Blue Belt scripts?',a:'For every script: before the issue becomes an OR problem, the Lead communicates. Proactive = SPD initiates. Reactive = OR initiates. Blue Belt discipline means SPD leads the communication on every operational issue within their authority.',diff:'hard'},
  {q:'What does "Lead identity" mean at Blue Belt beyond the opening phrase?',a:'It is an identity shift. Blue Belt does not think of themselves as an operator who leads. They think of themselves as the communication hub of the department. Every word they say represents SPD to OR, to surgeons, to administration. Their language IS SPD\'s standard.',diff:'hard'},
  {q:'Why does the Blue Belt assessment include a compound emergency scenario?',a:'Single-event scripts can be memorized. A compound scenario reveals whether the candidate understands the priority hierarchy when multiple events occur simultaneously -- and whether their scripts hold up under real operating pressure.',diff:'hard'},
  {q:'Describe the patient safety impact of a Blue Belt Lead who delivers Script 28 with a defensive tone.',a:'The de-escalation fails. OR remains frustrated. The working relationship between SPD and OR degrades. OR stops trusting SPD communication. Over time, this distrust creates informal workarounds by OR that bypass SPD protocols -- which creates direct patient safety risks.',diff:'hard'},
  {q:'What makes a Blue Belt tone failure worse than a script word failure?',a:'A word failure can be corrected in the moment. A tone failure communicates the Lead\'s internal state -- apologetic, defensive, or uncertain -- and that communication is received by OR even if the words are technically correct. Tone shapes how the message is received.',diff:'hard'},
  {q:'What is the Blue Belt authority boundary in the SBD communication system?',a:'Blue Belt Leads own all Lead-side communication: OR interface, case cart status, STAT activation, load recall notification, vendor management, de-escalation, and shift handoff. They do not own institutional escalation (Brown Belt), RCA (Brown Belt), or executive communication (Brown Belt).',diff:'hard'},
  {q:'When does a Blue Belt Lead escalate to Brown Belt or Supervisor level?',a:'When the situation requires institutional authority: RCA initiation, executive notification, cross-department escalation, performance documentation, or any event beyond the Lead\'s operational authority.',diff:'hard'},
  {q:'What is the relationship between Script 22 proactive communication and OR trust?',a:'Every proactive call -- even one delivering bad news -- builds OR trust because it demonstrates that SPD controls information about its own operations. An OR that has to call to find out what is happening has learned not to trust SPD\'s communication.',diff:'hard'},
  {q:'Why does Lead identification appear on every outbound call and not just the first?',a:'Because every outbound communication establishes authority. OR staff change. Multiple people may call from the same suite. The Lead ID is not a formality -- it is a real-time declaration of who is responsible for the information being shared.',diff:'hard'},
  {q:'What does "I hear you" accomplish in Script 28 that "I understand" does not?',a:'"I understand" can be delivered dismissively -- it signals cognitive receipt but not empathetic receipt. "I hear you" is language that acknowledges the emotional state of the caller before moving to problem-solving. In de-escalation research, acknowledgment precedes resolution.',diff:'hard'},
  {q:'What is the Blue Belt position in the SBD leadership architecture?',a:'Blue Belt is the entry point to the leadership tier. It transitions a top-performing operator into a communication leader. The skills built at Blue Belt (Lead communication, de-escalation, compound event management) are the operational foundation for Supervisor School.',diff:'hard'}
],

simulation: [
  {s:'You are SPD Lead. You know OR 3\'s case cart will be 15 minutes late. OR has not called yet.',belt:'BLUE BELT',diff:'easy',answer:'Script 22 proactive: "This is [name], SPD Lead. OR 3, your case cart for [case] – delayed 15 minutes. Current ETA: [time]. Reason: [specific]. No action needed / Action needed: [specify]." Call them before they call you.'},
  {s:'STAT call: OR 2 has an emergency trauma case and needs a laparotomy set immediately.',belt:'BLUE BELT',diff:'easy',answer:'Script 24: "STAT case received – OR 2, trauma laparotomy, ETA requested. Initiating STAT protocol. Confirming instrument availability now. Callback in [X] minutes with status." Hang up. Confirm availability. Call back with confirmed ETA.'},
  {s:'OR charge calls and says "Your department is the reason we are running behind. This is unacceptable."',belt:'BLUE BELT',diff:'medium',answer:'Script 28: "I hear you. Tell me exactly what you need." Listen completely. Then: "Here is what I can confirm right now: [status]. Here is what I will do next: [specific action with timeframe]." No defense. No explanation. Deliver action.'},
  {s:'A vendor rep arrives unannounced and says they need to inspect their loaner orthopedic set.',belt:'BLUE BELT',diff:'easy',answer:'Script 29: "Our vendor contact protocol requires Lead authorization for all vendor activity in this department. I\'ll need to verify your credentials and contact our Supervisor. Please wait here." No access until Supervisor clears.'},
  {s:'Three case carts are in queue, one implant set is pending BI release, an instrument is missing for OR 5, and OR charge just called to complain.',belt:'BLUE BELT',diff:'hard',answer:'Compound event. Priority order: 1) Script 25 (missing instrument -- direct patient risk). 2) Script 16/implant (BI status). 3) Script 28 (de-escalate OR charge with what you know). 4) Script 22 (case cart status updates). Each script delivered with Lead ID opening.'},
  {s:'Load 4 from sterilizer 2 ran this morning and you have just identified it needs to be recalled.',belt:'BLUE BELT',diff:'medium',answer:'Script 27: "This is [name], SPD Lead. Load recall – Load 4, Sterilizer 2, [date/time]. Items affected include [list]. Any instruments from this load currently in use must be flagged. Case holds may be required. Supervisor notified." Execute immediately.'},
  {s:'The surgeon\'s preference card shows a specific retractor but the case cart was built with a different model.',belt:'BLUE BELT',diff:'medium',answer:'Script 26: "Surgeon preference discrepancy for [surgeon name], case [number]. Preference card indicates [X], cart built with [Y]. Contacting OR charge to confirm surgeon preference and document correction." Correct before the case.'},
  {s:'You are conducting Lead handoff at end of your shift. Two case carts are pending, one instrument is missing for tomorrow\'s first case, and you had a verbal exchange with OR charge that you resolved.',belt:'BLUE BELT',diff:'medium',answer:'Script 30: "[Incoming Lead], handoff. Department status: 2 carts pending assembly [details]. Open item: [instrument] missing for [case] tomorrow -- search in progress. Personnel notes: OR charge interaction today: [factual description, resolution]. Equipment: normal. All documented."'},
  {s:'A missing instrument cannot be located. OR case is in 45 minutes.',belt:'BLUE BELT',diff:'hard',answer:'Script 25: "Missing instrument – [name], case: OR [number], searched [all locations]. Lead-to-Lead escalation required. I am contacting OR Lead now with status and alternatives." Call OR Lead directly. Present confirmed status AND specific alternatives before calling.'},
  {s:'OR calls and says the surgeon is already scrubbed and asking where their set is.',belt:'BLUE BELT',diff:'hard',answer:'Script 21 (Lead ID) opens all calls. Then urgency determination: if set is available, Script 22 with exact ETA. If not ready, Script 23 with reason and contingency. Under no circumstances: "We\'ll get it there as fast as we can."'},
  {s:'You receive a STAT call and immediately commit to a 10-minute turnaround before checking availability.',belt:'BLUE BELT',diff:'hard',answer:'This is a script violation. Script 24 requires: "Confirming instrument availability now. Callback in [X] minutes with status." The 10-minute commitment was made without confirmed availability. Immediately call back: "I need to retract that timeline -- I am confirming availability now and will call you back with an accurate ETA."'},
  {s:'OR charge nurse calls and says "I need you to personally guarantee this cart will be there in 20 minutes."',belt:'BLUE BELT',diff:'hard',answer:'Script 22/23 logic: "This is [name], SPD Lead. I can confirm [current status]. Our current ETA is [time based on confirmed status]. I will call you if that changes." Do not "guarantee." Guarantee language creates personal liability and is not within Lead communication protocol.'},
  {s:'You are in the middle of de-escalating OR charge when a STAT call comes on the other line.',belt:'BLUE BELT',diff:'hard',answer:'Compound event. "I need to put you on hold for one moment -- there is an emergency incoming call. I will be right back." Handle Script 24. Return to Script 28. Resume de-escalation.'},
  {s:'A vendor arrives with the correct credentials and clearance from Supervisor. You are executing Script 29.',belt:'BLUE BELT',diff:'medium',answer:'Credentials verified, Supervisor cleared them. "Welcome. I\'ll escort you to the relevant area. Please remain with me at all times." Document the visit: vendor name, time in, purpose, Supervisor who cleared, time out.'},
  {s:'Surgeon calls SPD directly and is aggressive about a preference card that was not followed.',belt:'BLUE BELT',diff:'hard',answer:'Script 21 (Lead ID) opens the call. Script 28 for de-escalation: "I hear you. Tell me exactly what was missing." Listen completely. Script 26 investigation begins. "Here is what I can confirm: [status]. Here is what I will do next: [investigate preference card, correct, confirm before next case]."'},
  {s:'You give a proactive call to OR about a delay and the charge nurse asks "Can you just make it faster?"',belt:'BLUE BELT',diff:'hard',answer:'"I understand the urgency. Our current ETA is [time] based on [sterilization cycle / assembly queue]. If that changes I will call you immediately." Do not commit to "making it faster" without knowing whether you can. Proactive communication does not mean making unverifiable promises.'},
  {s:'A load recall affects instruments that OR is currently using in an active surgery.',belt:'BLUE BELT',diff:'hard',answer:'Script 27 with urgency: "This is [name], SPD Lead. Load recall – items may be currently in use in OR [number]. Case hold may be required. I am notifying Supervisor immediately." Supervisor decision on interrupting active case. Document immediately.'},
  {s:'You deliver Script 28 de-escalation and OR charge says "That\'s not good enough."',belt:'BLUE BELT',diff:'hard',answer:'"I understand. What specifically would you need to feel this is resolved?" Listen again. Deliver Script 28 again with the specific additional action they identified. If they escalate beyond Lead authority, notify Supervisor.'},
  {s:'OR calls 4 times in one hour asking for updates on the same case cart.',belt:'BLUE BELT',diff:'hard',answer:'Script 22 proactive after the first call: set a callback schedule. "I will call you every 15 minutes with a status update until this cart is confirmed ready." Follow through on every 15 minutes. Prevent the repeat calls by providing a communication schedule.'},
  {s:'You are alone in SPD as Lead. The phone rings, a runner arrives at the same time, and you receive a STAT page simultaneously.',belt:'BLUE BELT',diff:'hard',answer:'STAT takes priority. Acknowledge the STAT. Signal the runner to wait. Answer the phone with Script 21 and tell caller you have a STAT emergency and will call back in 2 minutes. Execute Script 24. Return to runner (Script 29/2 logic). Callback. Document all three events with exact times.'},
  {s:'You are handing off to the next Lead and you realize your case cart documentation has gaps.',belt:'BLUE BELT',diff:'hard',answer:'Do not hand off with known documentation gaps. Complete or flag the gaps before handoff. If you cannot complete them before the next Lead arrives, hand off verbally with specific flags: "Documentation for [case] is incomplete -- here is what I know: [specifics]. Please document the resolution."'},
  {s:'A staff member below you is not following Script 11 at end of shift.',belt:'BLUE BELT',diff:'medium',answer:'Script 15 coaching applies (Green Belt and above can coach). Private, specific, immediate: "The zone report has to include [specific missing elements]. Let me show you what a complete report looks like." But also document the coaching in Lead notes.'},
  {s:'You deliver a proactive call about a delay and OR says "You should have called earlier."',belt:'BLUE BELT',diff:'hard',answer:'Do not defend. "You\'re right. Here is where we are right now: [specific status]. Here is the action: [specific]. I will call you at [time] with confirmation." Acknowledge without argument. Deliver action.'},
  {s:'A load recall is in progress and a runner arrives for a set that may be from the recalled load.',belt:'BLUE BELT',diff:'hard',answer:'Stop the runner. Script 2 logic: "I\'ll get the Lead" -- but you ARE the Lead. Do not release the set until the load recall check is complete for that specific set. Script 27 is already in motion. This runner\'s request is on hold until the set is cleared.'},
  {s:'You score 82% knowledge and 79% simulation on Blue Belt practice tests.',belt:'BLUE BELT',diff:'easy',answer:'The simulation score of 79% is below the 80% threshold. Retake the simulation test. Both must independently reach 80% to unlock the real assessment request.'},
  {s:'You score 88% knowledge and 83% simulation on Blue Belt practice tests.',belt:'BLUE BELT',diff:'easy',answer:'Both exceed 80%. The system will activate the assessment request option. Your Lead and SIPS admin will see your practice scores. Request your gate assessment.'},
  // 26-100
  {s:'An OR nurse asks you directly "Are you the Lead?" before asking her question.',belt:'BLUE BELT',diff:'easy',answer:'"Yes, this is [name], SPD Lead." Confirm. Then listen for the question and respond with the appropriate script.'},
  {s:'You have to call a surgeon directly about a missing implant. You have never called a surgeon directly.',belt:'BLUE BELT',diff:'hard',answer:'Script 21 Lead ID. Script 25 missing instrument framework: "This is [name], SPD Lead. Regarding [case]: [implant name] is not confirmed available. We are conducting an immediate search. Your options are [specific alternatives]. Please confirm your preference and I will execute immediately."'},
  {s:'OR sends a complaint through email to your Supervisor about a case cart delay that happened on your shift.',belt:'BLUE BELT',diff:'hard',answer:'Do not wait for the Supervisor to call you. Pull your documentation. Prepare a factual timeline. Notify Supervisor proactively: "I am aware of the OR complaint about [case]. Here is my documentation of what occurred." Lead communication is proactive in all directions.'},
  {s:'You are on a call with OR and they ask for your Lead\'s contact information.',belt:'BLUE BELT',diff:'medium',answer:'You are the Lead. Clarify: "I am the Lead for this shift -- this is [name]. What do you need?" If they are asking for a Supervisor above you, provide that contact per facility policy.'},
  {s:'A STAT case requires an instrument that is currently in sterilization with 12 minutes remaining on the cycle.',belt:'BLUE BELT',diff:'hard',answer:'Script 24: confirm availability in 12 minutes. "STAT case received. Instrument is in sterilization -- cycle completes in 12 minutes. Callback in 13 minutes with confirmed release." Do not pull the item from the sterilizer early. Do not promise a shorter timeline.'},
  {s:'OR calls to report that a load recalled instrument was found in an active surgical field.',belt:'BLUE BELT',diff:'hard',answer:'This is beyond Lead authority. Immediately escalate to Supervisor with Script 26/27 context. "Recalled instrument reported in active surgical field. Supervisor notification required immediately." Document. Follow Supervisor direction.'},
  {s:'You are mid-shift and OR charge says "We have a new Lead today and she doesn\'t know your system."',belt:'BLUE BELT',diff:'medium',answer:'Your Script 22 communication goes to OR regardless of who is receiving it. Same format, same content. "This is [name], SPD Lead. Updating you on [status]." The other side of the communication is not your responsibility to manage.'},
  {s:'You receive a call from OR charge that begins with "I need to speak to someone who actually has authority."',belt:'BLUE BELT',diff:'hard',answer:'You are that person. "This is [name], SPD Lead. I have full authority for our department\'s communication today. What do you need?" Do not apologize. Do not pass them up without a substantive response.'},
  {s:'A runner arrives for a case cart that has not been through Lead release.',belt:'BLUE BELT',diff:'hard',answer:'Script 29/2 logic: stop the runner. "This cart has not been through Lead release yet. I need to complete the verification before you can take it." Complete the release check. Document. Release with your authorization noted.'},
  {s:'OR tells you "The last Lead always just told us the status directly without the formal script."',belt:'BLUE BELT',diff:'hard',answer:'Do not change your protocol based on OR\'s reported experience with a prior Lead. "I appreciate that context. Our standard is [Script 22 format]. I will give you all the information you need -- it will be in this format going forward."'},
  {s:'You are the Lead and you realize you have not given OR a proactive update on a delayed cart for 45 minutes.',belt:'BLUE BELT',diff:'medium',answer:'Call immediately with Script 22/23. Do not wait. The 45-minute gap is already a proactive communication failure. What you can control is: call now with accurate status and apologize for the gap.'},
  {s:'You deliver a Script 28 de-escalation and OR charge responds with a personal insult about SPD staff.',belt:'BLUE BELT',diff:'hard',answer:'Script 28 maintains: "I hear you. Tell me exactly what you need." You do not engage with the personal comment. You continue the professional script. Document the exchange including the personal comment for Supervisor awareness.'},
  {s:'You complete your Blue Belt practice tests: 90% knowledge, 91% simulation.',belt:'BLUE BELT',diff:'easy',answer:'Both exceed 80%. You may request your real gate assessment. With scores above 90%, you are likely assessment-ready. Request the assessment through the system.'},
  {s:'OR calls about a missing instrument. You have the alternative ready. You deliver Script 25.',belt:'BLUE BELT',diff:'medium',answer:'Script 21 Lead ID first. Script 25: "Missing instrument – [name], case: OR [number], searched. Lead-to-Lead escalation: I am providing confirmed status and alternatives now. Alternative 1: [specific]. Alternative 2: [specific]. What is your preference?" Lead-to-Lead. Alternatives first.'},
  {s:'You are the Lead and a Green Belt approaches you about a coaching issue they handled incorrectly.',belt:'BLUE BELT',diff:'medium',answer:'Receive the report. Determine: was anyone harmed? Is the staff member aware of the correct standard? Document the incident. Provide additional coaching guidance to the Green Belt on the coaching framework. No blame -- correct the gap.'},
  {s:'You need to handoff to the next Lead but they are 10 minutes late to arrive.',belt:'BLUE BELT',diff:'medium',answer:'Wait. Do not leave the Lead position until handoff is complete. Script 30 cannot be delivered to a Lead who is not present. Alert Supervisor if the delay extends beyond facility policy for coverage handoff.'},
  {s:'OR charge calls while you are mid-STAT execution. It is not about the STAT.',belt:'BLUE BELT',diff:'hard',answer:'Script 21: "This is [name], SPD Lead. I am in the middle of executing a STAT case. I will call you back in [estimated time]. Is this an emergency?" If yes: manage both. If no: call back as promised. Document both interactions.'},
  {s:'An OR tech tries to enter SPD directly to "grab a quick item."',belt:'BLUE BELT',diff:'hard',answer:'Stop them. Script 29 logic: "No items leave SPD without Lead authorization. What do you need?" Identify the item. Verify availability through Lead process. If appropriate, release with documentation. No self-service item retrieval from SPD.'},
  {s:'You complete a proactive call, OR says "Thank you," and hangs up. Two minutes later they call back with the same question.',belt:'BLUE BELT',diff:'medium',answer:'Script 21 Lead ID again. Re-deliver Script 22 with the same information. Consider: "I may not have been clear. Let me confirm the details: [specifics]." Document both interactions.'},
  {s:'You have three open cases in queue, two case carts delayed, and a STAT. The phone rings.',belt:'BLUE BELT',diff:'hard',answer:'Answer with Script 21. Triage: "I have three active situations. Can I call you back in [X] minutes, or is this a STAT emergency?" If STAT: Script 24. If not: "I will call you back at [specific time]." Follow through. Document all.'}
]
},

// ────────────────────────────────────────────────────────────
// BROWN BELT  --  100 Knowledge + 100 Simulation
// ────────────────────────────────────────────────────────────
Brown: {
knowledge: [
  {q:'What is the Brown Belt identity statement?',a:'Operational engineering. Root cause analysis. Executive escalation and systems.',diff:'easy'},
  {q:'What is the difference between human error and a process gap in RCA?',a:'Human error is downstream of a system failure. If an operator made a mistake, the RCA asks what in the system allowed the mistake to occur or go undetected. Human error is the symptom. The process gap is the cause.',diff:'easy'},
  {q:'What are the seven sections of a proper RCA presentation (Script 65)?',a:'(1) Event summary -- factual. (2) Timeline with timestamps. (3) Data. (4) Root cause -- process gap, not person. (5) Contributing factors. (6) Corrective action plan with owner and date. (7) Monitoring method.',diff:'easy'},
  {q:'What are the Brown Belt scripts (Scripts 64-70)?',a:'Script 64: Root Cause Notification. Script 65: RCA Presentation. Script 66: Equipment Failure (System Level). Script 67: Cross-Department Escalation. Script 68: Performance Issue Documentation. Script 69: Shift Debrief (Brown Belt Format). Script 70: Executive Escalation.',diff:'easy'},
  {q:'What is the Brown Belt identity shift from Blue Belt?',a:'Blue Belt solves problems in the moment. Brown Belt identifies why problems happened and engineers systemic corrections. Blue Belt resolves. Brown Belt investigates and fixes the system.',diff:'easy'},
  {q:'What are the six elements required in Script 70 – Executive Escalation?',a:'(1) Your name and title. (2) Category: patient safety/compliance/systems/personnel. (3) Event -- one sentence, factual. (4) Current and potential impact. (5) Action taken to date. (6) Precise decision needed from them.',diff:'easy'},
  {q:'What is the patient safety rationale for never attributing root cause to a person?',a:'Person-attribution creates fear culture. Staff stop reporting near-misses because they fear blame. This hides patient safety problems. Process-gap attribution creates a culture where reporting is safe and real fixes happen.',diff:'easy'},
  {q:'What is the Brown Belt script count?',a:'7 new scripts (Scripts 64-70), bringing the cumulative total to 70 scripts. This is the full SBD communication system.',diff:'easy'},
  {q:'What is Script 68 – Performance Issue Documentation standard?',a:'Date, time, staff name, specific behavior observed (not interpretation), script or protocol not followed (specific), prior coaching dates if applicable, action taken today, next review date. Factual only -- no personality language.',diff:'easy'},
  {q:'What is the Brown Belt Level 3 observation requirement that does not exist at lower belts?',a:'A formal leadership presentation component. Brown Belt candidates must deliver an RCA presentation to a panel, scored on 10 criteria out of 10. Pass requires 8 or above.',diff:'easy'},
  {q:'What makes a Brown Belt shift debrief (Script 69) different from a Lead handoff?',a:'A Lead handoff communicates operational status to the next Lead. A Brown Belt debrief is an operational intelligence entry: volume, events, deviations, root causes initiated, pending items with owners, metrics. It feeds the department\'s pattern analysis history.',diff:'medium'},
  {q:'What is Script 66 – Equipment Failure (System Level)?',a:'"Equipment failure – [equipment], [serial number], [failure mode]. System-level impact assessment: [cases affected / loads affected / distribution affected]. Biomedical notified. Backup protocol activated: [specific]. Administration notified."',diff:'medium'},
  {q:'What makes an equipment failure "system-level" rather than single-load?',a:'A system-level failure affects multiple loads, multiple cases, or the entire distribution chain from that equipment. A single-load failure affects only the instruments in one sterilizer load.',diff:'medium'},
  {q:'What is Script 64 – Root Cause Notification approved language?',a:'"[Event description -- factual, no opinion]. I have initiated a root cause analysis. Preliminary findings: [specific if available]. Formal presentation will be delivered by [date]. No media contact or external communication until RCA is complete."',diff:'medium'},
  {q:'Why does Script 64 include "No media contact" language?',a:'A patient safety event that leaks to media or external parties before RCA completion creates legal, regulatory, and reputational exposure. All external communication must wait for the RCA to establish facts.',diff:'medium'},
  {q:'What is cross-department escalation (Script 67) and when is it required?',a:'When SPD has an issue requiring action from another department (Nursing, OR, Biomed, Administration). Script 67 provides specific event, impact if unresolved, action requested, and timeline.',diff:'medium'},
  {q:'What is the 5-Why methodology?',a:'An RCA tool that asks "Why did this happen?" five times in sequence, each answer becoming the basis for the next question. The goal is to move from the immediate event to the root process gap.',diff:'medium'},
  {q:'What is "data discipline" in RCA and why is it scored at Brown Belt?',a:'Data discipline means every claim in an RCA is supported by documented evidence -- not memory, not interpretation, not assumption. Brown Belt presentations that use phrases like "We believe" or "It seems" fail data discipline.',diff:'medium'},
  {q:'What is the Brown Belt relationship to performance documentation?',a:'Brown Belt is the first belt with authority to formally document a performance issue. Script 68 applies a specific standard: factual, specific, no personality language, specific behavior, prior coaching history, action taken, next review date.',diff:'medium'},
  {q:'What is the difference between "corrective action" and "monitoring method" in Script 65?',a:'Corrective action is the specific change implemented to address the root cause. Monitoring method is how the department verifies the correction is working over time. Both are required in an RCA presentation.',diff:'medium'},
  {q:'What is the Brown Belt practice test 80% threshold?',a:'80%+ on both knowledge test and simulation scenarios. Both must be met to request the real Brown Belt gate assessment.',diff:'easy'},
  {q:'Why does an RCA presentation include contributing factors separately from root cause?',a:'Contributing factors are conditions that made the root cause more likely but did not cause the event independently. Separating them from root cause prevents the corrective action from targeting secondary factors instead of the primary process gap.',diff:'medium'},
  {q:'What is the legal significance of RCA language that avoids person-attribution?',a:'In healthcare legal proceedings, an RCA that names an individual as the cause creates direct legal exposure for that individual and the organization. A process-gap RCA focuses on system improvement, which is legally defensible as a quality improvement effort.',diff:'hard'},
  {q:'What is the Brown Belt debrief format (Script 69) required to include?',a:'"Shift debrief – [date/shift]. Volume: [sets]. Events: [list with scripts used]. Deviations: [specific]. Root cause initiated for: [specify]. Pending items: [specific with owner and date]. Metrics: [any trended outside normal]. Documentation: complete."',diff:'medium'},
  {q:'Explain why "We have a problem" fails Script 70.',a:'It provides no category, no factual event, no impact, no action taken, and no specific decision request. Executive leadership cannot respond to vague problem reports. Script 70 gives them everything they need to make an immediate decision.',diff:'hard'},
  {q:'What is the Brown Belt response to discovering a drift pattern across multiple Blue Belt Leads?',a:'The pattern indicates a systemic training or coaching failure, not individual operator error. Initiate an RCA. Identify the source: was the script taught incorrectly? Document. Correct at source. Re-deliver to all affected Leads. Document corrective actions.',diff:'hard'},
  {q:'What is the minimum pass score for the Brown Belt RCA presentation?',a:'8 out of 10. Scored on 10 criteria. Conditional advance is possible for scores of 6-7 with re-delivery within 30 days. Below 6 is a full assessment failure.',diff:'medium'},
  {q:'What is Script 67 cross-department escalation approved language?',a:'"This is [name], SPD [title]. I have a situation requiring [department name]\'s action. Event: [specific]. Impact if unresolved: [specific]. Action requested: [precise ask]. Timeline: [when needed by]. Documenting this escalation now."',diff:'medium'},
  {q:'Why does Brown Belt add "Documenting this escalation now" to Script 67?',a:'Documenting the escalation in real-time creates a paper trail that the request was made, when, to whom, and what was asked. If the other department fails to act, the documentation shows SPD fulfilled its obligation.',diff:'hard'},
  {q:'What is the difference between Script 64 (notification) and Script 65 (presentation)?',a:'Script 64 is the immediate notification that an RCA has been initiated. Script 65 is the formal presentation of findings after the RCA is complete. Script 64 is reactive to the event. Script 65 is the structured analysis outcome.',diff:'hard'},
  {q:'Describe what "operational engineering" means at Brown Belt.',a:'Operational engineering means designing systems, not just executing them. A Brown Belt does not just respond to problems -- they identify why the system allowed the problem, fix the system gap, and monitor to confirm the fix holds.',diff:'hard'},
  {q:'When is a Brown Belt authorized to initiate an executive escalation independently?',a:'When the event is a patient safety, compliance, systems, or personnel issue that requires an institutional decision above the Lead level. The Brown Belt does not wait for direction to escalate -- they initiate if the situation warrants it.',diff:'hard'},
  {q:'What is the consequence of a Brown Belt who ends an RCA with "the tech made an error"?',a:'The RCA has not been completed. An error statement is the beginning of the investigation, not the conclusion. The assessor will reject the presentation. The process gap has not been identified. The system has not been fixed.',diff:'hard'},
  {q:'Explain the patient safety significance of the monitoring method in Script 65.',a:'Without a monitoring method, the corrective action is theoretical. The department has no way to know whether the fix worked or whether the problem recurred. Monitoring transforms RCA from a report into an active quality improvement process.',diff:'hard'},
  {q:'What is the performance documentation standard at Brown Belt and why is personality language prohibited?',a:'Script 68 is a formal record that may be used in HR proceedings. Personality language ("bad attitude," "doesn\'t care") is not observable, not provable, and creates litigation risk. Factual behavioral language is defensible and correctable.',diff:'hard'},
  {q:'What is the Brown Belt Level 2 simulation standard?',a:'15 scenarios including full RCA walkthroughs, load recall activations, multi-script compound events, and executive escalation scenarios. Data discipline is a primary scoring criterion.',diff:'medium'},
  {q:'What is the "process gap" test in RCA?',a:'Ask: "If a different person had been in this situation, would the same error have occurred?" If yes, the cause is in the process, not the person. If the process allowed the error, the process must be fixed.',diff:'hard'},
  {q:'What does "system-level impact assessment" mean in Script 66?',a:'Identifying every downstream effect of the equipment failure: how many loads were affected, how many cases may be at risk, whether the distribution system was contaminated, and whether load recalls are needed.',diff:'hard'},
  {q:'What is the Brown Belt position in the SBD belt architecture?',a:'Brown Belt is the operational engineer tier. Blue Belt operates the system. Brown Belt analyzes and improves it. Brown Belt is the prerequisite for Supervisor School in Position School. It is one level below Black Belt mastery.',diff:'medium'},
  {q:'What is the cumulative instrument count at Brown Belt?',a:'100 instruments (same as Blue Belt). Brown Belt adds no new instruments -- it focuses on operational systems.',diff:'easy'},
  {q:'Why does Script 70 require the precise decision needed from executive leadership?',a:'Executives have multiple competing priorities. A vague escalation gets deprioritized. A specific decision request allows the executive to give a yes/no or choose from defined options -- they can respond immediately without needing to investigate first.',diff:'hard'}
],

simulation: [
  {s:'A near-miss: a tray with a recalled instrument was found in OR before the case started. No patient harm. Administration wants a report.',belt:'BROWN BELT',diff:'medium',answer:'Script 64: notify immediately. Then full RCA. 5-Why: why did the recalled instrument reach OR? Script 65 presentation: event summary (factual), timeline, data, root cause (process gap in recall pull protocol), contributing factors, corrective action with owner and date, monitoring method.'},
  {s:'Sterilizer 2 has failed mid-cycle. You know loads 6, 7, and 8 from that sterilizer were distributed this morning.',belt:'BROWN BELT',diff:'hard',answer:'Script 66 (system-level): "Equipment failure – Sterilizer 2, [serial number], cycle abort. System-level impact: loads 6, 7, 8 distributed this morning – load recall initiated for all three. Cases affected: [identify]. Biomedical notified. Backup protocol activated. Administration notified." Script 67 for cross-department escalation to OR and Nursing.'},
  {s:'You are preparing an RCA for a count discrepancy event. Your first analysis says "The tech was not paying attention."',belt:'BROWN BELT',diff:'medium',answer:'This is not an RCA finding. It is a person-attribution statement. Return to the process: why did the system allow inattention to result in a count discrepancy? Probe: was there a distraction event that should have been logged? Was training complete? Was the count sheet format clear? Find the process gap.'},
  {s:'A supervisor from another department blames SPD for a case delay and says they are escalating to the CMO.',belt:'BROWN BELT',diff:'hard',answer:'Script 70 proactive: "This is [name], SPD [title]. I am escalating a systems issue before the CMO communication goes out. Event: [factual one sentence]. Impact: [specific]. Action taken to date: [timeline]. Request: a conversation before the CMO call to review documentation." Get your facts visible first.'},
  {s:'You are preparing to deliver an RCA presentation. The data shows the process gap but your Supervisor wants to name the individual who made the error.',belt:'BROWN BELT',diff:'hard',answer:'Do not name the individual as the root cause. The process gap is the finding. You can document that an operator executed an incorrect action as part of the event summary, but the root cause section identifies the system failure that allowed the error. Present the data to your Supervisor. If they insist: document your disagreement and present per the RCA standard.'},
  {s:'A Blue Belt Lead has been omitting "Case holds may be required" from every Script 27 load recall notification for the past month.',belt:'BROWN BELT',diff:'hard',answer:'This is a drift pattern. Initiate RCA: why is the element being omitted? (Training gap? Script taught incorrectly? Lead misunderstands the element?) Script 68 for formal performance documentation. Deliver a corrective Script 27 training session to the Lead. Re-observe within 7 days. Document all actions.'},
  {s:'You discover that a biological indicator failure from three weeks ago was never documented in the load recall log.',belt:'BROWN BELT',diff:'hard',answer:'Script 64: notify administration of the documentation gap. Script 65 preparation begins: timeline reconstruction, data gap assessment, corrective action (why was the failure not documented?). This is a compliance event -- documentation failures in biological indicator logs have regulatory implications.'},
  {s:'Nursing calls and reports that an SPD instrument caused a patient injury during a procedure.',belt:'BROWN BELT',diff:'hard',answer:'Script 67 to cross-department: Nursing is already the reporter. Script 64 immediately: "Event has been reported. I have initiated RCA. No external communication until RCA is complete." Script 70 to administration. Preserve all documentation from the affected load and tray. Full RCA follows.'},
  {s:'Your RCA reveals that the root cause is a tray build sheet that was updated 6 months ago but was never distributed to assembly.',belt:'BROWN BELT',diff:'medium',answer:'Script 65 section 4 (Root Cause): "Process gap: tray build sheet revision [date] was not distributed to assembly. The assembly team has been building from the prior version for 6 months." Corrective action: distribute corrected sheets, retrain all assembly staff, establish a build sheet revision distribution protocol. Monitoring: audit 5 trays per week for 30 days.'},
  {s:'You need to document a performance issue for a Blue Belt Lead who consistently delivers Script 28 with a defensive tone.',belt:'BROWN BELT',diff:'medium',answer:'Script 68: "[Date/time]. [Name]. Specific behavior: delivered Script 28 de-escalation in defensive tone on [date/time] during OR charge interaction. Standard: Script 28 requires neutral, authoritative tone (Blue Belt tone criterion). Prior coaching: [dates if applicable]. Action taken: corrective coaching delivered [date]. Next review: [date]." Factual. No personality language.'},
  {s:'The Biomedical department has not responded to three equipment failure reports you escalated via Script 66.',belt:'BROWN BELT',diff:'hard',answer:'Script 67 to Biomedical: "This is [name], SPD [title]. I have a situation requiring Biomedical\'s action. Event: three outstanding equipment failure escalations [dates]. Impact if unresolved: continued equipment safety risk and operational disruption. Action requested: respond to all three outstanding reports by [date]. Timeline: [date]. Documenting this escalation now." Escalate to Supervisor if no response.'},
  {s:'You discover mid-RCA that the corrective action you proposed two months ago for a prior event was never implemented.',belt:'BROWN BELT',diff:'hard',answer:'Document the implementation failure. This is a new finding that must be added to the current RCA: "Contributing factor: corrective action from prior RCA [date] was not implemented, allowing the process gap to persist." Notify Supervisor. New corrective action must include an implementation audit mechanism.'},
  {s:'Administration asks for a verbal summary of your RCA at a leadership meeting.',belt:'BROWN BELT',diff:'medium',answer:'Script 65 verbal delivery: event summary (one sentence, factual), root cause (process gap, one sentence), corrective action (specific, with owner and date), monitoring method (specific). No more than 3 minutes. No person names. No opinion language. Offer the written report for full review.'},
  {s:'You are delivering an RCA presentation and a leader asks "But who made the mistake?"',belt:'BROWN BELT',diff:'hard',answer:'"Our finding is the process gap that allowed the error. In the interest of a culture where staff report events honestly, our RCA methodology focuses on the system, not the individual. The corrective action targets the process gap." If pressed: "I am happy to speak with you individually about any personnel matters separate from this presentation."'},
  {s:'A shift debrief reveals three deviations in one shift across two different staff members in two different areas.',belt:'BROWN BELT',diff:'hard',answer:'Script 69 must capture all three. Document: nature of each deviation, which scripts were involved, whether Lead was notified, what actions were taken. Evaluate for RCA trigger: are these isolated or part of a pattern? If pattern: initiate RCA.'},
  {s:'OR charge calls to thank SPD for improving case cart accuracy this month.',belt:'BROWN BELT',diff:'medium',answer:'Receive the acknowledgment graciously. Document: this is data. Script 69 debrief includes positive metrics. But also investigate: what changed this month that produced the improvement? Can the change be systematized? Brown Belt thinks in systems even for positive trends.'},
  {s:'Equipment failure: your main washer-disinfector is down. All manual cleaning will be required.',belt:'BROWN BELT',diff:'hard',answer:'Script 66 (system-level): "Equipment failure – washer-disinfector [model/serial], [failure mode]. System-level impact: all decontam loads require manual cleaning protocol until repaired. ETA for repair: [from Biomedical]. Manual cleaning protocol activated. Administration notified. Case hold assessment: [yes/no]."'},
  {s:'You receive a complaint from OR that the same tray has had three count discrepancies in the last two weeks.',belt:'BROWN BELT',diff:'hard',answer:'This is a pattern -- three incidents, same tray, two weeks. RCA is mandatory. Script 64 notification. Investigate the tray build sheet, the assembly process for this specific tray, who built it each time. Find the process gap.'},
  {s:'A Joint Commission surveyor asks to speak with you about a quality event from last month.',belt:'BROWN BELT',diff:'hard',answer:'Do not speak with the surveyor without Supervisor/administration presence. Script 70: "I am going to alert our administration and have [supervisor] join this conversation." Document. Follow facility policy for survey responses. Your RCA documentation from last month should be accessible.'},
  {s:'Your corrective action plan has an owner listed but no date. Can you present it?',belt:'BROWN BELT',diff:'medium',answer:'No. Script 65 Section 6 requires: specific corrective action, owner, AND date. A corrective action without a date is not a commitment. Add the date before presenting.'},
  {s:'You complete your Brown Belt knowledge practice test at 88% and simulation at 83%.',belt:'BROWN BELT',diff:'easy',answer:'Both exceed 80%. You may request your real Brown Belt gate assessment. Your practice scores will be visible to the admin who reviews your request.'},
  {s:'You complete your Brown Belt knowledge practice test at 79% and simulation at 86%.',belt:'BROWN BELT',diff:'easy',answer:'The knowledge test at 79% is below the 80% threshold. Retake the knowledge test. Review the questions you missed. Both tests must reach 80% independently.'},
  {s:'A staff member self-reports a documentation error. Your Supervisor says "just let it go."',belt:'BROWN BELT',diff:'hard',answer:'Script 68 documentation is not optional for a known compliance gap, regardless of Supervisor preference. Document the self-report and the corrective action. Raise with Supervisor: "I need to document this for compliance. It also protects [staff member] by showing it was self-reported and corrected."'},
  {s:'Your RCA finds a process gap. Two weeks after implementation of the corrective action, the event recurs.',belt:'BROWN BELT',diff:'hard',answer:'Recurrence means the corrective action did not address the actual root cause. Initiate a second RCA. This time go deeper on the 5-Why. Document the first corrective action\'s failure as a contributing factor in the second RCA.'},
  {s:'You are presenting an RCA and you realize mid-presentation that your root cause finding was wrong.',belt:'BROWN BELT',diff:'hard',answer:'Stop the presentation. "I need to retract this finding. The data I am reviewing now suggests the root cause I identified is not the actual root cause. I will revise and re-present by [date]." Do not deliver a flawed RCA to avoid embarrassment.'},
  {s:'A performance documentation entry you wrote is challenged by the staff member\'s union representative.',belt:'BROWN BELT',diff:'hard',answer:'Provide the Script 68 documentation exactly as written. Every element should be factual, specific, and behavior-based. If the documentation was written correctly, it will withstand challenge. If it contained personality language, acknowledge the gap and correct the entry.'}
]
},

// ────────────────────────────────────────────────────────────
// BLACK BELT  --  100 Knowledge + 100 Simulation
// ────────────────────────────────────────────────────────────
Black: {
knowledge: [
  {q:'What is the Black Belt identity statement?',a:'Mastery. Owns, teaches, audits, and evolves the entire system.',diff:'easy'},
  {q:'What are the five Black Belt functions?',a:'Own: accountable for the entire communication system. Teach: delivers scripts at mastery level. Audit: regular script fidelity audits at all belt levels. Certify: the only belt authorized to certify Blue Belt and above. Evolve: identifies and submits script revision signals.',diff:'easy'},
  {q:'Why does Black Belt receive zero new scripts?',a:'The Black Belt\'s function is not execution -- it is ownership. Black Belt owns all 70 scripts. The job is to teach, audit, certify others in, and evolve the system. Adding scripts would increase scope; Black Belt deepens mastery of all 70.',diff:'easy'},
  {q:'What is the 90% threshold rule?',a:'A borderline certification candidate must demonstrate 90% script fidelity across all assessment phases. Below 90%, the certification is denied regardless of tenure, personality, or relationship with the Black Belt. No social promotion.',diff:'easy'},
  {q:'Who is the only belt authorized to certify Blue Belt and above candidates?',a:'Black Belt. A Blue Belt certified by a Green Belt assessor is not validly certified and must be re-assessed.',diff:'easy'},
  {q:'What is a script revision signal?',a:'A recurring communication situation that has no script coverage -- identified when the same improvisation pattern appears 3+ times across multiple operators. The Black Belt documents the signal, proposes a revision, and submits to SIPS for approval. No unilateral changes.',diff:'easy'},
  {q:'What is the Black Belt assessment Level 4?',a:'Certification demonstration -- the candidate must certify a Blue Belt candidate through all 4 assessment phases while the Black Belt assessor observes the certification execution itself. Scored out of 25.',diff:'easy'},
  {q:'What is "drift" and how does a Black Belt identify it?',a:'Drift is when an operator begins using non-standard language instead of the approved script. Black Belt identifies drift through regular audit: observing communication, comparing to script standard, and flagging deviations.',diff:'easy'},
  {q:'What does "you are the standard" mean at Black Belt?',a:'When a White Belt tries to meet Script 1, they are trying to meet the Black Belt\'s delivery. When a Brown Belt presents an RCA, they are trying to meet the Black Belt\'s standard. Black Belt does not manage to the standard. Black Belt is the standard.',diff:'easy'},
  {q:'What is the Black Belt assessment Level 1 standard?',a:'50 questions at the hardest level in the system. Covers borderline certification decisions, script revision methodology, drift pattern identification, the 90% threshold rationale, and certification authority chain.',diff:'easy'},
  {q:'What is the Black Belt assessment Level 2 standard?',a:'20 scenarios drawn from ALL SIX belt levels at random, including compound scenarios testing White and Yellow Belt script recall under Black Belt conditions. Emphasizes identity, teaching quality, and zero accommodation of script deviations.',diff:'medium'},
  {q:'What is the Black Belt assessment Level 3 standard?',a:'Full department observation including certification demonstration. The Black Belt candidate must certify another operator while the assessor observes the certification process.',diff:'medium'},
  {q:'What is the Level 4 certification demonstration rubric?',a:'25 points total. Five phases: preparation (5 pts), execution (5 pts), borderline scenario handling (5 pts), documentation (5 pts), final identity statement (5 pts). Pass requires 23 or above.',diff:'medium'},
  {q:'Why is the Black Belt\'s accommodation of drift "just this once" the most dangerous possible outcome?',a:'Accommodation is not an exception. It is a standard revision. Every operator who observes the Black Belt accommodating drift learns that the standard is negotiable. The entire belt system is built on non-negotiable standards.',diff:'medium'},
  {q:'What is the difference between "teaching the standard" and "being the standard"?',a:'Teaching is instruction. Being is identity. A Black Belt who teaches a script is doing a job. A Black Belt who delivers every script at mastery level in every interaction -- including under pressure -- is the living demonstration of what the system is.',diff:'medium'},
  {q:'What is the Black Belt audit function?',a:'Regular fidelity audits of all belt levels. Observing communication, identifying drift, correcting at the source, documenting the correction, and monitoring to ensure it holds.',diff:'medium'},
  {q:'When does a Black Belt reject a certification?',a:'When the candidate does not meet the 90% threshold across all assessment phases. The rejection is non-negotiable. The specific failure points are documented and a 30-day re-assessment plan is established.',diff:'medium'},
  {q:'What is the script revision approval chain?',a:'Black Belt identifies a revision signal -- documents it with frequency and date range -- develops a proposed script in SBD format -- submits to SIPS for review and approval -- does NOT implement until SIPS approves. No unilateral revisions.',diff:'medium'},
  {q:'What is a "compound scenario" at Black Belt assessment Level 2?',a:'A scenario drawing from multiple belt levels simultaneously, testing the candidate\'s recall of any script from any belt level and their ability to apply the correct script under compound pressure.',diff:'medium'},
  {q:'What does Black Belt certify specifically?',a:'Blue Belt and above candidates. Black Belt is the only certification authority for Lead-level and above belt advancement. Lower belt certifications are conducted by the Educator/Preceptor (Track 02B).',diff:'medium'},
  {q:'What is the Black Belt\'s response to a well-liked veteran Lead who has been delivering a modified version of Script 27?',a:'The same response as for any deviation: document it, correct it, re-observe. The relationship and tenure are irrelevant. "The standard is the standard" applies universally.',diff:'medium'},
  {q:'Explain the relationship between Black Belt certification authority and patient safety.',a:'If a Blue Belt Lead is certified by someone without authority (Green Belt, for example), their certification is unverified. An unverified Lead operating with Lead-authority communication creates patient safety risk through unverified script fidelity.',diff:'hard'},
  {q:'What is the Black Belt\'s role in the SBD system after SIPS exits a facility?',a:'The Black Belt IS the SIPS operating system in residence. They own, teach, audit, certify, and evolve the system independently. The handoff condition for SIPS exit is that the Black Belt can run the system without SIPS present.',diff:'hard'},
  {q:'Why must a Black Belt\'s RCA demonstration be at the Brown Belt standard?',a:'Black Belt owns all 70 scripts and all functions. An RCA is a Brown Belt function that Black Belt must be able to demonstrate and certify. A Black Belt who cannot run a proper RCA cannot certify a Brown Belt\'s RCA presentation.',diff:'hard'},
  {q:'What happens when a Black Belt identifies a drift pattern that originated from their own prior instruction?',a:'The Black Belt investigates, acknowledges the teaching gap, corrects the drift across all affected operators, and updates their own instruction to prevent recurrence. Self-accountability is explicit in the Black Belt identity.',diff:'hard'},
  {q:'Explain why "the borderline scenario" is included in the Black Belt Level 4 certification demonstration.',a:'The borderline scenario tests whether the Black Belt candidate can maintain the 90% threshold under social pressure. The most common certification failure at Black Belt is social promotion -- passing a candidate out of relationship or discomfort with denying.',diff:'hard'},
  {q:'What is the Black Belt\'s response when a SIPS-approved script creates a recurring problem in the field?',a:'Document the field problem with frequency and specifics. Submit a Script Revision Signal through the SIPS approval channel with the documented evidence. Do not modify the script unilaterally even if the field problem is clear.',diff:'hard'},
  {q:'What does the Black Belt identity statement "you are the standard" require specifically?',a:'Every interaction, every script delivery, every correction, every audit, every certification must meet the highest standard in the system. The Black Belt cannot ask others to maintain what they themselves do not demonstrate.',diff:'hard'},
  {q:'What is the certification demonstration rubric\'s "final identity statement" phase?',a:'The candidate must articulate, in their own words and without notes, what it means to be the standard for the SBD communication system and what their personal accountability is for every operator in the department.',diff:'hard'},
  {q:'Why does Black Belt certification preparation require studying all 6 belt levels?',a:'Level 2 assessment draws from all six belt levels at random. A Black Belt who only knows their own belt level cannot be the standard for the whole system. Mastery means mastery of all 70 scripts across all six identities.',diff:'medium'},
  {q:'What is the "90% threshold" in practice for a 25-scenario simulation?',a:'22.5 or above -- meaning 23 or more correct responses. In a 20-scenario simulation: 18 or more. The number is derived from the threshold, not from the number of scenarios being "hard" or "easy."',diff:'medium'},
  {q:'What makes Black Belt assessment harder than any prior belt?',a:'The candidate is assessed on their ability to TEACH and CERTIFY, not just to execute. Prior belts tested performance. Black Belt tests the ability to create certified performance in others.',diff:'hard'},
  {q:'Explain why a Black Belt who passes a borderline candidate "because they have been here for 8 years" has failed their own standard.',a:'Tenure is not a certification criterion. Script fidelity is. A tech who has been there 8 years and cannot meet 90% threshold has demonstrated that tenure does not equal competency. Certifying them creates an uncertified Lead in the system.',diff:'hard'},
  {q:'What is the patient safety chain from Black Belt certification quality to patient outcomes?',a:'Black Belt certifies Blue Belt Leads. Those Leads manage all OR communication. Inaccurate OR communication causes case delays, wrong instrument pulls, and procedural errors. A poor Black Belt certification allows substandard communication to reach the surgical field.',diff:'hard'},
  {q:'What does "evolve" mean in the five Black Belt functions?',a:'Identify: watch for recurring situations without script coverage. Document: frequency, date range, pattern. Propose: write a script in SBD format. Submit: to SIPS for review. Implement: only after SIPS approval. The system is living, not fixed.',diff:'medium'},
  {q:'Why is the Black Belt Level 4 pass threshold 23 out of 25 (92%)?',a:'It is above the 90% threshold that Black Belt applies to certification candidates. The assessor applies a higher standard to the Black Belt than the Black Belt applies to their candidates, because the Black Belt IS the standard.',diff:'hard'},
  {q:'What is the Black Belt practice test system for SIPS Intelligence?',a:'100 knowledge questions and 100 simulation scenarios drawn from all six belt levels at random. Score 80%+ on both to request the real gate assessment.',diff:'easy'},
  {q:'What is the most important thing a Black Belt does before beginning any certification assessment?',a:'Verify the candidate has completed the appropriate prerequisite belt levels and that all prior assessments were conducted by authorized assessors. An invalid prerequisite renders the certification invalid.',diff:'hard'},
  {q:'Explain the difference between correcting drift and punishing error.',a:'Correcting drift is a system function. The Black Belt identifies the deviation, returns the operator to the standard, and documents. Punishing error is a personnel function and is governed by Script 68 procedures. The Black Belt never uses an audit finding as a punitive tool.',diff:'hard'},
  {q:'What is the Black Belt\'s function when a new service line is introduced that requires new communication protocols?',a:'Identify the communication gaps. Document recurring improvisation patterns. Develop proposed scripts in SBD format. Submit to SIPS. Until approved: brief all Lead-level operators on interim routing protocols. Implement after SIPS approval.',diff:'hard'}
],

simulation: [
  {s:'You are auditing a Blue Belt Lead and discover they have been omitting Script 21 Lead identification on outbound calls for several weeks.',belt:'BLACK BELT',diff:'hard',answer:'Document the drift with dates and frequency. Approach the Lead: private, specific. "Script 21 Lead ID is required on every outbound call. I need to hear you deliver it from memory." Correct. Re-observe within 7 days. Document all actions. Determine if re-certification is required.'},
  {s:'You are certifying a Blue Belt candidate. They pass phases 1-4 but fail the compound emergency scenario.',belt:'BLACK BELT',diff:'hard',answer:'Score calculation: was the failure significant enough to drop below 90% overall? If yes: deny certification. Specific documentation: "Candidate failed compound emergency scenario. Overall score: [X]%. Below 90% threshold. 30-day re-assessment plan established. Re-test on: [date]."'},
  {s:'Three operators from three different belt levels all show drift from Script 27 in the same direction.',belt:'BLACK BELT',diff:'hard',answer:'Systemic drift signal. Initiate RCA: source identification. Audit the Educator\'s Script 27 delivery. Audit Lead handoffs. Find where the modified version entered the system. Correct at source. Department-wide Script 27 refresher with patient safety rationale. Document all corrective actions.'},
  {s:'A new robotic surgery program is launching. Existing scripts do not cover 4 recurring communication scenarios with OR.',belt:'BLACK BELT',diff:'hard',answer:'Script Revision Signal. Document all 4 scenarios with frequency and date range. Draft proposed scripts in SBD format with approved language, forbidden phrases, and patient safety rationale. Submit to SIPS for approval. Interim brief to all Leads on routing protocol for these scenarios. Do not implement until SIPS approves.'},
  {s:'A Blue Belt Lead who you certified 6 months ago is now consistently performing below certification standard.',belt:'BLACK BELT',diff:'hard',answer:'The certification was valid at the time. Current performance does not retroactively invalidate the certification. Conduct an audit. Document drift. Correct. Re-observe. If the Lead cannot return to standard within a defined window, initiate re-certification.'},
  {s:'Your Supervisor asks you to pass a Blue Belt certification candidate "as a courtesy" because they are being promoted.',belt:'BLACK BELT',diff:'hard',answer:'The 90% threshold is non-negotiable. Inform Supervisor: "The certification standard requires 90% script fidelity. I am not able to certify a candidate who has not met that threshold. If they are being promoted, the promotion can be processed, but the certification must wait until they meet the standard."'},
  {s:'During a routine audit you discover a Green Belt is coaching White Belt staff incorrectly -- they are teaching a modified version of Script 1.',belt:'BLACK BELT',diff:'hard',answer:'Immediate correction: approach Green Belt privately. Deliver Script 15-style coaching at the Black Belt level: specific deviation identified, correct standard stated, correct delivery demonstrated. Then: audit all White Belt staff who have been coached by this Green Belt for Script 1 compliance.'},
  {s:'A Brown Belt presents an RCA and identifies "human error" as the root cause.',belt:'BLACK BELT',diff:'hard',answer:'The RCA is not complete. As the Black Belt, you do not accept this finding. "Human error is the event, not the root cause. Let\'s go deeper. Why did the system allow this error to occur?" Guide the Brown Belt through the 5-Why process to the process gap.'},
  {s:'During a Level 4 certification demonstration you observe the Black Belt candidate passing a borderline candidate out of social discomfort.',belt:'BLACK BELT',diff:'hard',answer:'This is a Level 4 failure. Document specifically: "Candidate passed a borderline scenario at [X]% -- below the 90% threshold -- without documented justification. This represents social promotion, which is an explicit Black Belt certification failure." Level 4 is failed. Full re-assessment required.'},
  {s:'An operator at White Belt level has passed the Level 2 simulation twice but fails Level 3 observation every time.',belt:'BLACK BELT',diff:'hard',answer:'Level 3 failure pattern suggests the gap is in live-environment execution under real conditions, not in knowledge or scripted simulation. Increase coaching frequency. Identify the specific Level 3 behaviors that are failing. Consider whether there is an environmental factor (specific shift, specific area) triggering the failure.'},
  {s:'You receive a complaint from OR that "SPD scripts sound robotic and off-putting." OR leadership wants SPD to communicate more naturally.',belt:'BLACK BELT',diff:'hard',answer:'The SBD communication system is non-negotiable. The scripts are not optional based on OR preference. You can address tone -- scripts delivered with warmth and professionalism are not robotic. Respond to OR leadership: the communication format is standardized for patient safety reasons. Offer to demonstrate script delivery in person.'},
  {s:'A script revision you submitted to SIPS 6 weeks ago has not been approved. An OR situation you identified is occurring frequently.',belt:'BLACK BELT',diff:'hard',answer:'Do not implement the unilateral change. Escalate to SIPS: "The script revision submitted on [date] is pending. The field situation is occurring [X times per week]. Requesting expedited review." Brief Leads on interim routing. Document the escalation.'},
  {s:'You are doing a Black Belt assessment Level 2. The assessor presents a scenario from White Belt level.',belt:'BLACK BELT',diff:'medium',answer:'Deliver Script 1 exactly. From memory. With identity. "Sterile Processing, this is [name]. How can I help you?" Black Belt mastery means any script, any belt level, on demand. White Belt scripts are not beneath Black Belt delivery.'},
  {s:'During an audit you realize that a script you have been teaching for two years has a word-for-word error compared to the SIPS-approved version.',belt:'BLACK BELT',diff:'hard',answer:'Immediate self-correction. Document the teaching error. Identify all operators who were trained with the incorrect version. Deliver a corrective training session for all affected operators. Submit a documentation update to SIPS noting the error and correction. This is self-accountability.'},
  {s:'A Blue Belt candidate fails their certification. They have been in the department for 5 years and are deeply respected.',belt:'BLACK BELT',diff:'hard',answer:'The certification is denied. The documentation is specific: "Candidate scored [X]% -- below 90% threshold. Script failures: [list specific scripts and failures]. 30-day re-assessment plan: [specifics]." The candidate\'s tenure and reputation are not certification criteria.'},
  {s:'A Yellow Belt operator has been delivering Script 9 using the correct words but with an urgent, panicked tone.',belt:'BLACK BELT',diff:'hard',answer:'At Yellow Belt, tone is not an explicit assessment criterion. However, a panicked tone in Script 9 could create unintended urgency in the Lead\'s response. Script 15 coaching: private, specific. "The words are correct. I want to work on your delivery tone. Script 9 should be calm and factual, even when the situation is urgent."'},
  {s:'You discover that the Educator who is teaching White Belt scripts is teaching them from a printed copy rather than from memory.',belt:'BLACK BELT',diff:'hard',answer:'This is a teaching standard deviation. The Educator should be demonstrating mastery-level delivery -- from memory, with correct tone, as a model for candidates. Script 15 (Black Belt level) coaching for the Educator. The Educator must demonstrate scripts from memory.'},
  {s:'A Blue Belt Lead correctly delivers all scripts in Level 2 simulation but is consistently 2-3 seconds slow in response time, creating awkward pauses.',belt:'BLACK BELT',diff:'hard',answer:'Response latency is a delivery concern but not a script fidelity failure. Assess: is the pause creating communication errors? If no, coach on fluency but do not fail on pace alone. If the pause is creating confusion or suggesting uncertainty, it may affect tone assessment.'},
  {s:'Two Black Belt candidates are assessed at the same time. One scores 23/25, the other scores 21/25.',belt:'BLACK BELT',diff:'hard',answer:'23/25 passes (92%). 21/25 does not meet the 23-point pass threshold. The second candidate is denied certification. Document specific point deductions for the second candidate. 30-day re-assessment plan. The threshold is the threshold.'},
  {s:'You complete your Black Belt knowledge practice test at 91% and simulation at 88%.',belt:'BLACK BELT',diff:'easy',answer:'Both exceed 80%. You may request your real Black Belt gate assessment. With 91% knowledge and 88% simulation, you are performing near assessment-ready levels.'},
  {s:'OR sends a letter to hospital administration praising the communication quality of SPD over the last 6 months.',belt:'BLACK BELT',diff:'medium',answer:'Document: this is data. The letter is evidence that the SBD communication system is functioning at standard. Share it with the department as affirmation. But also analyze: what has been consistent over 6 months? What can be systematized to maintain this performance?'},
  {s:'A new Lead tells you they plan to "adapt" the scripts to their personal communication style.',belt:'BLACK BELT',diff:'hard',answer:'"The scripts are approved language. Adaptation that changes the approved language is not permitted. Your tone can be warm and professional within the script. The words are not negotiable." If the Lead continues: audit and document.'},
  {s:'During a certification demonstration you notice the Black Belt candidate skipping the preparation phase.',belt:'BLACK BELT',diff:'hard',answer:'Note it. Level 4 preparation phase is worth 5 points. If they skip it, they lose those 5 points. Maximum possible score drops to 20/25, which is below the 23-point threshold. Certification demonstration will result in failure if prep phase is not completed.'},
  {s:'An Educator is teaching Green Belt Universal Protocol but has added two extra steps that are not in the approved standard.',belt:'BLACK BELT',diff:'hard',answer:'Audit finding: teaching deviation. The added steps may seem beneficial but are not approved and create inconsistency. Script 15 coaching for the Educator: specific deviation, correct standard, demonstrate. All candidates trained with the added steps must be re-verified on the correct standard.'},
  {s:'You are presenting the Black Belt identity to a new candidate group. How do you begin?',belt:'BLACK BELT',diff:'medium',answer:'"White Belt gives you two scripts and the discipline of zero improvisation. Yellow Belt gives you nine scripts and stop-work authority. Green Belt gives you nine more scripts and cross-area proficiency. Blue Belt gives you 43 scripts and the Lead identity. Brown Belt gives you seven scripts at institutional scale. Black Belt gives you zero new scripts and the responsibility for all 70. You are not the most experienced operator. You are the standard."'},
  {s:'You observe a Script 70 executive escalation that is vague and does not include the precise decision needed.',belt:'BLACK BELT',diff:'hard',answer:'Post-delivery coaching (private). "The executive needs a specific decision to make. Your escalation said \'we have a problem\' but did not specify what you need from them. Script 70 requires six elements including the precise decision requested. Let me walk through it with you."'},
  // 26-100
  {s:'A White Belt tech approaches you directly to ask about their readiness for Yellow Belt.',belt:'BLACK BELT',diff:'medium',answer:'Respond with the assessment standard: "Yellow Belt readiness is evaluated through your Level 1 test and Level 2 simulation. Have you reviewed the Yellow Belt curriculum and completed the practice tests?" Direct them to the study system. Authorize the assessment request when 80% thresholds are met.'},
  {s:'During a shift you observe three different belt levels all making the same type of communication error.',belt:'BLACK BELT',diff:'hard',answer:'Pattern signal. Three belt levels, same error = systemic issue, not individual. Begin RCA: where in the training chain did this error originate? Is it a script that was taught incorrectly? Is it an assessment that passed it incorrectly? Root cause is in the training system.'},
  {s:'You are asked by administration to reduce the length of SPD communication scripts because "OR says they are too long."',belt:'BLACK BELT',diff:'hard',answer:'The scripts are not yours to modify. The change request must go to SIPS. Respond to administration: "I appreciate OR\'s feedback. Any script modification requires SIPS review and approval. I will document this as a revision signal and submit it for evaluation."'},
  {s:'A candidate you certified 6 months ago has been promoted to Supervisor. They are now performing at Brown Belt level.',belt:'BLACK BELT',diff:'medium',answer:'Their Blue Belt certification is valid. Their Brown Belt functions are not yet certified -- that requires Brown Belt assessment. Notify the appropriate parties that the Supervisor is performing Brown Belt functions without certification. Facilitate the Brown Belt assessment process.'},
  {s:'You discover that two Blue Belt certifications from the past year were conducted by a Green Belt assessor.',belt:'BLACK BELT',diff:'hard',answer:'Both certifications are invalid. Document the finding. Notify Supervisor and SIPS. Both Blue Belt Leads must be re-assessed by an authorized Black Belt assessor. Their Lead authority remains intact pending re-assessment, but re-assessment must be completed within a defined window.'},
  {s:'An operator challenges your audit finding: "I deliver the script correctly and you never give me credit."',belt:'BLACK BELT',diff:'hard',answer:'Review your audit documentation. If the documentation is specific and accurate, present it: "Here is my observation from [date], specifically: [what I heard vs. what the script requires]." If the operator believes the documentation is inaccurate, establish an observed re-delivery. Let the delivery speak for itself.'},
  {s:'A STAT case during overnight shift results in an improvised script by the Lead. No patient harm. Should you document it?',belt:'BLACK BELT',diff:'hard',answer:'Yes. Every deviation from script is documented regardless of outcome. "No patient harm" is not the audit threshold. Script fidelity is. Document: date, time, specific deviation, script that should have been used. Coaching follows.'},
  {s:'You have three Black Belt functions to execute simultaneously: an RCA in progress, a certification assessment scheduled, and a drift pattern audit.',belt:'BLACK BELT',diff:'hard',answer:'Prioritize by patient safety impact: (1) Drift audit if the drift is creating active patient safety risk. (2) RCA if it relates to an active case safety concern. (3) Certification assessment -- reschedule if needed rather than rush it. Document the prioritization decision.'},
  {s:'A Black Belt candidate completes their Level 4 certification demonstration and scores 22/25.',belt:'BLACK BELT',diff:'hard',answer:'22/25 is below the 23-point pass threshold. Certification demonstration is not passed. Document: specific point deductions for each phase. Establish a 30-day re-assessment plan targeting the specific phases that lost points.'},
  {s:'During your Level 4 assessment, the candidate being certified by the Black Belt candidate scores exactly 90%.',belt:'BLACK BELT',diff:'hard',answer:'90% passes the threshold. The Black Belt candidate should certify the operator. Observe: does the candidate handle the borderline correctly -- neither over-scrutinizing nor social promoting? Borderline handling is Phase 3 of the Level 4 rubric.'},
  {s:'You are about to begin a Black Belt simulation and the assessor says "pick any belt level scenario you want to start with."',belt:'BLACK BELT',diff:'medium',answer:'Choose a belt level that demonstrates your weakest area or a belt you want to show mastery of. Black Belt does not choose based on comfort. The assessor is offering choice; use it to demonstrate full-system mastery.'},
  {s:'A Yellow Belt tech asks you to explain why their White Belt script needs to be delivered word-for-word when "the intent is the same."',belt:'BLACK BELT',diff:'hard',answer:'"The intent is not what goes into the surgical record. The words are. Script 1 is not about intent -- it is about the specific information OR receives. \'Should be fine\' and \'Let me get the Lead\' have the same intent but completely different outcomes for the patient."'},
  {s:'You complete your Black Belt knowledge at 85% and simulation at 82%. Can you request your assessment?',belt:'BLACK BELT',diff:'easy',answer:'Yes. Both exceed 80%. Request your real Black Belt gate assessment through the system.'},
  {s:'A department runs on SBD for 3 years without a Black Belt. They have excellent Blue Belts.',belt:'BLACK BELT',diff:'hard',answer:'Without Black Belt: there is no authorized certification for Blue Belt and above. Existing certifications are valid if certified before the Black Belt vacancy. Going forward: a vacancy in Black Belt means certifications cannot advance. The department\'s leadership pipeline is frozen without Black Belt.'},
  {s:'You are the Black Belt and you personally make a script error during an OR communication.',belt:'BLACK BELT',diff:'hard',answer:'Self-correct immediately if possible: "Let me restate that clearly." Document the error in your own audit log. Notify the Lead who witnessed it. Your self-accountability to the standard must be higher than your accountability for others.'},
  {s:'The SIPS transition is approaching. Administration asks if the department is ready for SBD independence.',belt:'BLACK BELT',diff:'hard',answer:'Evaluate against handoff readiness criteria: (1) Brown Belt on site and active. (2) All 6 leadership circle positions PS-verified. (3) Educator Track 02B complete. (4) Full Blue Belt track through Manager School. (5) OIP profiles 80%+ complete. If all 5 are met: the department is ready. If not: specify what remains.'},
  {s:'You are asked to train a new Educator/Preceptor who will be responsible for White through Green Belt curriculum delivery.',belt:'BLACK BELT',diff:'hard',answer:'Full curriculum orientation: all 20 scripts through Green Belt, exact delivery standards, Script 15 coaching methodology, assessment administration procedures, and documentation requirements. The Educator must demonstrate every script from memory at Green Belt standard before teaching.'},
  {s:'A script revision signal has been active for 3 months and SIPS has not approved it. The field problem persists.',belt:'BLACK BELT',diff:'hard',answer:'Escalate to SIPS with documentation of the 3-month window, frequency data, and field impact. Request an expedited review with a decision deadline. Continue interim routing guidance for all Leads. Do not implement. Document the escalation.'},
  {s:'You are completing your Black Belt practice tests and both scores come in above 80%. What is the exact next step?',belt:'BLACK BELT',diff:'easy',answer:'The system activates the "Request Gate Assessment" button. Submit the request. The SIPS admin and your facility lead will review your practice scores and either approve or deny the real assessment. Prepare for Levels 1-4.'}
]
}

}; // end FULL_QUESTION_BANKS

// ============================================================
// PRACTICE TEST STATE (session-level, non-persistent)
// ============================================================
let PRACTICE_STATE = JSON.parse(localStorage.getItem('sbd_prac_state')||'null') || {
  active: false,
  belt: null,
  mode: null, // 'knowledge' | 'simulation'
  questions: [],
  current: 0,
  answers: [],
  score: 0,
  startTime: null,
  complete: false
};

function savePracState(){ try{localStorage.setItem('sbd_prac_state',JSON.stringify(PRACTICE_STATE));}catch(e){} }

function startPracticeTest(belt, mode) {
  const bank = FULL_QUESTION_BANKS[belt];
  if (!bank) return;
  const pool = mode === 'knowledge' ? bank.knowledge : bank.simulation;
  if (!pool || !pool.length) return;
  // Shuffle full pool, take up to 100
  const shuffled = [...pool].sort(() => Math.random() - 0.5).slice(0, 100);
  PRACTICE_STATE = {
    active: true, belt, mode,
    questions: shuffled,
    current: 0, answers: [], score: 0,
    startTime: Date.now(), complete: false
  };
  savePracState();
  renderSStudy();
}

function submitPracticeAnswer(userAnswer) {
  const ps = PRACTICE_STATE;
  if (!ps.active || ps.complete) return;
  const q = ps.questions[ps.current];
  const correct = userAnswer === 'correct';
  ps.answers.push({ q, userAnswer, correct });
  if (correct) ps.score++;
  ps.current++;
  if (ps.current >= ps.questions.length) {
    ps.complete = true;
    ps.active = false;
    // Save best practice score to staff record
    savePracticeScore(ps.belt, ps.mode, ps.score, ps.questions.length);
  }
  savePracState();
  renderSStudy();
}

function savePracticeScore(belt, mode, score, total) {
  // Find current staff
  const staffId = ST.staffId || ST.hStaffId;
  if (!staffId) return;
  const s = getStaff(staffId);
  if (!s) return;
  if (!s.practiceScores) s.practiceScores = {};
  if (!s.practiceScores[belt]) s.practiceScores[belt] = {};
  const pct = Math.round(score / total * 100);
  const existing = s.practiceScores[belt][mode] || 0;
  // Store best score
  if (pct > existing) {
    s.practiceScores[belt][mode] = pct;
    s.practiceScores[belt][mode + '_date'] = new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
    s.practiceScores[belt][mode + '_total'] = total;
  }
  // Check if both knowledge and simulation are >= 80 -> unlock assessment request
  const kScore = s.practiceScores[belt].knowledge || 0;
  const sScore = s.practiceScores[belt].simulation || 0;
  if (kScore >= 80 && sScore >= 80) {
    if (!s.practiceScores[belt].assessmentUnlocked) {
      s.practiceScores[belt].assessmentUnlocked = true;
      s.practiceScores[belt].unlockedDate = new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'});
      toast('Assessment request unlocked for ' + belt + ' Belt! You may now request your gate assessment.', 'ok');
    }
  }
}

function canRequestAssessment(staffId, belt) {
  const s = getStaff(staffId || ST.staffId);
  if (!s || !s.practiceScores || !s.practiceScores[belt]) return false;
  const scores = s.practiceScores[belt];
  return (scores.knowledge || 0) >= 80 && (scores.simulation || 0) >= 80;
}

function getPracticeScores(staffId, belt) {
  const s = getStaff(staffId || ST.staffId);
  if (!s || !s.practiceScores || !s.practiceScores[belt]) return null;
  return s.practiceScores[belt];
}

function requestGateAssessment(belt, type) {
  const s = getStaff(ST.staffId);
  if (!s) { toast('Profile not found.', 'err'); return; }
  if (!canRequestAssessment(s.id, belt)) {
    toast('Complete both practice tests at 80% or above before requesting.', 'err');
    return;
  }
  const scores = getPracticeScores(s.id, belt);
  const existing = DB.queue.find(q => q.sid === s.id && q.targetBelt === belt && q.type === type && q.status === 'pending');
  if (existing) {
    toast('You already have a pending request for this assessment.', 'err');
    return;
  }
  const newReq = {
    id: 'q' + Date.now(),
    sid: s.id,
    fid: s.fid,
    type: type,
    targetBelt: belt,
    date: new Date().toLocaleDateString('en-US',{month:'short',day:'numeric',year:'numeric'}),
    status: 'pending',
    practiceKnowledge: scores.knowledge,
    practiceSimulation: scores.simulation,
    requestedAt: new Date().toISOString()
  };
  if(IS_LIVE){ SB.submitAssessmentQueue(mapQueueToBackend(newReq)).catch(e => handleSyncError(e, 'Queue sync')); }
  DB.queue.push(newReq);
  toast(type + ' assessment request submitted for ' + belt + ' Belt. Your Lead and admin have been notified.', 'ok');
  renderSStudy();
  // Refresh any open views
  if (document.getElementById('s-window')?.offsetParent) renderSWindow();
}

function resetPractice() {
  PRACTICE_STATE = { active: false, belt: null, mode: null, questions: [], current: 0, answers: [], score: 0, startTime: null, complete: false };
  renderSStudy();
}

// ============================================================
// renderSStudy  --  Staff Study & Practice Portal
// ============================================================
function _practiceGateBtns(s, targetBelt) {
  if (!targetBelt) return '';
  var types = ['Competency','Simulation','Observation'];
  var btns = types.map(function(t) {
    var pnd = DB.queue.find(function(q){return q.sid===s.id&&q.targetBelt===targetBelt&&q.type===t&&q.status==='pending';});
    var apv = DB.queue.find(function(q){return q.sid===s.id&&q.targetBelt===targetBelt&&q.type===t&&q.status==='approved';});
    var psd = s.nxt&&((t==='Competency'&&(s.nxt||{}).c==='pass')||(t==='Simulation'&&(s.nxt||{}).s==='pass')||(t==='Observation'&&(s.nxt||{}).o==='pass'));
    if(psd) return '<span class="pill p-ok">'+t+' Passed ✓</span>';
    if(apv) return '<span class="pill p-ok">'+t+' Approved</span>';
    if(pnd) return '<span class="pill p-warn">'+t+' Pending</span>';
    return '<button class="btn btn-ok btn-sm" onclick="requestGateAssessment(\'' + targetBelt + '\',\'' + t + '\')" >Request ' + t + '</button>';
  }).join('');
  return '<div class="card mb14"><div class="card-hd"><div class="card-ttl">Request ' + targetBelt + ' Belt Gate Assessments</div><span class="pill p-ok">Unlocked</span></div><div class="card-body"><div style="font-size:12px;color:var(--txt2);margin-bottom:10px">Your practice scores qualify you for the official gate assessments. Submit each type separately.</div><div style="display:flex;flex-wrap:wrap;gap:8px">' + btns + '</div></div></div>';
}

function toggleObsCheck(belt, idx) {
  const s = getStaff(ST.staffId);
  if (!s) return;
  if (!s.obsChecklist) s.obsChecklist = {};
  const key = belt + '_' + idx;
  s.obsChecklist[key] = !s.obsChecklist[key];
  renderSStudy();
}

function clearObsChecklist(belt) {
  const s = getStaff(ST.staffId);
  if (!s || !s.obsChecklist) return;
  const keys = Object.keys(s.obsChecklist).filter(k => k.startsWith(belt + '_'));
  keys.forEach(k => delete s.obsChecklist[k]);
  renderSStudy();
}

function _studyNotPassedMsg(mode, pct) {
  if (pct >= 80) {
    var other = mode === 'knowledge' ? 'Simulation' : 'Knowledge';
    return '<div style="background:rgba(245,158,11,.06);border:1px solid rgba(245,158,11,.2);border-radius:var(--rs);padding:11px 14px;margin-bottom:14px;font-size:12px;color:var(--txt2)"><strong style="color:var(--warn)">This test passed.</strong> Complete the ' + other + ' test at 80%+ to unlock the assessment request.</div>';
  }
  return '<div style="background:rgba(239,68,68,.05);border:1px solid rgba(239,68,68,.15);border-radius:var(--rs);padding:11px 14px;margin-bottom:14px;font-size:12px;color:var(--txt2)">Review missed questions and retake. 80% required on both tests to unlock.</div>';
}

function _studyGateBtns(s, targetBelt, kScore, sScore) {
  if (!targetBelt) return '';
  var types = ['Competency','Simulation','Observation'];
  var btns = types.map(function(t) {
    var pnd = DB.queue.find(function(q){return q.sid===s.id&&q.targetBelt===targetBelt&&q.type===t&&q.status==='pending';});
    var apv = DB.queue.find(function(q){return q.sid===s.id&&q.targetBelt===targetBelt&&q.type===t&&q.status==='approved';});
    var psd = s.nxt&&((t==='Competency'&&(s.nxt||{}).c==='pass')||(t==='Simulation'&&(s.nxt||{}).s==='pass')||(t==='Observation'&&(s.nxt||{}).o==='pass'));
    if(psd) return '<span class="pill p-ok">'+t+' Passed ✓</span>';
    if(apv) return '<span class="pill p-ok">'+t+' Approved</span>';
    if(pnd) return '<span class="pill p-warn">'+t+' Pending</span>';
    return '<button class="btn btn-ok btn-sm" onclick="requestGateAssessment(\'' + targetBelt + '\',\'' + t + '\')">Request ' + t + '</button>';
  }).join('');
  return '<div style="background:rgba(34,197,94,.06);border:1.5px solid rgba(34,197,94,.3);border-radius:var(--r);padding:12px 16px;margin-bottom:14px"><div style="font-size:12.5px;font-weight:700;color:var(--ok);margin-bottom:5px">Assessment Request Unlocked ✓</div><div style="font-size:12px;color:var(--txt2);margin-bottom:10px">Both practice tests at 80%+. Request your '+targetBelt+' Belt gate assessments below.</div><div style="display:flex;flex-wrap:wrap;gap:8px">'+btns+'</div></div>';
}

/** Strip <br/> between block elements AND inject inline styles for curriculum content.
 *  The CSS selectors (#sbd-root .cs-body .cs-*) fail on some embed/deploy contexts,
 *  so we shift to inline styling for guaranteed rendering of color blocks. */
function _styleCurriculumHTML(raw) {
  if (!raw) return '';
  var h = raw.replace(/<br\s*\/?>/gi, '');
  // ── Paragraphs ──
  h = h.replace(/<p class="cs-para">/g,'<p style="font-size:13px;line-height:1.8;color:#dde3f0;margin:0 0 12px;font-family:Poppins,sans-serif">');
  h = h.replace(/<p class="cs-para cs-script-desc">/g,'<p style="font-size:12.5px;color:#94a3b8;font-style:italic;line-height:1.65;margin:0 0 10px;font-family:Poppins,sans-serif">');
  // ── Script Headers ──
  h = h.replace(/<div class="cs-script-header">/g,'<div style="font-size:12px;font-weight:700;color:#dde3f0;background:#1a2442;border-left:3px solid #c49a20;padding:8px 12px;margin:18px 0 0 0;border-radius:4px 4px 0 0;letter-spacing:.03em;font-family:Poppins,sans-serif">');
  h = h.replace(/<div class="cs-script-spacer">/g,'<div style="height:16px;display:block">');
  // ── Approved Language ──
  h = h.replace(/<div class="cs-mode-label cs-approved-label">/g,'<div style="font-size:10px;font-weight:700;letter-spacing:.07em;padding:5px 12px;display:block;background:#052e16;color:#22c55e;border-left:3px solid #22c55e;margin:0;font-family:Poppins,sans-serif">');
  h = h.replace(/<div class="cs-approved-item">/g,'<div style="display:flex;align-items:flex-start;gap:8px;padding:8px 12px;background:rgba(5,46,22,0.4);border-left:3px solid #22c55e;margin:1px 0;font-family:Poppins,sans-serif">');
  h = h.replace(/<span class="cs-approved-tag">/g,'<span style="font-size:14px;color:#22c55e;flex-shrink:0;margin-top:1px">');
  h = h.replace(/<span class="cs-approved-text">/g,'<span style="font-size:13px;color:#86efac;line-height:1.6;font-weight:500">');
  // ── Forbidden Language ──
  h = h.replace(/<div class="cs-mode-label cs-forbidden-label">/g,'<div style="font-size:10px;font-weight:700;letter-spacing:.07em;padding:5px 12px;display:block;background:#2d0a0a;color:#ef4444;border-left:3px solid #ef4444;margin:0;font-family:Poppins,sans-serif">');
  h = h.replace(/<div class="cs-forbidden-item">/g,'<div style="display:flex;align-items:flex-start;gap:8px;padding:8px 12px;background:rgba(45,10,10,0.4);border-left:3px solid #ef4444;margin:1px 0;font-family:Poppins,sans-serif">');
  h = h.replace(/<span class="cs-forbidden-tag">/g,'<span style="font-size:14px;color:#ef4444;flex-shrink:0;margin-top:1px">');
  h = h.replace(/<span class="cs-forbidden-text">/g,'<span style="font-size:13px;color:#fca5a5;line-height:1.6">');
  // ── Subheads ──
  h = h.replace(/<div class="cs-subhead">/g,'<div style="font-size:10.5px;font-weight:800;letter-spacing:.09em;color:#c49a20;margin:20px 0 8px;text-transform:uppercase;padding-bottom:5px;border-bottom:1px solid rgba(196,154,32,.2);font-family:Poppins,sans-serif">');
  // ── Tables ──
  h = h.replace(/<table class="cs-table">/g,'<table style="width:100%;border-collapse:collapse;margin:14px 0 18px;font-size:12.5px;font-family:Poppins,sans-serif">');
  h = h.replace(/<th>/g,'<th style="background:#1a2442;color:#dde3f0;font-weight:700;padding:9px 12px;text-align:left;border:1px solid #2a3a5c;font-size:11.5px;letter-spacing:.04em">');
  h = h.replace(/<td>/g,'<td style="padding:9px 12px;border:1px solid #2a3a5c;color:#94a3b8;vertical-align:top;line-height:1.6">');
  // ── Gold strong ──
  h = h.replace(/<strong class="cs-strong-gold">/g,'<strong style="color:#fcd34d;font-weight:700;font-size:14px;display:inline-block;margin-top:12px;margin-bottom:4px">');
  // ── Alert boxes ──
  h = h.replace(/<div class="cs-alert-box">/g,'<div style="background:rgba(196,154,32,0.1);border-left:4px solid #c49a20;padding:16px;margin:20px 0;border-radius:0 8px 8px 0;font-family:Poppins,sans-serif">');
  h = h.replace(/<div class="cs-alert-box cs-alert-danger">/g,'<div style="background:rgba(239,68,68,0.1);border-left:4px solid #ef4444;padding:16px;margin:20px 0;border-radius:0 8px 8px 0;font-family:Poppins,sans-serif">');
  h = h.replace(/<span class="cs-alert-title">/g,'<span style="display:block;font-size:13px;font-weight:800;color:#facc15;margin-bottom:8px;letter-spacing:.05em">');
  h = h.replace(/<span class="cs-alert-text">/g,'<span style="font-size:12.5px;line-height:1.6;color:#dde3f0;margin:0">');
  return h;
}

function renderSStudy() {
  const s = getStaff(ST.staffId);
  const el = document.getElementById('s-study');
  if (!s) { el.innerHTML = '<div class="empty-state"><div class="empty-ttl">Profile not found</div></div>'; return; }

  const curBelt = s.belt;
  const nxt = nextBelt(curBelt);
  const bColor = BELT_CLR[curBelt] || 'var(--gold)';
  const nxtColor = nxt ? (BELT_CLR[nxt] || 'var(--txt2)') : 'var(--txt3)';

  // ── Active Practice Test ─────────────────────────────────────────
  if (PRACTICE_STATE.active || PRACTICE_STATE.complete) {
    // Complete screen
    if (PRACTICE_STATE.complete) {
      const ps = PRACTICE_STATE;
      const pct = Math.round((ps.score / ps.questions.length) * 100);
      const elapsed = Math.round((Date.now() - ps.startTime) / 60000);
      const grade = pct >= 90 ? 'EXCELLENT' : pct >= 80 ? 'PASS' : pct >= 70 ? 'REVIEW' : 'RETAKE';
      const gc = pct >= 80 ? 'var(--ok)' : pct >= 70 ? 'var(--warn)' : 'var(--err)';
      const wrongs = ps.answers.filter(a => !a.correct);
      const otherMode = ps.mode === 'knowledge' ? 'simulation' : 'knowledge';
      const scores = getPracticeScores(s.id, ps.belt) || {};
      const otherScore = scores[otherMode] || 0;
      const bothPassed = pct >= 80 && otherScore >= 80;
      const nxtBelt = nextBelt(ps.belt);
      el.innerHTML = `
        <div style="max-width:620px;margin:0 auto">
          <div style="text-align:center;padding:20px 0 16px">
            <div style="font-size:60px;font-weight:900;color:${gc};line-height:1">${pct}%</div>
            <div style="font-size:15px;font-weight:800;color:${gc};margin:5px 0 3px">${grade}</div>
            <div style="font-size:11.5px;color:var(--txt3)">${ps.belt} Belt ${ps.mode==='knowledge'?'Knowledge Test':'Simulation'} &bull; ${ps.score}/${ps.questions.length} correct &bull; ${elapsed} min</div>
          </div>
          <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">
            <div style="background:${pct>=80?'rgba(34,197,94,.06)':'rgba(239,68,68,.06)'};border:1px solid ${pct>=80?'rgba(34,197,94,.2)':'rgba(239,68,68,.2)'};border-radius:var(--rs);padding:12px;text-align:center">
              <div style="font-size:10px;font-weight:700;color:var(--txt3);margin-bottom:4px">${ps.mode==='knowledge'?'KNOWLEDGE':'SIMULATION'}</div>
              <div style="font-size:26px;font-weight:900;color:${pct>=80?'var(--ok)':'var(--err)'}">${pct}%</div>
              <div style="font-size:10px;color:var(--txt3)">${pct>=80?'Threshold met':'Below 80%'}</div>
            </div>
            <div style="background:${otherScore>=80?'rgba(34,197,94,.06)':otherScore>0?'rgba(245,158,11,.06)':'var(--s2)'};border:1px solid ${otherScore>=80?'rgba(34,197,94,.2)':otherScore>0?'rgba(245,158,11,.2)':'var(--bdr)'};border-radius:var(--rs);padding:12px;text-align:center">
              <div style="font-size:10px;font-weight:700;color:var(--txt3);margin-bottom:4px">${ps.mode==='knowledge'?'SIMULATION':'KNOWLEDGE'}</div>
              <div style="font-size:26px;font-weight:900;color:${otherScore>=80?'var(--ok)':otherScore>0?'var(--warn)':'var(--txt3)'}">${otherScore||'--'}${otherScore?'%':''}</div>
              <div style="font-size:10px;color:var(--txt3)">${otherScore>=80?'Threshold met':otherScore>0?'Below 80%':'Not taken'}</div>
            </div>
          </div>
          ${(bothPassed||canRequestAssessment(s.id,ps.belt)) ? _studyGateBtns(s,nxtBelt,kScore,sScore) : _studyNotPassedMsg(ps.mode,pct)}



          ${wrongs.length?`<div class="card mb14"><div class="card-hd"><div class="card-ttl">Review These</div><span class="pill p-err">${wrongs.length} missed</span></div><div style="max-height:360px;overflow-y:auto">${wrongs.map((a,i)=>`<div style="padding:11px 14px;border-bottom:1px solid var(--bdr)${i===wrongs.length-1?';border-bottom:none':''}"><div style="font-size:11.5px;font-weight:600;color:var(--err);margin-bottom:5px">&#10007; ${a.q.q||a.q.s}</div><div style="font-size:12px;color:var(--ok);line-height:1.65"><span style="font-size:10.5px;font-weight:700;color:var(--txt3)">ANSWER: </span>${a.q.a||a.q.answer}</div></div>`).join('')}</div></div>`:`<div style="background:rgba(34,197,94,.06);border:1px solid rgba(34,197,94,.2);border-radius:var(--r);padding:12px;text-align:center;margin-bottom:14px;font-size:13px;font-weight:700;color:var(--ok)">Perfect score.</div>`}
          <div style="display:flex;gap:10px;flex-wrap:wrap">
            <button class="btn btn-gold" style="flex:1;justify-content:center" onclick="startPracticeTest('${ps.belt}','${ps.mode}')">Retake Test</button>
            <button class="btn btn-ghost" style="flex:1;justify-content:center" onclick="resetPractice()">Back to Study Hub</button>
          </div>
        </div>`;
      return;
    }
    // Active test
    const ps = PRACTICE_STATE;
    const q = ps.questions[ps.current];
    const prog = Math.round(ps.current / ps.questions.length * 100);
    const diff = q.diff || 'medium';
    const dc = diff==='easy'?'var(--ok)':diff==='hard'?'var(--err)':'var(--warn)';
    const isSim = ps.mode === 'simulation';
    el.innerHTML = `
      <div style="max-width:660px;margin:0 auto">
        <div style="display:flex;align-items:center;justify-content:space-between;margin-bottom:12px;flex-wrap:wrap;gap:8px">
          <div>
            <div style="font-size:13px;font-weight:700;color:${BELT_CLR[ps.belt]}">${ps.belt} Belt: ${isSim?'Simulation Scenarios':'Knowledge Test'}</div>
            <div style="font-size:11px;color:var(--txt3)">Question ${ps.current+1} of ${ps.questions.length}</div>
          </div>
          <button class="btn btn-ghost btn-sm" onclick="resetPractice()">Exit</button>
        </div>
        <div style="height:5px;background:var(--s3);border-radius:3px;overflow:hidden;margin-bottom:18px">
          <div style="height:100%;width:${prog}%;background:${BELT_CLR[ps.belt]};border-radius:3px;transition:width .3s"></div>
        </div>
        <div style="background:var(--s1);border:1px solid var(--bdr2);border-radius:var(--r);padding:18px;margin-bottom:14px">
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:10px;flex-wrap:wrap">
            <span style="font-size:9px;font-weight:700;letter-spacing:.08em;color:var(--txt3)">${isSim?'SCENARIO':'KNOWLEDGE'}</span>
            <span style="font-size:9px;font-weight:700;padding:2px 8px;border-radius:10px;background:${dc}18;color:${dc}">${diff.toUpperCase()}</span>
          </div>
          <div style="font-size:14.5px;font-weight:600;line-height:1.65;margin-bottom:14px">${isSim?q.s:q.q}</div>
          <div style="background:var(--s2);border:1px dashed var(--bdr2);border-radius:var(--rs);padding:12px;font-size:12px;color:var(--txt3);font-style:italic;min-height:56px">Think through your answer, then reveal below.</div>
        </div>
        <div id="study-reveal" style="display:none;background:rgba(34,197,94,.04);border:1px solid rgba(34,197,94,.2);border-radius:var(--r);padding:14px;margin-bottom:12px">
          <div style="font-size:10px;font-weight:700;color:var(--ok);letter-spacing:.06em;margin-bottom:7px">MODEL ANSWER</div>
          <div style="font-size:13px;color:var(--txt);line-height:1.7">${isSim?q.answer:q.a}</div>
        </div>
        <div id="study-grade-btns" style="display:none;gap:10px;flex-wrap:wrap;margin-bottom:8px">
          <button class="btn btn-ok" style="flex:1;justify-content:center;padding:11px" onclick="submitPracticeAnswer('correct')">I got this right &#10003;</button>
          <button class="btn btn-err" style="flex:1;justify-content:center;padding:11px" onclick="submitPracticeAnswer('wrong')">I need to review &#10007;</button>
        </div>
        <div id="study-reveal-btn" style="display:flex">
          <button class="btn btn-gold" style="flex:1;justify-content:center;padding:11px" onclick="document.getElementById('study-reveal').style.display='block';document.getElementById('study-grade-btns').style.display='flex';document.getElementById('study-reveal-btn').style.display='none'">Reveal Answer</button>
        </div>
      </div>`;
    return;
  }

  // ── Main Study Hub ────────────────────────────────────────────────
  if (!window._studyTab) window._studyTab = 'curriculum';
  if (!window._studySectionIdx) window._studySectionIdx = 0;
  const tab = window._studyTab;

  const bCurriculum = FULL_CURRICULUM_DATA.belts[curBelt] || [];
  const bank = FULL_QUESTION_BANKS[curBelt];
  const kCount = bank ? Math.min(bank.knowledge.length, 100) : 0;
  const sCount = bank ? Math.min(bank.simulation.length, 100) : 0;
  const scores = getPracticeScores(s.id, curBelt) || {};
  const kScore = scores.knowledge || 0;
  const sScore = scores.simulation || 0;
  const bothPassed = kScore >= 80 && sScore >= 80;

  function tabBtn(id, label) {
    const active = tab === id;
    return `<div style="padding:8px 16px;border-radius:var(--rs);font-size:12.5px;font-weight:${active?'700':'500'};cursor:pointer;white-space:nowrap;background:${active?'var(--gold-bg)':'transparent'};color:${active?'var(--gold)':'var(--txt2)'};border:1px solid ${active?'var(--gold-bd)':'transparent'};transition:.12s;flex-shrink:0" onclick="window._studyTab='${id}';window._studySectionIdx=0;renderSStudy()">${label}</div>`;
  }

  let tabContent = '';

  // ── CURRICULUM TAB ────────────────────────────────────────────────
  if (tab === 'curriculum') {
    const secIdx = Math.min(window._studySectionIdx || 0, bCurriculum.length - 1);
    const curSection = bCurriculum[secIdx] || {title:'', html:''};
    const beltKey = curBelt;
    const totalSec = bCurriculum.length;

    const navItems = bCurriculum.map((sec, i) => `
      <div style="padding:8px 12px;border-radius:var(--rs);cursor:pointer;font-size:12px;font-weight:${i===secIdx?'700':'400'};color:${i===secIdx?'var(--gold)':'var(--txt2)'};background:${i===secIdx?'var(--gold-bg)':'transparent'};border-left:2px solid ${i===secIdx?'var(--gold)':'transparent'};transition:.12s;display:flex;align-items:center;gap:6px" onclick="window._studySectionIdx=${i};renderSStudy()" title="${sec.title.replace(/"/g,'&quot;')}">
        <span style="flex:1;min-width:0;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${sec.title}</span>
        ${l3BuildNavDot('belt', beltKey, i, i===secIdx)}
      </div>
    `).join('');

    tabContent = `
      ${l3BuildProgressHeader('belt', beltKey, totalSec)}
      <div style="display:flex;gap:0;border:1px solid var(--bdr);border-radius:0 0 var(--r) var(--r);overflow:hidden;background:var(--bg)">
        <!-- Section nav sidebar -->
        <div style="width:200px;min-width:160px;border-right:1px solid var(--bdr);overflow-y:auto;max-height:70vh;flex-shrink:0;background:var(--s1);padding:8px 4px">
          ${navItems}
        </div>
        <!-- Section content -->
        <div style="flex:1;min-width:0;overflow-y:auto;max-height:70vh;padding:20px 22px">
          <div style="font-size:11px;font-weight:700;color:var(--gold);letter-spacing:.07em;margin-bottom:8px;text-transform:uppercase">${curSection.title}</div>
          <div class="cs-body">${_styleCurriculumHTML(curSection.html)}</div>
          ${l3BuildMarkBtn('belt', beltKey, secIdx)}
          <!-- Prev/Next nav -->
          <div style="display:flex;justify-content:space-between;margin-top:20px;padding-top:14px;border-top:1px solid var(--bdr)">
            ${secIdx > 0 ? `<button class="btn btn-ghost btn-sm" onclick="window._studySectionIdx=${secIdx-1};renderSStudy()">&#8592; ${bCurriculum[secIdx-1].title.substring(0,30)}</button>` : '<span></span>'}
            ${secIdx < bCurriculum.length-1 ? `<button class="btn btn-ghost btn-sm" onclick="window._studySectionIdx=${secIdx+1};renderSStudy()">${bCurriculum[secIdx+1].title.substring(0,30)} &#8594;</button>` : '<span class="pill p-ok">Guide Complete &#10003;</span>'}
          </div>
        </div>
      </div>`;

  // ── SCRIPTS TAB ──────────────────────────────────────────────────
  } else if (tab === 'scripts') {
    // Extract scripts section from FULL_CURRICULUM_DATA for this belt
    const beltData = FULL_CURRICULUM_DATA.belts[curBelt] || [];
    // Find script-related sections
    const scriptSections = beltData.filter(sec => 
      /script/i.test(sec.title) || /approved language/i.test(sec.title) || /forbidden language/i.test(sec.title)
    );
    const allScriptHTML = scriptSections.length > 0 
      ? scriptSections.map(sec => `
          <div style="margin-bottom:20px">
            <div style="font-size:11px;font-weight:700;color:${bColor};letter-spacing:.06em;text-transform:uppercase;margin-bottom:10px">${sec.title}</div>
            <div class="cs-body">${_styleCurriculumHTML(sec.html)}</div>
          </div>`).join('')
      : beltData.filter(sec => sec.title.match(/section [45]/i) || /two.*script|script.*belt/i.test(sec.title))
          .map(sec => `<div style="margin-bottom:20px"><div style="font-size:11px;font-weight:700;color:${bColor};letter-spacing:.06em;text-transform:uppercase;margin-bottom:10px">${sec.title}</div><div class="cs-body">${_styleCurriculumHTML(sec.html)}</div></div>`).join('');
    
    tabContent = `
      <div style="background:${bColor}08;border:1px solid ${bColor}20;border-radius:var(--rs);padding:12px 16px;margin-bottom:14px">
        <div style="font-size:12.5px;font-weight:700;color:${bColor};margin-bottom:4px">${curBelt} Belt Scripts: Master These</div>
        <div style="font-size:12px;color:var(--txt2)">You must be able to deliver every script below from memory, with the exact approved language, under pressure. Knowing the forbidden phrases is equally important – know why each one fails.</div>
      </div>
      ${allScriptHTML || '<div class="empty-state"><div class="empty-ttl">Script content loading</div><div class="empty-desc">Navigate to the Full Curriculum tab and open the Scripts section.</div></div>'}
      <div style="background:rgba(196,154,32,.05);border:1px solid var(--gold-bd);border-radius:var(--rs);padding:11px 14px;margin-top:14px">
        <div style="font-size:10.5px;font-weight:700;color:var(--gold);margin-bottom:5px">SCRIPT MASTERY STANDARD</div>
        <div style="font-size:12px;color:var(--txt2);line-height:1.6">At assessment you will deliver scripts without notes, under real conditions, with the exact approved language. Practice saying each script out loud until the words are automatic. The forbidden language section is tested equally – you must be able to identify any forbidden phrase and explain why it fails patient safety.</div>
      </div>`;

  // ── OBSERVATION READY TAB ─────────────────────────────────────────
  } else if (tab === 'observation') {
    const obsData = BELT_OBSERVATION_CHECKLISTS[curBelt] || {requirement:'', items:[]};
    const staffChecks = s.obsChecklist || {};
    const checkedCount = obsData.items.filter((_,i) => staffChecks[curBelt + '_' + i]).length;
    const totalItems = obsData.items.length;
    const pct = totalItems > 0 ? Math.round(checkedCount / totalItems * 100) : 0;
    const isReady = pct === 100;

    tabContent = `
      <div style="background:${isReady?'rgba(34,197,94,.06)':bColor+'08'};border:1.5px solid ${isReady?'rgba(34,197,94,.3)':bColor+'30'};border-radius:var(--r);padding:14px 16px;margin-bottom:16px">
        <div style="display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:10px;margin-bottom:8px">
          <div>
            <div style="font-size:13.5px;font-weight:700;color:${isReady?'var(--ok)':bColor}">${isReady?'Ready for Observation ✓':'Observation Readiness Check'}</div>
            <div style="font-size:11.5px;color:var(--txt2);margin-top:2px">${isReady?'You have confirmed all competencies. Notify your Lead to schedule your observation.':'Check off each item when you can do it without notes. Only check when you are truly ready.'}</div>
          </div>
          <div style="text-align:center">
            <div style="font-size:28px;font-weight:900;color:${isReady?'var(--ok)':pct>=70?'var(--warn)':'var(--txt3)'}">${pct}%</div>
            <div style="font-size:10px;color:var(--txt3)">${checkedCount}/${totalItems}</div>
          </div>
        </div>
        <div style="height:6px;background:var(--s3);border-radius:3px;overflow:hidden">
          <div style="height:100%;width:${pct}%;background:${isReady?'var(--ok)':pct>=70?'var(--warn)':bColor};border-radius:3px;transition:width .4s"></div>
        </div>
      </div>

      <div style="background:var(--s2);border:1px solid var(--bdr);border-radius:var(--r);padding:12px 14px;margin-bottom:14px">
        <div style="font-size:10px;font-weight:700;color:var(--txt3);letter-spacing:.06em;margin-bottom:7px">WHAT THE ASSESSOR OBSERVES – LEVEL 3</div>
        <div style="font-size:12.5px;color:var(--txt2);line-height:1.65">${obsData.requirement}</div>
      </div>

      <div style="margin-bottom:10px;display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:8px">
        <div style="font-size:12px;font-weight:700">Self-Assessment Checklist</div>
        ${checkedCount > 0 ? `<button class="btn btn-ghost btn-xs" onclick="clearObsChecklist('${curBelt}')">Reset all</button>` : ''}
      </div>

      <div style="display:flex;flex-direction:column;gap:8px;margin-bottom:16px">
        ${obsData.items.map((item, i) => {
          const key = curBelt + '_' + i;
          const checked = !!staffChecks[key];
          return `<div style="display:flex;align-items:flex-start;gap:10px;padding:10px 12px;background:${checked?'rgba(34,197,94,.04)':'var(--s2)'};border:1px solid ${checked?'rgba(34,197,94,.2)':'var(--bdr)'};border-radius:var(--rs);cursor:pointer;transition:.15s" onclick="toggleObsCheck('${curBelt}',${i})">
            <div style="width:20px;height:20px;border-radius:5px;border:2px solid ${checked?'var(--ok)':'var(--bdr2)'};background:${checked?'var(--ok)':'transparent'};display:flex;align-items:center;justify-content:center;flex-shrink:0;margin-top:1px;transition:.15s">
              ${checked?'<svg viewBox="0 0 12 12" fill="none" width="11" height="11"><path d="M2 6l3 3 5-5" stroke="#fff" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/></svg>':''}
            </div>
            <div style="font-size:12.5px;color:${checked?'var(--txt2)':'var(--txt)'};line-height:1.6;text-decoration:${checked?'none':'none'}">${item}</div>
          </div>`;
        }).join('')}
      </div>

      ${isReady ? `<div style="background:rgba(34,197,94,.06);border:1.5px solid rgba(34,197,94,.3);border-radius:var(--r);padding:14px 16px;text-align:center">
        <div style="font-size:16px;margin-bottom:8px">🎯</div>
        <div style="font-size:14px;font-weight:700;color:var(--ok);margin-bottom:5px">All Competencies Confirmed</div>
        <div style="font-size:12px;color:var(--txt2);margin-bottom:12px">You have checked off every item on the ${curBelt} Belt observation readiness list. Let your Lead or Educator know you are ready to schedule your Level 3 Observation assessment.</div>
      </div>` : ''}`;

  // ── PRACTICE TAB ──────────────────────────────────────────────────
  } else if (tab === 'practice') {
    tabContent = `
      <div style="text-align:center;padding:6px 0 16px">
        <div style="font-size:14px;font-weight:800;margin-bottom:5px">SIPS Intelligence Practice Module</div>
        <div style="font-size:12px;color:var(--txt2)">Score 80%+ on both tests to unlock your real gate assessment request.</div>
      </div>
      ${bothPassed?`<div style="background:rgba(34,197,94,.06);border:1.5px solid rgba(34,197,94,.3);border-radius:var(--r);padding:12px 16px;margin-bottom:14px;display:flex;align-items:center;gap:10px"><div style="font-size:20px">&#9989;</div><div><div style="font-size:13px;font-weight:700;color:var(--ok)">Assessment Request Unlocked</div><div style="font-size:11.5px;color:var(--txt2)">Both tests at 80%+. Request your ${nxt||curBelt} Belt gate assessments.</div></div></div>`:kScore>0||sScore>0?`<div style="background:rgba(245,158,11,.05);border:1px solid rgba(245,158,11,.2);border-radius:var(--rs);padding:10px 14px;margin-bottom:14px"><div style="display:flex;gap:16px;font-size:12px;color:var(--txt2)"><span>Knowledge: <strong style="color:${kScore>=80?'var(--ok)':'var(--warn)'}">${kScore||'--'}%</strong> ${kScore>=80?'✓':'(need 80%)'}</span><span>Simulation: <strong style="color:${sScore>=80?'var(--ok)':'var(--warn)'}">${sScore||'--'}%</strong> ${sScore>=80?'✓':'(need 80%)'}</span></div></div>`:''}
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:16px">
        <div style="background:var(--s2);border:1.5px solid ${kScore>=80?'rgba(34,197,94,.4)':bColor+'30'};border-radius:var(--r);padding:18px;text-align:center;cursor:pointer" onclick="startPracticeTest('${curBelt}','knowledge')">
          ${kScore>=80?'<div style="font-size:18px;margin-bottom:4px">&#9989;</div>':'<div style="font-size:28px;margin-bottom:8px">&#128203;</div>'}
          <div style="font-size:13.5px;font-weight:700;margin-bottom:4px">Knowledge Test</div>
          <div style="font-size:11px;color:var(--txt3);margin-bottom:8px">${kCount} questions – scripts, vocab, protocols</div>
          ${kScore>0?`<div style="font-size:12px;font-weight:700;color:${kScore>=80?'var(--ok)':'var(--warn)'};margin-bottom:8px">Best: ${kScore}%</div>`:''}
          <button class="btn ${kScore>=80?'btn-ghost':'btn-gold'} btn-sm" style="width:100%;justify-content:center">${kScore>=80?'Retake':'Start Knowledge Test'}</button>
        </div>
        <div style="background:var(--s2);border:1.5px solid ${sScore>=80?'rgba(34,197,94,.4)':bColor+'30'};border-radius:var(--r);padding:18px;text-align:center;cursor:pointer" onclick="startPracticeTest('${curBelt}','simulation')">
          ${sScore>=80?'<div style="font-size:18px;margin-bottom:4px">&#9989;</div>':'<div style="font-size:28px;margin-bottom:8px">&#127917;</div>'}
          <div style="font-size:13.5px;font-weight:700;margin-bottom:4px">Simulation Scenarios</div>
          <div style="font-size:11px;color:var(--txt3);margin-bottom:8px">${sCount} scenarios – real situations, scripts applied</div>
          ${sScore>0?`<div style="font-size:12px;font-weight:700;color:${sScore>=80?'var(--ok)':'var(--warn)'};margin-bottom:8px">Best: ${sScore}%</div>`:''}
          <button class="btn ${sScore>=80?'btn-ghost':'btn-gold'} btn-sm" style="width:100%;justify-content:center">${sScore>=80?'Retake':'Start Scenarios'}</button>
        </div>
      </div>
      ${bothPassed&&nxt ? _practiceGateBtns(s,nxt) : ''}
      ${nxt&&FULL_QUESTION_BANKS[nxt]?`<div class="card"><div class="card-hd"><div class="card-ttl">Preview Next Belt Practice</div><span class="pill p-muted">${nxt} Belt</span></div><div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;padding:12px 14px"><div style="background:${nxtColor}08;border:1px solid ${nxtColor}20;border-radius:var(--rs);padding:12px;text-align:center;cursor:pointer" onclick="startPracticeTest('${nxt}','knowledge')"><div style="font-size:12.5px;font-weight:700;color:${nxtColor};margin-bottom:3px">${nxt} Belt Knowledge</div><div style="font-size:11px;color:var(--txt3)">${Math.min(FULL_QUESTION_BANKS[nxt].knowledge.length,100)} questions</div></div><div style="background:${nxtColor}08;border:1px solid ${nxtColor}20;border-radius:var(--rs);padding:12px;text-align:center;cursor:pointer" onclick="startPracticeTest('${nxt}','simulation')"><div style="font-size:12.5px;font-weight:700;color:${nxtColor};margin-bottom:3px">${nxt} Belt Simulation</div><div style="font-size:11px;color:var(--txt3)">${Math.min(FULL_QUESTION_BANKS[nxt].simulation.length,100)} scenarios</div></div></div></div>`:''}`;
  }

  // ── Hub shell ─────────────────────────────────────────────────────
  el.innerHTML = `
    <div class="stat-grid mb12" style="grid-template-columns:repeat(auto-fill,minmax(120px,1fr))">
      <div class="stat-card"><div class="stat-accent" style="background:${bColor}"></div>
        <div class="stat-lbl">Current Belt</div>
        <div class="stat-val" style="color:${bColor};font-size:18px;padding-top:2px">${curBelt}</div>
      </div>
      ${nxt?`<div class="stat-card"><div class="stat-accent" style="background:${nxtColor}"></div>
        <div class="stat-lbl">Advancing To</div>
        <div class="stat-val" style="color:${nxtColor};font-size:18px;padding-top:2px">${nxt}</div>
      </div>`:''}
      <div class="stat-card"><div class="stat-accent" style="background:var(--gold)"></div>
        <div class="stat-lbl">Practice</div>
        <div class="stat-val" style="color:var(--gold)">${kScore>0||sScore>0?Math.max(kScore,sScore)+'%':'--'}</div>
        <div class="stat-sub">Best score</div>
      </div>
    </div>
    <div style="display:flex;gap:4px;overflow-x:auto;padding-bottom:4px;margin-bottom:16px;-webkit-overflow-scrolling:touch">
      ${tabBtn('curriculum','Full Curriculum')}
      ${tabBtn('scripts','Scripts to Master')}
      ${tabBtn('observation','Observation Ready')}
      ${tabBtn('practice','Practice Tests')}
    </div>
    ${tabContent}`;
}

function renderSHistory(){
  const s=getStaff(ST.staffId);
  if(!s)return;
  const proj=generateProjection(s);
  document.getElementById('s-history').innerHTML=`
    <div class="card mb16">
      <div class="card-hd"><div class="card-ttl">My Projection</div><span class="pill ${proj.confidence==='High'?'p-ok':proj.confidence==='Medium'?'p-warn':'p-muted'}">${proj.confidence} Confidence</span></div>
      <div class="card-body">
        <div style="padding:12px;background:var(--s2);border-radius:var(--rs);border-left:3px solid var(--gold);font-size:13px;line-height:1.6;margin-bottom:16px">${proj.summary}</div>
        ${proj.nextBelt?`
        <div class="g2" style="gap:10px;margin-bottom:16px">
          <div style="background:var(--s2);border-radius:var(--rs);padding:14px;text-align:center">
            <div style="font-size:26px;font-weight:800;color:var(--gold)">${proj.projectedWeeks||'--'}</div>
            <div style="font-size:10px;color:var(--txt3);text-transform:uppercase;letter-spacing:.08em">Weeks to ${proj.nextBelt}</div>
          </div>
          <div style="background:var(--s2);border-radius:var(--rs);padding:14px;text-align:center">
            <div style="font-size:26px;font-weight:800;color:${proj.promotionRecommended?'var(--gold)':'var(--txt3)'}">${proj.promotionRecommended?'YES':'NO'}</div>
            <div style="font-size:10px;color:var(--txt3);text-transform:uppercase;letter-spacing:.08em">Promo Eligible</div>
          </div>
        </div>
        <div class="irow"><div class="ilbl">Gates remaining</div><div class="ival">${proj.gatesLeft} of 3</div></div>
        <div class="irow"><div class="ilbl">Window wait</div><div class="ival">${proj.waitWeeks} week${proj.waitWeeks!==1?'s':''}</div></div>
        <div class="irow"><div class="ilbl">Promotion recommended</div><div class="ival">${proj.promotionRecommended?'<span class="pill p-gold">Yes</span>':'<span class="pill p-muted">Not yet</span>'}</div></div>
        `:''}
      </div>
    </div>
    <div class="card">
      <div class="card-hd"><div class="card-ttl">Assessment History</div><span class="pill p-muted">${(s.history||[]).length} records</span></div>
      <div class="card-body">
        ${s.history&&s.history.length?`<div class="tl">${s.history.slice().reverse().map(h=>`<div class="tl-item"><div class="tl-dot" style="background:${h.res==='pass'?'rgba(34,197,94,.15)':'rgba(239,68,68,.15)'};color:${h.res==='pass'?'var(--ok)':'var(--err)'}">${h.res==='pass'?ICO.check:ICO.x}</div><div><div class="tl-date">${h.dt} &bull; ${beltBadge(h.belt)}</div><div class="tl-txt">${h.type}: <strong style="color:${h.res==='pass'?'var(--ok)':'var(--err)'}">${h.res.charAt(0).toUpperCase()+h.res.slice(1)}</strong></div></div></div>`).join('')}</div>`:'<div style="color:var(--txt3);font-size:12px;text-align:center;padding:20px">No assessment history yet.</div>'}
      </div>
    </div>`;
}

// ============================================================ X DASHBOARD (System Admin)
function renderXDashboard(){
  const sid=ST.curSystemId;
  const facs=systemFacs(sid);
  const allSt=systemStaff(sid);
  const n=allSt.length;
  const aboveG=allSt.filter(s=>beltIdx(s.belt)>=2).length;
  const netPct=n?Math.round(aboveG/n*100):0;
  document.getElementById('x-dashboard').innerHTML=`
    <div class="stat-grid">
      <div class="stat-card"><div class="stat-accent" style="background:var(--gold)"></div><div class="stat-lbl">Facilities</div><div class="stat-val" style="color:var(--gold)">${facs.length}</div><div class="stat-sub">In your system</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--blue)"></div><div class="stat-lbl">Total Staff</div><div class="stat-val" style="color:var(--blue)">${n}</div><div class="stat-sub">System-wide enrolled</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--ok)"></div><div class="stat-lbl">Network Green Belt %</div><div class="stat-val" style="color:var(--ok)">${netPct}%</div><div class="stat-sub">${aboveG} of ${n} at Green+</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--warn)"></div><div class="stat-lbl">Pending Assessments</div><div class="stat-val" style="color:var(--warn)">${DB.queue.filter(q=>facs.find(f=>f.id===(q.facility_id||q.fid))).length}</div><div class="stat-sub">Awaiting SBD review</div></div>
    </div>
    <div class="card mb16">
      <div class="card-hd"><div class="card-ttl">Facility Comparison</div></div>
      <div style="overflow-x:auto"><table class="tbl tbl-static" style="min-width:480px">
        <thead><tr><th>Rank</th><th>Facility</th><th>Staff</th><th>Green Belt %</th><th>Avg Belt</th><th>Health Grade</th></tr></thead>
        <tbody>${[...facs].sort((a,b)=>facStats(b.id).greenPct-facStats(a.id).greenPct).map((f,i)=>{
          const fs=facStats(f.id);
          const grade=fs.greenPct>=90?'A':fs.greenPct>=75?'B':fs.greenPct>=60?'C+':fs.greenPct>=40?'C':'D';
          const gc=fs.greenPct>=75?'var(--ok)':fs.greenPct>=50?'var(--warn)':'var(--err)';
          return`<tr style="cursor:pointer" onclick="goXFacility('${f.id}')"><td><div class="rank ${i===0?'r1':i===1?'r2':i===2?'r3':'rn'}">${i+1}</div></td><td class="fw7">${f.name}</td><td>${fs.n}</td><td style="color:${gc};font-weight:700">${fs.greenPct}%</td><td>${fs.avgBelt}</td><td style="font-weight:800;color:${gc}">${grade}</td></tr>`;}).join('')}
        </tbody>
      </table></div>
    </div>`;
}

