function openBeltOverrideModal(staffId, context){
  const s = getStaff(staffId); if(!s) return;
  const overrideReasons = [
    'Assessor Error Correction',
    'Administrative Override',
    'Performance-Based Promotion',
    'Performance-Based Demotion',
    'Training Reset',
    'Special Circumstance'
  ];
  openModal(`Override Belt: ${fullName(s)}`,`
    <div class="modal-body">
      <div style="background:var(--s2);border:1px solid var(--bdr);border-radius:var(--rs);padding:12px 14px;margin-bottom:14px;display:flex;gap:12px;align-items:center">
        <div style="width:40px;height:40px;border-radius:10px;background:${BELT_CLR[s.belt]||'#888'}22;border:2px solid ${BELT_CLR[s.belt]||'#888'};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:${BELT_CLR[s.belt]||'#888'};flex-shrink:0">${userInitials(s)}</div>
        <div>
          <div style="font-size:13.5px;font-weight:700">${fullName(s)}</div>
          <div style="font-size:11.5px;color:var(--txt2)">${s.role} &bull; ${s.belt} Belt</div>
          <div style="margin-top:4px">${beltBadge(s.belt,s)}</div>
        </div>
      </div>

      <div style="background:rgba(196,154,32,.07);border:1px solid var(--gold-bd);border-radius:var(--rs);padding:10px 14px;margin-bottom:14px;font-size:11.5px;color:var(--txt2);line-height:1.5">
        <strong style="color:var(--gold)">&#x1F6E1; Master Admin Override</strong><br>
        This action bypasses the normal assessment/gate system. The belt change takes effect immediately and is logged in the staff member's permanent audit trail.
      </div>

      <div class="form-group">
        <label class="form-label">New Belt Level *</label>
        <select class="form-select" id="bo-belt" onchange="(function(){
          var sel=document.getElementById('bo-belt');
          var dir=document.getElementById('bo-direction');
          var warn=document.getElementById('bo-demote-warn');
          if(!sel||!dir) return;
          var cur=${beltIdx(s.belt)};
          var nw=parseInt(sel.value);
          if(nw>cur){dir.innerHTML='<span style=\"color:var(--ok);font-weight:700\">&#x2B06; PROMOTION</span>';warn.style.display='none';}
          else if(nw<cur){dir.innerHTML='<span style=\"color:var(--err);font-weight:700\">&#x2B07; DEMOTION</span>';warn.style.display='block';}
          else{dir.innerHTML='<span style=\"color:var(--txt3)\">No change</span>';warn.style.display='none';}
        })()">
          ${BELT_ORDER.map((b,i)=>`<option value="${i}" ${b===s.belt?'selected':''}>${b} Belt — ${BELT_CERT[b]}</option>`).join('')}
        </select>
        <div id="bo-direction" style="margin-top:6px;font-size:12px"><span style="color:var(--txt3)">Select a different belt</span></div>
      </div>

      <div id="bo-demote-warn" style="display:none;background:rgba(239,68,68,.07);border:1px solid var(--err-bd);border-radius:var(--rs);padding:10px 14px;margin-bottom:14px;font-size:11.5px;color:var(--err);line-height:1.5">
        &#x26A0; <strong>Demotion Warning:</strong> This will reset the staff member's current and advancement assessment gates. Position School progress will be preserved but may become hidden if demoted below Green Belt.
      </div>

      <div class="form-group">
        <label class="form-label">Reason *</label>
        <select class="form-select" id="bo-reason">
          <option value="">Select reason for override</option>
          ${overrideReasons.map(r=>`<option value="${r}">${r}</option>`).join('')}
        </select>
      </div>

      <div class="form-group">
        <label class="form-label">Notes * <span style="color:var(--txt3);font-weight:400">(min 10 characters)</span></label>
        <textarea class="form-input" id="bo-notes" rows="3" placeholder="Explain the reason for this belt override. This is permanently recorded in the audit trail." style="resize:none"></textarea>
      </div>

      <div class="form-group">
        <label class="form-label">Effective Date</label>
        <input type="date" class="form-input" id="bo-date" value="${new Date().toISOString().slice(0,10)}">
      </div>
    </div>
    <div class="modal-ft">
      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-gold" onclick="submitBeltOverride('${s.id}','${context}')">Confirm Override</button>
    </div>`,'modal-md');
}

function submitBeltOverride(staffId, context){
  const s = getStaff(staffId);
  if(!s){ toast('Staff record not found.','err'); return; }
  const beltEl = document.getElementById('bo-belt');
  const reasonEl = document.getElementById('bo-reason');
  const notesEl = document.getElementById('bo-notes');
  const dateEl = document.getElementById('bo-date');
  if(!beltEl||!reasonEl) return;

  const newBeltIdx = parseInt(beltEl.value);
  const newBelt = BELT_ORDER[newBeltIdx];
  const reason = reasonEl.value;
  const notes = (notesEl?.value||'').trim();
  const effectDate = dateEl?.value || new Date().toISOString().slice(0,10);
  const oldBelt = s.belt;
  const adminName = ST.user?.name || ST.name || 'Master Admin';

  // Validation
  if(newBelt === oldBelt){ toast('Belt is unchanged. Select a different belt level.','err'); return; }
  if(!reason){ toast('Please select a reason for the override.','err'); return; }
  if(notes.length < 10){ toast('Notes must be at least 10 characters for the audit trail.','err'); return; }

  const isPromotion = newBeltIdx > beltIdx(oldBelt);
  const dirLabel = isPromotion ? 'promoted' : 'demoted';

  if(!confirm(`${isPromotion?'PROMOTE':'DEMOTE'} ${fullName(s)} from ${oldBelt} Belt to ${newBelt} Belt?\n\nReason: ${reason}\nThis action is logged permanently.`)) return;

  // ── Update staff record ──
  s.belt = newBelt;
  s.since = effectDate;

  if(isPromotion){
    // Promotion: clear advancement gates (they'll advance from new belt now)
    s.nxt = {c:null,s:null,o:null};
  } else {
    // Demotion: reset both current and advancement gates
    s.cur = {c:null,s:null,o:null};
    s.nxt = {c:null,s:null,o:null};
  }

  // ── Audit trail ──
  if(!s.history) s.history = [];
  s.history.unshift({
    dt: effectDate,
    type: 'Belt Override',
    belt: newBelt,
    res: isPromotion ? 'pass' : 'fail',
    note: `${reason}: ${notes} (Override by ${adminName}, ${oldBelt} → ${newBelt})`
  });

  // ── Persist to Supabase ──
  if(IS_LIVE){
    sbFetch(`/rest/v1/staff?id=eq.${s.id}`, {
      method:'PATCH',
      body: { 
        belt: newBelt, 
        since: s.since, 
        history: s.history,
        cur_comp: null, cur_sim: null, cur_obs: null,
        nxt_comp: null, nxt_sim: null, nxt_obs: null
      }
    }).catch(e => handleSyncError(e, 'Belt override sync'));
  }

  closeModal();
  toast(`${fullName(s)} ${dirLabel} from ${oldBelt} to ${newBelt} Belt.`, isPromotion?'ok':'err');

  // ── Re-render ──
  if(context==='admin'){ renderHProfile(staffId,'admin'); }
  else if(context==='h'){ renderHProfile(staffId,'h'); }
  else { renderHProfile(staffId, context); }
}

function renderHProfile(sid,context){
  const s=getStaff(sid);if(!s)return;
  const nb=nextBelt(s.belt);
  const curSt=gatesStatus(s.cur);
  const nxtSt=nb?gatesStatus(s.nxt):null;
  const pctNxt=nxtSt?Math.round(nxtSt.p/3*100):0;
  const gateCard=(lbl,ico,val,canRec,qid)=>{
    const cls=val==='pass'?'g-pass':val==='fail'?'g-fail':'';
    const icoCls=val==='pass'?'pass-ico':val==='fail'?'fail-ico':'empty-ico';
    const icoHtml=val==='pass'?ICO.check:val==='fail'?ICO.x:'<span style="width:10px;height:10px;border-radius:50%;border:1px solid var(--bdr2);display:inline-block"></span>';
    const st=val==='pass'?'<span class="gate-status pass">Passed</span>':val==='fail'?'<span class="gate-status fail">Failed</span>':'<span class="gate-status empty">Not Started</span>';
    return`<div class="gate ${cls}"><div class="gate-ico ${icoCls}">${icoHtml}</div><div class="gate-lbl">${lbl}</div>${st}</div>`;
  };
  const track={White:['SBD Mindset & Discipline','PPE Protocol Standards','Decontamination Orientation','Instrument Sorting & Receiving','Manual Cleaning Procedures','Assembly Zone Introduction','Sterility Assurance Principles','Documentation Standards'],Yellow:['Zone 1 Proficiency','Zone 2 Proficiency','Zone 3 Proficiency','Zone 4 Proficiency','Zone 5 Proficiency','Zone Mastery Selection'],Green:['Quality Science Base Training','Zone Mastery 1','Zone Mastery 2','Zone Mastery 3'],Blue:['Leadership Base Training','Leadership Circle Entry','Position 1 - Quality Assurance','Position 2 - Training Coordinator','Position 3 - Shift Lead','Position 4 - Inventory Lead'],Brown:['Operations Engineering Base','HFL Program','OTIS Mastery'],Black:['Mastery Base Training','Director School','SBD Operator Certification','SBD Project Implementation']};
  const trackItems=(track[s.belt]||[]).map((t,i)=>{const done=i<Math.max(curSt.p,2);const cur=i===Math.max(curSt.p,2);return`<div class="track-item" style="display:flex;gap:8px;align-items:flex-start;padding:8px 0;border-bottom:1px solid var(--bdr)"><div style="width:18px;height:18px;border-radius:50%;flex-shrink:0;display:flex;align-items:center;justify-content:center;font-size:9px;background:${done?'rgba(34,197,94,.15)':cur?'var(--gold-bg)':'var(--s3)'};color:${done?'var(--ok)':cur?'var(--gold)':'var(--txt3)'};">${done?ICO.check:cur?'&rsaquo;':'&bull;'}</div><div><div style="font-size:12.5px;font-weight:500">${t}</div></div></div>`}).join('');
  const backBtn=context==='admin'?`<button class="btn btn-ghost btn-sm mb16" onclick="renderAFacility()"><svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M9 3L5 7l4 4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg> Back to Facility</button>`:
    `<button class="btn btn-ghost btn-sm mb16" onclick="hNav(document.querySelector('[data-view=h-staff]'),'h-staff','Staff Directory')"><svg width="13" height="13" viewBox="0 0 14 14" fill="none"><path d="M9 3L5 7l4 4" stroke="currentColor" stroke-width="1.5" stroke-linecap="round"/></svg> Back to Staff</button>`;
  const html=`${backBtn}
    <div class="prof-banner">
      <div class="prof-av">${userInitials(s)}</div>
      <div style="flex:1">
        <div class="prof-name">${fullName(s)}</div>
        <div class="prof-role">
          ${s.role} &bull; 
          ${(()=>{
            const fac = getFac(s.fid);
            if (!fac) return 'Sterile Processing Department';
            const sys = (window.DB?.hospitalSystems || []).find(sys => sys.id === fac.systemId);
            if (sys) return `${sys.name} &bull; ${fac.name}`;
            return fac.name;
          })()}
        </div>
        <div style="margin-bottom:8px">${beltBadge(s.belt)} <span style="font-size:12px;color:var(--txt3);margin-left:6px">${BELT_CERT[s.belt]}</span></div>
        <div class="prof-meta"><span class="pmeta"><svg width="12" height="12" viewBox="0 0 14 14" fill="none"><rect x="2" y="3" width="10" height="10" rx="1" stroke="currentColor" stroke-width="1.3"/><path d="M5 1v3M9 1v3M2 7h10" stroke="currentColor" stroke-width="1.2" stroke-linecap="round"/></svg>Since ${s.since}</span><span class="pmeta">${daysAt(s.since)} days at current belt</span>${s.stars>0?`<span class="pmeta tc-gold">${'* '.repeat(s.stars).trim()}</span>`:''}</div>
      </div>
      <div style="display:flex;gap:6px;flex-wrap:wrap">
        ${context==='admin'?`<button class="btn btn-gold btn-sm" onclick="openRecordModal('${s.id}')">${ICO.record} Record Assessment</button>`:''}
        ${context==='admin'||context==='h'?`<button class="btn btn-blue btn-sm" onclick="openPromoteModal('${s.id}','${context}')">&#x2B06; Promote</button>`:''}
        <button class="btn btn-ghost btn-sm" onclick="downloadStaffReport('${s.id}')">${ICO.dl} Report</button>
        ${(ST.user&&ST.user.role==='master_admin')?`<button class="btn btn-ghost btn-sm" onclick="openBeltOverrideModal('${s.id}','${context}')" style="border-color:var(--gold-bd);color:var(--gold)"><svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z"/></svg> Override Belt</button>`:''}
        ${context==='admin'&&(ST.user&&ST.user.role==='master_admin')?`<button class="btn btn-err btn-sm" onclick="releaseToFreeAgent('${s.id}')" title="Release staff member to Free Agent Registry" style="margin-left:auto"><svg width="13" height="13" viewBox="0 0 18 18" fill="none"><path d="M12 14H15a1 1 0 001-1V5a1 1 0 00-1-1H12" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><path d="M9 12l3-3-3-3M12 9H5" stroke="currentColor" stroke-width="1.4" stroke-linecap="round" stroke-linejoin="round"/></svg> Release</button>`:''}
      </div>
    </div>
    <div class="g2 mb16">
      <div class="card"><div class="card-hd"><div class="card-ttl">Current Belt Assessments</div><span style="font-size:11.5px;color:${curSt.p===3?'var(--ok)':'var(--warn)'}">${curSt.p}/3 passed</span></div>
        <div class="card-body"><div class="gates">${gateCard('Competency','c',(s.cur||{}).c)}${gateCard('Simulation','s',(s.cur||{}).s)}${gateCard('Observation','o',(s.cur||{}).o)}</div><div style="font-size:11.5px;color:var(--txt3);line-height:1.5">All three assessments required to certify current belt. Marked by SBD-certified assessors only.</div></div>
      </div>
      <div class="card"><div class="card-hd"><div class="card-ttl">Advancing to ${nb||'(Max Belt)'}</div>${nb?`<span style="font-size:11.5px;color:${nxtSt.p===3?'var(--ok)':'var(--txt3)'}">${nxtSt.p}/3 gates</span>`:''}</div>
        <div class="card-body">${nb?`<div class="gates">${gateCard('Competency','c',(s.nxt||{}).c)}${gateCard('Simulation','s',(s.nxt||{}).s)}${gateCard('Observation','o',(s.nxt||{}).o)}</div><div class="prog mt8 mb8" style="height:8px"><div class="prog-fill" style="width:${pctNxt}%;background:var(--gold)"></div></div><div style="font-size:11.5px;color:${nxtSt.rem===0?'var(--ok)':nxtSt.rem===1?'var(--warn)':'var(--txt3)'}"><strong>${nxtSt.p} of 3</strong> advancement gates cleared &bull; ${nxtSt.rem} remaining${nxtSt.rem===0?': Ready for belt review':''}</div>`:'<div class="tc-muted" style="font-size:12px;padding:20px 0;text-align:center">Black Belt is the highest level.</div>'}</div>
      </div>
    </div>
    <div class="g2 mb16">
      <div class="card"><div class="card-hd"><div class="card-ttl">${s.belt} Belt Development Track</div></div><div class="card-body">${trackItems}</div></div>
      <div>
        <div class="card mb16"><div class="card-hd"><div class="card-ttl">Position School</div><span style="color:var(--gold);font-size:13px;font-weight:700">${calcTotalPSStars(s)>0?Array(calcTotalPSStars(s)).fill('★').join(' '):''}</span></div><div class="card-body">${(()=>{
  const bIdx=beltIdx(s.belt);
  if(bIdx<2) return '<div style="color:var(--txt3);font-size:12px;text-align:center;padding:12px">Unlocks at Green Belt</div>';
  const allT=[...PS_GREEN_TRACKS,...(bIdx>=3?PS_BLUE_TRACKS:[])];
  return allT.map(tid=>{
    const t=PS_TRACKS[tid]; const st2=getTrackStatus(s,tid); const td=s.ps&&s.ps.tracks?s.ps.tracks[tid]||{}:{};
    const statusBadge=st2==='complete'?'<span class="pill p-ok">Complete ★</span>':st2==='testing'?'<span class="pill p-blue">Ready to Test</span>':st2==='active'?'<span class="pill p-warn">In Progress</span>':st2==='eligible'?'<span class="pill p-gold">Available</span>':'<span class="pill p-muted">Locked</span>';
    const action=st2==='testing'?`<button class="btn btn-ok btn-xs" style="margin-left:8px" onclick="completePSTrack('${s.id}','${tid}'); event.stopPropagation()">Award Star</button>`:st2==='active'?`<span style="font-size:10.5px;color:var(--txt3);margin-left:8px">Since ${td.startedAt||'--'}</span>`:'';
    const canClick = st2 !== 'locked';
    return `<div class="irow" style="${st2==='locked'?'opacity:.5':'cursor:pointer'}" ${canClick?`onclick="openPSTrackDetail('${tid}','${s.id}')"`:''}><div class="ilbl" style="font-size:11.5px;flex:1">${t.name}</div><div class="ival" style="display:flex;align-items:center;gap:6px">${statusBadge}${action}</div></div>`;
  }).join('')+'<div class="irow" style="border:none"><div class="ilbl">Promotion Eligible</div><div class="ival">'+( s.promo?'<span class="pill p-gold">Yes</span>':'<span style="color:var(--txt3);font-size:12px">Not yet</span>' )+'</div></div>';
})()}</div></div>
        <div class="card"><div class="card-hd"><div class="card-ttl">Assessment History</div></div><div class="card-body"><div class="tl">${s.history.length?s.history.slice().reverse().map(h=>`<div class="tl-item"><div class="tl-dot" style="background:${h.res==='pass'?'rgba(34,197,94,.15)':'rgba(239,68,68,.15)'};color:${h.res==='pass'?'var(--ok)':'var(--err)'}">${h.res==='pass'?ICO.check:ICO.x}</div><div><div class="tl-date">${h.dt} &bull; ${beltBadge(h.belt)}</div><div class="tl-txt">${h.type}: <strong style="color:${h.res==='pass'?'var(--ok)':'var(--err)'}">${h.res.charAt(0).toUpperCase()+h.res.slice(1)}</strong></div></div></div>`).join(''):'<div style="font-size:12px;color:var(--txt3)">No assessment history recorded yet.</div>'}</div></div></div>
      </div>
    </div>
    <div>${buildOIPLeaderPanel(s, context==='admin')}</div>`;
  const target=context==='admin'?document.getElementById('a-facility'):document.getElementById('h-profile');
  if(target) target.innerHTML=html;
}


// ============================================================ OIP LEADER PANEL (leader/admin only)
function buildOIPLeaderPanel(s, canAdminAward){
  ensureOIP(s);
  if(!s.oip.completed){
    return `<div class="card mb16">
      <div class="card-hd">
        <div class="card-ttl">Operator Intelligence Profile</div>
        ${canAdminAward?`<button class="btn btn-ghost btn-xs" onclick="adminSendOIPPrompt('${s.id}')">Send Prompt</button>`:''}
      </div>
      <div class="card-body" style="text-align:center;padding:16px">
        <div style="font-size:28px;margin-bottom:8px">&#9670;</div>
        <div style="font-size:13px;font-weight:600;margin-bottom:6px">Not Yet Completed</div>
        <div style="font-size:11.5px;color:var(--txt3);line-height:1.5">This staff member has not completed their OIP assessment. They can access it from their staff portal under My Profile.</div>
      </div>
    </div>`;
  }

  const pType = OIP_TYPES[s.oip.primaryType];
  const sType = OIP_TYPES[s.oip.secondaryType];
  const scores = s.oip.scores;
  const total = scores.S+scores.St+scores.Su+scores.A;
  const roleKey = oipRoleKey(s.role);
  const compat = oipCompatibility(scores, roleKey);
  const nextRoleKey = (()=>{const keys=Object.keys(OIP_ROLE_TARGETS);const idx=keys.indexOf(roleKey);return idx<keys.length-1?keys[idx+1]:null;})();
  const nextCompat = nextRoleKey?oipCompatibility(scores,nextRoleKey):null;
  const compatColor = compat>=90?'var(--ok)':compat>=75?'var(--gold)':compat>=60?'var(--warn)':'var(--err)';
  const compatLabel = compat>=90?'Highly Compatible':compat>=75?'Compatible':compat>=60?'Developing Fit':'Profile Gap';
  const coaching = OIP_COACHING[s.oip.primaryType];

  return `<div class="card mb16">
    <div class="card-hd" style="flex-wrap:wrap;gap:8px">
      <div style="display:flex;align-items:center;gap:10px">
        <div style="width:42px;height:42px;border-radius:10px;background:${pType.bg};border:1.5px solid ${pType.bd};display:flex;align-items:center;justify-content:center;font-size:22px">${pType.icon}</div>
        <div>
          <div class="card-ttl" style="margin:0">${pType.name} <span style="font-size:10px;font-weight:500;color:var(--txt3)">(${sType.icon} ${sType.name} secondary)</span></div>
          <div style="font-size:10.5px;color:${pType.color}">${pType.label}</div>
        </div>
      </div>
      <div style="display:flex;align-items:center;gap:8px;margin-left:auto">
        <div style="text-align:right">
          <div style="font-size:10px;color:var(--txt3)">Role Compatibility</div>
          <div style="font-size:16px;font-weight:800;color:${compatColor}">${compat}%</div>
          <div style="font-size:9.5px;color:${compatColor}">${compatLabel}</div>
        </div>
      </div>
    </div>
    <div class="card-body">
      <!-- Score bars -->
      <div style="margin-bottom:14px">
        ${Object.values(OIP_TYPES).map(t=>{const sc=scores[t.key]||0;const pct=total>0?Math.round(sc/total*100):0;return`
          <div style="display:flex;align-items:center;gap:8px;margin-bottom:5px">
            <div style="width:70px;font-size:10.5px;color:${t.key===s.oip.primaryType?t.color:'var(--txt3)'};font-weight:${t.key===s.oip.primaryType?'700':'400'};flex-shrink:0">${t.name}</div>
            <div style="flex:1;height:6px;background:var(--s3);border-radius:3px;overflow:hidden">
              <div style="height:100%;width:${pct}%;background:${t.color};border-radius:3px"></div>
            </div>
            <div style="width:24px;font-size:10.5px;color:var(--txt3);text-align:right">${sc}</div>
          </div>`}).join('')}
      </div>

      <!-- Compatibility with next role -->
      ${nextRoleKey?`<div style="background:var(--s2);border:1px solid var(--bdr);border-radius:var(--rs);padding:10px 12px;margin-bottom:14px">
        <div style="font-size:10.5px;color:var(--txt3);margin-bottom:4px">Compatibility with next role (${nextRoleKey})</div>
        <div style="display:flex;align-items:center;gap:8px">
          <div style="flex:1;height:6px;background:var(--s3);border-radius:3px;overflow:hidden">
            <div style="height:100%;width:${nextCompat}%;background:${nextCompat>=75?'var(--ok)':nextCompat>=60?'var(--gold)':'var(--warn)'};border-radius:3px"></div>
          </div>
          <span style="font-size:12px;font-weight:700;color:${nextCompat>=75?'var(--ok)':nextCompat>=60?'var(--gold)':'var(--warn)'}">${nextCompat}%</span>
        </div>
      </div>`:''}

      <!-- Coaching accordion -->
      <div style="border:1px solid ${pType.bd};border-radius:var(--rs);overflow:hidden">
        <div style="background:${pType.bg};padding:9px 14px;font-size:11px;font-weight:700;color:${pType.color};letter-spacing:.05em">HOW TO LEAD A ${pType.name.toUpperCase()}</div>
        ${[
          ['Lead',coaching.lead,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><path d="M9 2l1.8 4 4.2.4-3 2.8.8 4.2L9 11.4l-3.8 2 .8-4.2-3-2.8 4.2-.4z" stroke="currentColor" stroke-width="1.3"/></svg>'],
          ['Motivate',coaching.motivate,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><path d="M9 3v6l3 3" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><circle cx="9" cy="9" r="7" stroke="currentColor" stroke-width="1.3"/></svg>'],
          ['Develop',coaching.develop,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><path d="M4 14c0-3 2-5 5-5s5 2 5 5M9 7V3M6 5l3-2 3 2" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/></svg>'],
          ['Watch For',coaching.watch,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><circle cx="9" cy="9" r="2.5" stroke="currentColor" stroke-width="1.3"/><path d="M2 9c2-4 4-5 7-5s5 1 7 5c-2 4-4 5-7 5s-5-1-7-5z" stroke="currentColor" stroke-width="1.3"/></svg>'],
          ['How to Correct',coaching.correct,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><path d="M14 7l-5 5-2.5-2.5" stroke="currentColor" stroke-width="1.4" stroke-linecap="round"/><circle cx="9" cy="9" r="7" stroke="currentColor" stroke-width="1.3"/></svg>'],
          ['Promotion Path',coaching.promote,'<svg viewBox="0 0 18 18" fill="none" width="13" height="13"><path d="M4 14l5-9 5 9M6.5 11h5" stroke="currentColor" stroke-width="1.3" stroke-linecap="round"/></svg>'],
        ].map(([label,text,ico])=>`
          <div style="border-top:1px solid ${pType.bd}">
            <div style="padding:9px 14px;display:flex;align-items:flex-start;gap:9px">
              <div style="color:${pType.color};margin-top:1px;flex-shrink:0">${ico}</div>
              <div>
                <div style="font-size:11px;font-weight:700;color:${pType.color};margin-bottom:3px">${label}</div>
                <div style="font-size:12px;color:var(--txt2);line-height:1.6">${text}</div>
              </div>
            </div>
          </div>`).join('')}
      </div>
      <div style="font-size:10px;color:var(--txt3);margin-top:8px;text-align:center">OIP is a development tool. It does not determine promotions. Completed ${s.oip.completedAt}.</div>
    </div>
  </div>`;
}

function adminSendOIPPrompt(staffId){
  toast('Staff member notified to complete their Operator Intelligence Profile.');
}


// ============================================================ H SCHEDULE BUILDER
let schViewDate = todayStr();
let schViewShift = 'AM';


// ============================================================ H SCHEDULE  --  FULL BUILDER
let schTab = 'builder'; // 'builder' | 'attendance' | 'record'
let schBuilderMonth = new Date().getMonth();
let schBuilderYear  = new Date().getFullYear();

// Smart dispatch: re-renders the correct view depending on whether the user
// is on h-attendance (standalone) or h-schedule (combined tabs)
function _refreshHAtt(){ if(ST.hView==='h-attendance') renderHAttendance(); else renderHSchedule(); }

function renderHSchedule(){
  const fid = ST.hFid||'test-a';
  const el = document.getElementById('h-schedule');
  const today = todayStr();
  const shifts = getFacilityShifts(fid);
  const shiftKeys = Object.keys(shifts);

  // Tabs
  const tabs = `<div style="display:flex;gap:2px;background:var(--s2);border:1px solid var(--bdr);border-radius:var(--rs);padding:3px;margin-bottom:14px;flex-wrap:wrap">
    ${[['builder','📅 Schedule Builder'],['attendance','✅ Take Attendance'],['record','📋 Attendance Record'],['shifts','⚙️ Manage Shifts']].map(([k,lbl])=>
      `<div style="flex:1;min-width:100px;text-align:center;padding:7px 10px;border-radius:var(--rs);cursor:pointer;font-size:12px;font-weight:600;transition:.15s;background:${schTab===k?'var(--s1)':'transparent'};color:${schTab===k?'var(--txt1)':'var(--txt3)'};border:${schTab===k?'1px solid var(--bdr)':'1px solid transparent'}" onclick="schTab='${k}';renderHSchedule()">${lbl}</div>`
    ).join('')}
  </div>`;

  if(schTab==='builder')   { el.innerHTML=tabs+buildScheduleBuilder(fid,shifts); wireScheduleBuilder(fid); }
  else if(schTab==='attendance') { el.innerHTML=tabs+buildAttendanceTab(fid,shifts); }
  else if(schTab==='record')     { el.innerHTML=tabs+buildAttendanceRecord(fid); }
  else if(schTab==='shifts')     { el.innerHTML=tabs+buildShiftManager(fid); }
}

// ─── SCHEDULE BUILDER ────────────────────────────────────────────────────────
function buildScheduleBuilder(fid, shifts){
  const today = todayStr();
  const year = schBuilderYear, month = schBuilderMonth;
  const firstDay = new Date(year, month, 1);
  const lastDay  = new Date(year, month+1, 0);
  const daysInMonth = lastDay.getDate();
  const monthName = firstDay.toLocaleDateString('en-US',{month:'long',year:'numeric'});
  const shiftKeys = Object.keys(shifts);

  // Stats
  let totalFilled=0, totalSlots=0, totalStaff=0;
  for(let d=1;d<=daysInMonth;d++){
    const dt = `${year}-${String(month+1).padStart(2,'0')}-${String(d).padStart(2,'0')}`;
    shiftKeys.forEach(sk=>{
      totalSlots++;
      const sch=getSchedule(fid,dt,sk);
      if(sch&&sch.assignedStaff.length){totalFilled++;totalStaff+=sch.assignedStaff.length;}
    });
  }

  // Day headers
  const dayHeaders = Array.from({length:daysInMonth},(_,i)=>{
    const dt=new Date(year,month,i+1);
    const isToday=`${year}-${String(month+1).padStart(2,'0')}-${String(i+1).padStart(2,'0')}`===today;
    const wd=dt.toLocaleDateString('en-US',{weekday:'short'});
    return `<th style="min-width:52px;max-width:68px;padding:4px 2px;text-align:center;font-size:9px;font-weight:700;color:${isToday?'var(--gold)':'var(--txt3)'};background:${isToday?'rgba(196,154,32,.08)':'var(--s2)'}">
      <div style="letter-spacing:.03em">${wd}</div>
      <div style="font-size:12px;font-weight:800;color:${isToday?'var(--gold)':'var(--txt1)'}">${i+1}</div>
    </th>`;
  }).join('');

  // Shift rows
  const shiftRows = shiftKeys.map(sk=>{
    const sh=shifts[sk];
    const cells = Array.from({length:daysInMonth},(_,i)=>{
      const day = String(i+1).padStart(2,'0');
      const dt = `${year}-${String(month+1).padStart(2,'0')}-${day}`;
      const sch = getSchedule(fid,dt,sk);
      const count = sch?sch.assignedStaff.length:0;
      const isPast = dt<today;
      const isToday = dt===today;
      const hasAbs = sch?(DB.attendance||[]).filter(a=>a.fid===fid&&a.date===dt&&a.shift===sk&&(a.status==='absent')).length>0:false;
      const bg = count===0?(isPast?'rgba(239,68,68,.06)':'transparent'):hasAbs?'rgba(239,68,68,.08)':'rgba(34,197,94,.06)';
      const border = isToday?`2px solid ${sh.color}`:count>0?`1px solid ${sh.color}44`:'1px solid var(--bdr)';
      return `<td style="padding:2px;text-align:center">
        <div style="background:${bg};border:${border};border-radius:5px;padding:3px 2px;cursor:pointer;min-height:32px;display:flex;flex-direction:column;align-items:center;justify-content:center;transition:.12s" onclick="openShiftEditModal('${fid}','${dt}','${sk}')" title="${dateLabel(dt)}: ${sh.label} (${count} staff)">
          ${count>0?`<div style="font-size:11px;font-weight:800;color:${sh.color}">${count}</div><div style="font-size:8px;color:var(--txt3)">staff</div>`:`<div style="font-size:14px;opacity:.3">+</div>`}
          ${hasAbs?'<div style="width:5px;height:5px;border-radius:50%;background:var(--err);margin-top:1px"></div>':''}
        </div>
      </td>`;
    }).join('');
    return `<tr>
      <td style="padding:6px 10px;white-space:nowrap;position:sticky;left:0;background:var(--s1);z-index:2;min-width:100px;border-right:2px solid var(--bdr)">
        <div style="font-size:14px;margin-bottom:1px">${sh.icon}</div>
        <div style="font-size:11.5px;font-weight:700;color:${sh.color}">${sh.label}</div>
        <div style="font-size:9.5px;color:var(--txt3)">${fmtTime(sh.start)}–${fmtTime(sh.end)}</div>
      </td>
      ${cells}
    </tr>`;
  }).join('');

  return `
    <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;margin-bottom:12px">
      <button class="btn btn-ghost btn-sm" onclick="schBuilderMonth--;if(schBuilderMonth<0){schBuilderMonth=11;schBuilderYear--;}renderHSchedule()">‹</button>
      <div style="font-size:15px;font-weight:800;flex:1;text-align:center">${monthName}</div>
      <button class="btn btn-ghost btn-sm" onclick="schBuilderMonth++;if(schBuilderMonth>11){schBuilderMonth=0;schBuilderYear++;}renderHSchedule()">›</button>
      <button class="btn btn-gold btn-sm" onclick="openPublishModal('${fid}')">📤 Publish</button>
      <button class="btn btn-ghost btn-sm" onclick="openBulkScheduleModal('${fid}')">⚡ Quick Fill</button>
      <button class="btn btn-ghost btn-sm" onclick="openScheduleUploadModal('${fid}')">📥 Upload CSV</button>
    </div>

    <div style="display:grid;grid-template-columns:repeat(4,1fr);gap:8px;margin-bottom:12px">
      <div class="stat-card"><div class="stat-accent" style="background:var(--ok)"></div><div class="stat-lbl">Shifts Filled</div><div class="stat-val" style="color:var(--ok)">${totalFilled}/${totalSlots}</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--blue)"></div><div class="stat-lbl">Total Assignments</div><div class="stat-val" style="color:var(--blue)">${totalStaff}</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--gold)"></div><div class="stat-lbl">Active Shifts</div><div class="stat-val" style="color:var(--gold)">${shiftKeys.length}</div></div>
      <div class="stat-card"><div class="stat-accent" style="background:var(--warn)"></div><div class="stat-lbl">Coverage Gaps</div><div class="stat-val" style="color:var(--warn)">${totalSlots-totalFilled}</div></div>
    </div>

    <div style="overflow-x:auto;-webkit-overflow-scrolling:touch;border:1px solid var(--bdr);border-radius:var(--r)">
      <table style="border-collapse:collapse;width:100%;min-width:${100+daysInMonth*54}px">
        <thead>
          <tr>
            <th style="position:sticky;left:0;background:var(--s1);z-index:3;min-width:100px;padding:6px 10px;text-align:left;font-size:10.5px;font-weight:700;color:var(--txt3);border-right:2px solid var(--bdr);border-bottom:1px solid var(--bdr)">SHIFT</th>
            ${dayHeaders}
          </tr>
        </thead>
        <tbody>${shiftRows}</tbody>
      </table>
    </div>
    <div style="font-size:10.5px;color:var(--txt3);margin-top:8px">Click any cell to assign staff. Red dot = absent recorded. Green background = fully staffed.</div>`;
}

function wireScheduleBuilder(fid){ /* already interactive via onclick */ }

// ─── QUICK FILL MODAL ─────────────────────────────────────────────────────────
function openBulkScheduleModal(fid){
  const shifts = getFacilityShifts(fid);
  const st = staffOf(fid);
  openModal('Quick Fill: Bulk Schedule',`
    <div class="modal-body">
      <div style="background:rgba(196,154,32,.06);border:1px solid var(--gold-bd);border-radius:var(--rs);padding:10px 14px;font-size:12px;color:var(--txt2);margin-bottom:14px">
        Auto-assign staff equally across all shifts for the selected date range. You can edit individual shifts afterward.
      </div>
      <div class="form-row">
        <div class="form-group"><label class="form-label">Start Date</label><input type="date" class="form-input" id="qf-start" value="${todayStr()}"></div>
        <div class="form-group"><label class="form-label">End Date</label><input type="date" class="form-input" id="qf-end" value="${add30Days(todayStr(),29)[29]}"></div>
      </div>
      <div class="form-group"><label class="form-label">Shifts to Fill</label>
        <div style="display:flex;gap:8px;flex-wrap:wrap">
          ${Object.keys(shifts).map(sk=>{const sh=shifts[sk];return`<label style="display:flex;align-items:center;gap:6px;cursor:pointer;padding:6px 10px;border:1px solid var(--bdr);border-radius:var(--rs);font-size:12px"><input type="checkbox" id="qf-sh-${sk}" checked style="accent-color:var(--gold)"> ${sh.icon} ${sh.label}</label>`;}).join('')}
        </div>
      </div>
      <div class="form-group"><label class="form-label">Staff per Shift</label>
        <select class="form-select" id="qf-count">
          ${[2,3,4,5,6,8,10].map(n=>`<option value="${n}" ${n===3?'selected':''}>${n} staff</option>`).join('')}
        </select>
      </div>
    </div>
    <div class="modal-ft"><button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-gold" onclick="execBulkSchedule('${fid}')">Fill Schedule</button></div>`,'modal-md');
}

function execBulkSchedule(fid){
  const start = document.getElementById('qf-start').value;
  const end   = document.getElementById('qf-end').value;
  const count = parseInt(document.getElementById('qf-count').value)||3;
  const shifts = getFacilityShifts(fid);
  const st = staffOf(fid);
  if(!st.length||!start||!end){toast('Missing data.','err');return;}
  const dates = [];
  const d=new Date(start+'T12:00:00');
  while(d.toISOString().slice(0,10)<=end){ dates.push(d.toISOString().slice(0,10)); d.setDate(d.getDate()+1); }
  let filled=0;
  dates.forEach((date,di)=>{
    Object.keys(shifts).forEach((sk,si)=>{
      const chk=document.getElementById('qf-sh-'+sk);
      if(chk&&!chk.checked) return;
      const existing=DB.schedule.find(s=>s.fid===fid&&s.date===date&&s.shift===sk);
      const offset=((di*Object.keys(shifts).length+si)*count)%st.length;
      const assigned=[];
      for(let i=0;i<Math.min(count,st.length);i++) assigned.push(st[(offset+i)%st.length].id);
      if(existing){ existing.assignedStaff=assigned; if(!existing.zoneAssignments) existing.zoneAssignments={}; }
      else {
        const autoSched={id:'sch-'+DB.schNextId++,fid,date,shift:sk,assignedStaff:assigned,publishedBy:ST.user?.id||'',notes:'',zoneAssignments:{}};
        if(IS_LIVE){ SB.createSchedule(mapScheduleToBackend(autoSched)).catch(e => { if (e instanceof ReferenceError || e instanceof TypeError || e instanceof SyntaxError) throw e; }); }
        DB.schedule.push(autoSched);
      }
      filled++;
    });
  });
  closeModal();
  toast(`Schedule filled: ${filled} shifts assigned across ${dates.length} days.`,'ok');
  renderHSchedule();
}

// ─── SHIFT MANAGER (create / edit / delete facility shifts) ───────────────────
function buildShiftManager(fid){
  const shifts = getFacilityShifts(fid);
  const shiftRows = Object.values(shifts).map(sh=>`
    <div style="display:flex;align-items:center;gap:10px;padding:10px 14px;border-bottom:1px solid var(--bdr);flex-wrap:wrap">
      <div style="font-size:22px;width:36px;text-align:center">${sh.icon}</div>
      <div style="flex:1;min-width:140px">
        <div style="font-size:13px;font-weight:700">${sh.label}: ${sh.name}</div>
        <div style="font-size:11.5px;color:var(--txt3)">${fmtTime(sh.start)} – ${fmtTime(sh.end)}</div>
      </div>
      <div style="display:flex;gap:4px">
        <button class="btn btn-ghost btn-xs" onclick="openCreateShiftModal('${fid}','${sh.id}')">Edit</button>
        ${sh.id!=='AM'&&sh.id!=='PM'&&sh.id!=='NOC'?`<button class="btn btn-err btn-xs" onclick="deleteShift('${fid}','${sh.id}')">Delete</button>`:''}
      </div>
    </div>`).join('');
  return `
    <div style="display:flex;justify-content:flex-end;margin-bottom:10px">
      <button class="btn btn-gold btn-sm" onclick="openCreateShiftModal('${fid}',null)">+ Create New Shift</button>
    </div>
    <div class="card mb16">
      <div class="card-hd"><div class="card-ttl">Shift Definitions</div><span class="pill p-muted">${Object.keys(shifts).length} shifts</span></div>
      ${shiftRows}
    </div>
    <div style="background:var(--s2);border:1px solid var(--bdr);border-radius:var(--rs);padding:12px 14px;font-size:11.5px;color:var(--txt2);line-height:1.6">
      Shifts defined here apply to your facility only. Default shifts (AM, PM, NOC) can be edited but not deleted. Custom shifts can be removed.
    </div>`;
}

