function downloadFreeAgentReport(faId) {
  const fa = DB.freeAgents.find(f => f.id === faId);
  if (!fa) { toast('Record not found.', 'err'); return; }

  const pts = calcPoints(fa);
  const psStars = calcTotalPSStars(fa);
  const hist = fa.facilityHistory || [];
  const bColor = BELT_CLR_PRINT[fa.belt] || '#0f172a';
  const bIdx_val = beltIdx(fa.belt);
  const nxt = nextBelt(fa.belt);
  const generatedAt = new Date().toLocaleDateString('en-US',{year:'numeric',month:'long',day:'numeric'});
  const allHistory = (fa.history||[]).slice().reverse();

  // Gates per belt
  const beltHistory = BELT_ORDER.filter(b => beltIdx(b) <= bIdx_val);
  const gatesByBelt = beltHistory.map(b => {
    const bh = (fa.history||[]).filter(h => h.belt === b);
    const pass = bh.filter(h => h.res==='pass').length;
    const fail = bh.filter(h => h.res==='fail').length;
    return {b, pass, fail, total: pass+fail};
  }).filter(x => x.total > 0);

  // PS tracks
  const psTracks = [...PS_GREEN_TRACKS,...PS_BLUE_TRACKS]
    .map(tid => ({tid, t:PS_TRACKS[tid], status:getTrackStatus(fa,tid), td:(fa.ps&&fa.ps.tracks&&fa.ps.tracks[tid])||{}}))
    .filter(x => x.status !== 'locked');

  // OIP section
  const oipSection = fa.oip && fa.oip.completed && fa.oip.primaryType ? `
    ${pSection('Operator Intelligence Profile')}
    <table><thead><tr><th>Primary Type</th><th>Secondary Type</th><th>Completed</th></tr></thead>
    <tbody><tr>
      <td><strong>${OIP_TYPES[fa.oip.primaryType]?.name||'–'}</strong><br><span style="font-size:7.5pt;color:#64748b">${OIP_TYPES[fa.oip.primaryType]?.label||''}</span></td>
      <td>${fa.oip.secondaryType && OIP_TYPES[fa.oip.secondaryType] ? OIP_TYPES[fa.oip.secondaryType].name : '–'}</td>
      <td>${fa.oip.completedAt||'–'}</td>
    </tr></tbody></table>` : '';

  // Belt bars
  const beltBar = BELT_ORDER.map((b,i) => {
    const done = i <= bIdx_val;
    const cur = b === fa.belt;
    const clr = done ? (BELT_CLR_PRINT[b]||'#888') : '#e2e8f0';
    return `<div style="flex:1;text-align:center">
      <div style="height:6px;border-radius:3px;background:${clr};margin-bottom:3px"></div>
      <div style="font-size:7pt;font-weight:${cur?'800':'400'};color:${done?clr:'#94a3b8'}">${b}</div>
    </div>`;
  }).join('');

  // Facility history
  const facHistSection = hist.length ? `
    ${pSection('Facility Employment History')}
    <table><thead><tr><th>Facility</th><th>From</th><th>To</th><th>Location</th></tr></thead>
    <tbody>${hist.map(h=>`<tr>
      <td style="font-weight:600">${h.facName||'–'}</td>
      <td style="color:#64748b">${h.from||'–'}</td>
      <td style="color:#64748b">${h.to||'–'}</td>
      <td style="color:#64748b;font-size:7.5pt">${h.loc||'–'}</td>
    </tr>`).join('')}</tbody></table>
    <div style="margin-top:8px;padding:8px 10px;background:#fef9c3;border:1px solid #d97706;border-radius:4px;font-size:8pt">
      <strong>Release Reason:</strong> ${fa.releaseReason||'Not specified'} &bull; <strong>Released:</strong> ${fa.releasedAt||'–'}
    </div>` : `${pSection('Facility Employment History')}<div style="color:#94a3b8;padding:8px 0">No facility history on record.</div>`;

  const body = `
    <!-- Verified Banner -->
    <div style="background:#fefce8;border:1.5px solid #d97706;border-radius:6px;padding:10px 14px;margin-bottom:18px;display:flex;align-items:center;gap:10px">
      <div style="font-size:18pt">&#9989;</div>
      <div>
        <div style="font-size:9pt;font-weight:800;color:#92400e;letter-spacing:.05em">SIPS-VERIFIED FREE AGENT RECORD</div>
        <div style="font-size:8pt;color:#78350f">All belt certifications, assessment history, and employment records are authenticated by SIPS Healthcare Solutions. This document is confidential and intended for authorized hiring facilities only.</div>
      </div>
    </div>

    <!-- Header -->
    <div class="rpt-header">
      <div>
        <div class="rpt-brand">SIPS Healthcare Solutions &bull; Sterile By Design &bull; Free Agent Registry</div>
        <div class="rpt-title">${fullName(fa)}</div>
        <div class="rpt-sub">${fa.role} &bull; Sterile Processing Department<br>Current Belt: ${fa.belt} (${BELT_CERT[fa.belt]||''}) &bull; Certified Since ${fa.since||'–'}<br>Released: ${fa.releasedAt||'–'}</div>
      </div>
      <div class="rpt-grade-box">
        <div class="rpt-grade" style="color:${bColor}">${psStars > 0 ? Array(psStars).fill('★').join('') : '–'}</div>
        <div class="rpt-grade-lbl">PS Stars</div>
      </div>
    </div>

    <!-- Belt Progress Bar -->
    <div style="display:flex;gap:4px;margin-bottom:16px">${beltBar}</div>

    <!-- Stat Grid -->
    ${pStatGrid([
      ['Current Belt', fa.belt, 'Since ' + (fa.since||'–'), bColor],
      ['Points', pts.toLocaleString(), 'SBD Score', '#d97706'],
      ['PS Stars', psStars, psStars===0 ? 'No tracks yet' : psStars===1 ? '1 track complete' : psStars+' tracks complete', '#d97706'],
      ['Assessments', (fa.history||[]).length, (fa.history||[]).filter(h=>h.res==='pass').length+' passed', '#16a34a'],
      ['Facilities', hist.length, hist.length===1 ? '1 placement' : hist.length+' placements', '#2563eb'],
    ])}

    ${pSection('Current Belt Gates')}
    <table class="no-break"><thead><tr><th>Assessment</th><th>Result</th></tr></thead>
    <tbody>${['Competency','Simulation','Observation'].map((a,i)=>{
      const key=['c','s','o'][i];
      const v=fa.cur&&fa.cur[key];
      return `<tr><td>${a}</td><td><span class="badge ${v==='pass'?'badge-green':v==='fail'?'badge-err':'badge-muted'}">${v?v.charAt(0).toUpperCase()+v.slice(1):'Not assessed'}</span></td></tr>`;
    }).join('')}</tbody></table>

    ${gatesByBelt.length ? `${pSection('Assessment History by Belt')}
    <table class="no-break"><thead><tr><th>Belt</th><th>Taken</th><th>Passed</th><th>Failed</th><th>Pass Rate</th></tr></thead>
    <tbody>${gatesByBelt.map(({b,pass,fail,total})=>`<tr>
      <td>${pBelt(b)}</td><td>${total}</td>
      <td style="color:#16a34a;font-weight:700">${pass}</td>
      <td style="color:${fail>0?'#dc2626':'#64748b'};font-weight:${fail>0?'700':'400'}">${fail}</td>
      <td><span class="badge ${pass/total>=0.8?'badge-green':pass/total>=0.6?'badge-warn':'badge-err'}">${Math.round(pass/total*100)}%</span></td>
    </tr>`).join('')}</tbody></table>` : ''}

    ${psTracks.length ? `${pSection('Position School Tracks')}
    <table class="no-break"><thead><tr><th>Track</th><th>Tier</th><th>Status</th><th>Started</th><th>Completed</th></tr></thead>
    <tbody>${psTracks.map(({tid,t,status,td})=>`<tr>
      <td style="font-weight:600">${t.name}</td>
      <td style="font-size:7.5pt;font-weight:700;color:${t.tier==='green'?'#16a34a':'#2563eb'}">${t.tier.toUpperCase()}</td>
      <td>${pPSStatus(status)}</td>
      <td style="color:#64748b">${td.startedAt||'–'}</td>
      <td style="color:${status==='complete'?'#16a34a':'#64748b'};font-weight:${status==='complete'?'700':'400'}">${td.completedAt||'–'}</td>
    </tr>`).join('')}</tbody></table>` : ''}

    ${oipSection}
    ${facHistSection}

    ${pSection('Full Assessment Log', allHistory.length+' entries')}
    ${allHistory.length === 0 ? '<div style="color:#94a3b8;padding:8px 0">No assessment history recorded.</div>' :
    `<table><thead><tr><th>Date</th><th>Belt</th><th>Type</th><th>Result</th><th>Notes</th></tr></thead>
    <tbody>${allHistory.map(h=>`<tr>
      <td style="color:#64748b">${h.dt||'–'}</td>
      <td>${pBelt(h.belt)}</td>
      <td>${h.type}</td>
      <td><span class="badge ${h.res==='pass'?'badge-green':'badge-err'}">${h.res==='pass'?'Pass':'Fail'}</span></td>
      <td style="color:#64748b;font-size:7.5pt">${h.note||'–'}</td>
    </tr>`).join('')}</tbody></table>`}
  `;

  openPrintWindow('SIPS Free Agent Record: ' + fullName(fa), body);
}


// ============================================================ TRANSFER VERIFICATION ENGINE
function approveTransfer(trId) {
  if(!DB.pendingTransfers) return;
  const tr = DB.pendingTransfers.find(t => t.id === trId);
  if(!tr || tr.status !== 'pending') return;
  const adminName = (ST.user&&(ST.user.name||ST.user.email))||'Admin';

  if(tr.requestedBy === (ST.user?.id||'admin')) {
    toast('You cannot approve your own transfer request. A second administrator must verify this action.','err');
    return;
  }

  tr.status = 'approved';
  tr.approvedBy = ST.user?.id||'admin';
  tr.approvedByName = adminName;
  tr.approvedAt = new Date().toISOString().slice(0,10);

  if(tr.type === 'release') {
    // Execute the release
    const s = getStaff(tr.staffId);
    if(!s) { toast('Staff record not found during approval.','err'); return; }
    const fac = getFac(s.fid);
    const date = tr.effectDate;
    if(!DB.freeAgents) DB.freeAgents = [];

    const faRecord = {
      ...s,
      id: 'fa-'+Date.now(),
      originalId: s.id,
      fid: null,
      releasedAt: date,
      releaseReason: tr.reason,
      releaseNotes: tr.notes,
      releasedFrom: fac?.name||'--',
      facilityHistory: [
        ...(s.facilityHistory||[]),
        {facName:fac?.name||'--', fid:s.fid, loc:fac?.loc||'', from:s.since, to:date}
      ]
    };
    faRecord.history = [...(s.history||[]), {dt:date, type:'Release', belt:s.belt, res:'released', note:`Released from ${fac?.name||'--'}. Reason: ${tr.reason}${tr.notes?' \u2014 '+tr.notes:''}. Approved by ${adminName}.`}];
    if(IS_LIVE){ SB.releaseToFreeAgent(mapFreeAgentToBackend(faRecord)).catch(e => handleSyncError(e, 'Release sync')); }
  DB.freeAgents.push(faRecord);
    DB.staff = DB.staff.filter(x => x.id !== tr.staffId);
    DB.users = DB.users.filter(u => !(u.sid === tr.staffId && u.role === 'staff_member'));

    // Log placement
    _logPlacement({
      faName: tr.staffName, belt: tr.belt, psStars: 0,
      fromFacName: tr.fromFacName, toFacName: 'Free Agent Pool',
      releasedAt: date, assignedAt: null,
      assignedBy: adminName, outcome: 'released', notes: tr.notes
    });

    toast(`Release approved. ${tr.staffName} is now in the Free Agent Registry.`,'ok');

  } else if(tr.type === 'assignment') {
    // Execute the assignment
    const fa = DB.freeAgents.find(f => f.id === tr.faId);
    if(!fa) { toast('Free agent record not found during approval.','err'); return; }
    const fac = getFac(tr.toFacId);
    const date = tr.effectDate;

    const restoredStaff = {...fa, fid: tr.toFacId, id: fa.originalId||fa.id};
    if(!DB.staff.find(s => s.id === restoredStaff.id)) {
      if(IS_LIVE){ SB.assignFreeAgent(tr.faId,tr.toFacId,mapStaffToBackend(restoredStaff)).catch(e => handleSyncError(e, 'Assign sync')); }
      DB.staff.push(restoredStaff);
    } else {
      restoredStaff.id = ++DB.nextId;
      if(IS_LIVE){ SB.createStaff(mapStaffToBackend(restoredStaff)).catch(e => handleSyncError(e, 'Staff sync')); }
      DB.staff.push(restoredStaff);
    }
    if(!restoredStaff.facilityHistory) restoredStaff.facilityHistory = [];
    restoredStaff.facilityHistory.push({facName:fac?.name||tr.toFacName, fid:tr.toFacId, loc:fac?.loc||'', from:date, to:'Present'});
    restoredStaff.history = [...(restoredStaff.history||[]), {dt:date, type:'Assignment', belt:restoredStaff.belt, res:'placement', note:`Assigned to ${fac?.name||tr.toFacName}${tr.notes?' \u2014 '+tr.notes:''}. Approved by ${adminName}.`}];

    DB.freeAgents = DB.freeAgents.filter(f => f.id !== tr.faId);

    // Log placement
    _logPlacement({
      faName: tr.staffName, belt: tr.belt,
      psStars: calcTotalPSStars(restoredStaff),
      fromFacName: 'Free Agent Pool', toFacName: fac?.name||tr.toFacName,
      releasedAt: fa.releasedAt||'--', assignedAt: date,
      assignedBy: adminName, outcome:'placed', notes: tr.notes
    });

    toast(`Assignment approved. ${tr.staffName} is now active at <strong>${fac?.name||tr.toFacName}</strong>.`,'ok');
  }

  updateFANB();
  /* saveDemoData() removed */
  renderAFreeAgents();
}

function denyTransfer(trId) {
  const tr = DB.pendingTransfers&&DB.pendingTransfers.find(t => t.id === trId);
  if(!tr) return;
  openModal('Deny Transfer Request', `<div class="modal-body">
    <div style="font-size:13.5px;font-weight:700;margin-bottom:4px">Deny: ${tr.type==='release'?'Release':'Assignment'} for ${cleanName(tr.staffName)||'Unknown'}</div>
    <div style="font-size:12px;color:var(--txt3);margin-bottom:14px">${tr.type==='release'?'From '+tr.fromFacName:'To '+tr.toFacName} &bull; Requested by ${tr.requestedByName}</div>
    <div class="form-group"><label class="form-label">Reason for Denial *</label>
      <textarea class="form-textarea" id="deny-reason-inp" placeholder="Explain why this transfer is being denied..." style="min-height:80px"></textarea>
    </div>
  </div>
  <div class="modal-ft">
    <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
    <button class="btn btn-err" onclick="executeDenyTransfer('${trId}')">Deny Transfer</button>
  </div>`, 'modal-sm');
}

function executeDenyTransfer(trId) {
  const reason = document.getElementById('deny-reason-inp')?.value.trim();
  if(!reason) { toast('Please provide a reason for denial.','err'); return; }
  const tr = DB.pendingTransfers&&DB.pendingTransfers.find(t => t.id === trId);
  if(!tr) return;
  const adminName = (ST.user&&(ST.user.name||ST.user.email))||'Admin';
  tr.status = 'denied';
  tr.deniedBy = ST.user?.id||'admin';
  tr.deniedByName = adminName;
  tr.deniedAt = new Date().toISOString().slice(0,10);
  tr.denyReason = reason;
  closeModal();
  toast(`Transfer denied. ${tr.staffName} was not moved.`,'err');
  updateFANB();
  /* saveDemoData() removed */
  renderAFreeAgents();
}

function _logPlacement(data) {
  if(!DB.placementLog) DB.placementLog = [];
  DB.placementLog.unshift({
    id: 'pl-'+Date.now(),
    loggedAt: new Date().toISOString().slice(0,10),
    ...data
  });
}

// ============================================================ FREE AGENT REGISTRY (Master Admin only)
function renderAFreeAgents(){
  const isMaster=ST.user&&ST.user.role==='master_admin';
  const el=document.getElementById('a-freeagents');
  if(!isMaster){
    el.innerHTML=`<div class="card"><div class="empty-state"><div class="empty-ttl">Access Restricted</div><div class="empty-desc">The Free Agent Registry is only accessible to SIPS Master Admins.</div></div></div>`;
    return;
  }
  if(!DB.freeAgents) DB.freeAgents=[];
  if(!DB.pendingTransfers) DB.pendingTransfers=[];
  if(!DB.placementLog) DB.placementLog=[];
  if(!window._faTab) window._faTab='agents';

  const tab=window._faTab;
  const fas=DB.freeAgents;
  const pending=DB.pendingTransfers.filter(t=>t.status==='pending');
  const allTransfers=DB.pendingTransfers.slice().sort((a,b)=>b.id.localeCompare(a.id));
  const placed=DB.placementLog;
  const myUserId=ST.user?.id||'admin';

  function faTabBtn(id,label,badge){
    const active=tab===id;
    return `<div style="padding:9px 18px;border-radius:var(--rs);font-size:13px;font-weight:${active?'700':'500'};cursor:pointer;white-space:nowrap;background:${active?'var(--s1)':'transparent'};color:${active?'var(--txt1)':'var(--txt3)'};border:1px solid ${active?'var(--bdr)':'transparent'};transition:.12s;display:flex;align-items:center;gap:7px" onclick="window._faTab='${id}';renderAFreeAgents()">${label}${badge?`<span style="min-width:18px;height:18px;border-radius:9px;background:var(--err);color:#fff;font-size:10px;font-weight:800;display:inline-flex;align-items:center;justify-content:center;padding:0 5px">${badge}</span>`:''}</div>`;
  }

  // ── HEADER ─────────────────────────────────────────────────────
  let html=`
    <div style="background:linear-gradient(135deg,#0e1328,#131829);border:1px solid rgba(196,154,32,.2);border-radius:var(--r);padding:18px;margin-bottom:16px">
      <div style="display:flex;align-items:flex-start;justify-content:space-between;flex-wrap:wrap;gap:10px">
        <div>
          <div style="font-size:9.5px;color:#c49a20;font-weight:700;letter-spacing:.1em;margin-bottom:4px">SIPS HEALTHCARE SOLUTIONS &bull; MASTER ADMIN ONLY</div>
          <div style="font-size:18px;font-weight:800;margin-bottom:4px">Free Agent Registry</div>
          <div style="font-size:12px;color:#64748b;max-width:600px">Complete belt records for staff between facilities. All transfers require dual-admin verification. Every placement is logged permanently.</div>
        </div>
        <div style="display:flex;gap:10px">
          <div style="text-align:center;padding:10px 16px;background:rgba(196,154,32,.08);border:1px solid rgba(196,154,32,.25);border-radius:var(--rs)">
            <div style="font-size:24px;font-weight:900;color:#c49a20">${fas.length}</div>
            <div style="font-size:9.5px;color:#64748b;font-weight:600;letter-spacing:.06em">FREE AGENTS</div>
          </div>
          ${pending.length?`<div style="text-align:center;padding:10px 16px;background:rgba(239,68,68,.08);border:1.5px solid rgba(239,68,68,.3);border-radius:var(--rs)">
            <div style="font-size:24px;font-weight:900;color:var(--err)">${pending.length}</div>
            <div style="font-size:9.5px;color:#64748b;font-weight:600;letter-spacing:.06em">AWAITING REVIEW</div>
          </div>`:''}
          <div style="text-align:center;padding:10px 16px;background:rgba(34,197,94,.07);border:1px solid rgba(34,197,94,.2);border-radius:var(--rs)">
            <div style="font-size:24px;font-weight:900;color:var(--ok)">${placed.length}</div>
            <div style="font-size:9.5px;color:#64748b;font-weight:600;letter-spacing:.06em">PLACED</div>
          </div>
        </div>
      </div>
    </div>
    <!-- Tabs -->
    <div style="display:flex;gap:4px;overflow-x:auto;margin-bottom:16px;padding-bottom:2px">
      ${faTabBtn('agents','Active Free Agents')}
      ${faTabBtn('queue','Transfer Verification', pending.length||'')}
      ${faTabBtn('history','Placement History')}
    </div>`;

  // ── TAB: ACTIVE FREE AGENTS ────────────────────────────────────
  if(tab==='agents'){
    const faBeltBar=(fa)=>BELT_ORDER.filter(b=>beltIdx(b)<=beltIdx(fa.belt)).map(b=>`<span style="display:inline-flex;align-items:center;gap:3px;margin-right:4px;margin-bottom:2px;background:${BELT_BG[b]};border:1px solid ${BELT_CLR[b]}33;border-radius:10px;padding:1px 7px;font-size:10px;font-weight:600;color:${BELT_CLR[b]}">${b}</span>`).join('');

    html+=fas.length===0?`<div class="card"><div class="empty-state" style="padding:60px 20px">
      <div class="empty-ttl">Registry is Empty</div>
      <div class="empty-desc">Staff released from a facility will appear here. All transfers require dual-admin verification before execution.</div>
    </div></div>`:`<div class="card"><div class="card-hd"><div class="card-ttl">Active Free Agents</div><span class="pill p-muted">${fas.length} on record</span></div>
      <div style="display:flex;flex-direction:column;gap:0">${fas.map((fa,idx)=>{
        const pts=calcPoints(fa);
        const hist=fa.facilityHistory||[];
        const psStars=calcTotalPSStars(fa);
        return`<div style="padding:16px;border-bottom:1px solid rgba(255,255,255,.06)${idx===fas.length-1?';border-bottom:none':''}">
          <div style="display:flex;align-items:flex-start;gap:14px;flex-wrap:wrap">
            <div style="display:flex;flex-direction:column;align-items:center;gap:6px;flex-shrink:0">
              <div style="width:44px;height:44px;border-radius:50%;background:${BELT_CLR[fa.belt]||'#888'}22;border:2px solid ${BELT_CLR[fa.belt]||'#888'};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:${BELT_CLR[fa.belt]||'#dde3f0'}">${userInitials(fa)}</div>
              ${beltBadge(fa.belt)}
            </div>
            <div style="flex:1;min-width:200px">
              <div style="font-size:15px;font-weight:800;margin-bottom:2px">${fullName(fa)}</div>
              <div style="font-size:12px;color:#94a3b8;margin-bottom:6px">${fa.role}</div>
              <div style="display:flex;flex-wrap:wrap;gap:5px;margin-bottom:7px">
                <span style="background:rgba(196,154,32,.1);color:#c49a20;border:1px solid rgba(196,154,32,.25);border-radius:10px;padding:2px 9px;font-size:11px;font-weight:700">${pts.toLocaleString()} pts</span>
                ${psStars>0?`<span style="background:rgba(234,179,8,.1);color:#eab308;border:1px solid rgba(234,179,8,.25);border-radius:10px;padding:2px 9px;font-size:11px;font-weight:700">${Array(psStars).fill('\u2605').join('')} PS</span>`:''}
                <span class="pill p-muted">Released ${fa.releasedAt||'--'}</span>
                <span class="pill p-muted">From: ${fa.releasedFrom||'--'}</span>
              </div>
              <div style="display:flex;flex-wrap:wrap;gap:3px;margin-bottom:6px">${faBeltBar(fa)}</div>
            </div>
            <div style="display:flex;flex-direction:column;gap:6px;flex-shrink:0">
              <button class="btn btn-gold btn-sm" onclick="openAssignFreeAgentModal('${fa.id}')">${ICO.plus} Assign to Facility</button>
              <button class="btn btn-ghost btn-sm" onclick="openFreeAgentFullReport('${fa.id}')">${ICO.view} Full Record</button>
              <button class="btn btn-ghost btn-sm" onclick="downloadFreeAgentReport('${fa.id}')">${ICO.dl} Download</button>
              <button class="btn btn-err btn-xs" onclick="confirmPurgeFreeAgent('${fa.id}')">${ICO.x} Remove</button>
            </div>
          </div>
        </div>`;
      }).join('')}</div></div>`;
  }

  // ── TAB: TRANSFER VERIFICATION QUEUE ──────────────────────────
  else if(tab==='queue'){
    const statusBadge=(tr)=>{
      if(tr.status==='pending') return `<span class="pill p-warn" style="font-size:10px">Awaiting Verification</span>`;
      if(tr.status==='approved') return `<span class="pill p-ok" style="font-size:10px">Approved by ${tr.approvedByName||'Admin'}</span>`;
      if(tr.status==='denied') return `<span class="pill p-err" style="font-size:10px">Denied by ${tr.deniedByName||'Admin'}</span>`;
      return '';
    };
    const typeBadge=(tr)=>tr.type==='release'
      ?`<span class="pill p-err" style="font-size:10px">Release</span>`
      :`<span class="pill p-ok" style="font-size:10px">Assignment</span>`;
    const canApprove=(tr)=>tr.status==='pending' && tr.requestedBy !== myUserId;
    const selfRequest=(tr)=>tr.status==='pending' && tr.requestedBy === myUserId;

    html+=`<div class="card" style="margin-bottom:14px">
      <div style="background:rgba(245,158,11,.05);border-radius:var(--rs);padding:11px 14px;margin-bottom:0;font-size:12px;color:var(--txt2);border-bottom:1px solid var(--bdr)">
        <strong style="color:var(--warn)">Dual-Admin Verification Required.</strong> Every release and assignment must be approved by a second SIPS Master Admin who did not initiate the request. This protects against accidental or unauthorized transfers.
      </div>
      ${allTransfers.length===0?`<div class="empty-state" style="padding:40px 20px"><div class="empty-ttl">No Transfer Activity</div><div class="empty-desc">Release and assignment requests will appear here for verification.</div></div>`:`
      <div style="overflow-x:auto"><table class="tbl tbl-static" style="min-width:600px">
        <thead><tr><th>Staff Member</th><th>Belt</th><th>Type</th><th>Movement</th><th>Requested By</th><th>Date</th><th>Status</th><th>Actions</th></tr></thead>
        <tbody>${allTransfers.map(tr=>`<tr style="background:${tr.status==='pending'?'rgba(245,158,11,.03)':'transparent'}">
          <td class="fw7">${cleanName(tr.staffName)||'Unknown'}</td>
          <td>${beltBadge(tr.belt||'White')}</td>
          <td>${typeBadge(tr)}</td>
          <td style="font-size:11.5px;color:var(--txt2)">${tr.fromFacName} &rarr; ${tr.toFacName}</td>
          <td style="font-size:11.5px;color:var(--txt3)">${tr.requestedByName||'Admin'}</td>
          <td style="font-size:11.5px;color:var(--txt3)">${tr.requestedAt||'--'}</td>
          <td>${statusBadge(tr)}${tr.status==='denied'&&tr.denyReason?`<div style="font-size:10.5px;color:var(--txt3);margin-top:3px">${tr.denyReason}</div>`:''}</td>
          <td onclick="event.stopPropagation()" style="min-width:180px">${canApprove(tr)?`
              <div style="display:flex;gap:5px">
                <button class="btn btn-ok btn-xs" onclick="approveTransfer('${tr.id}')">${ICO.check} Approve</button>
                <button class="btn btn-err btn-xs" onclick="denyTransfer('${tr.id}')">${ICO.x} Deny</button>
              </div>`
            :selfRequest(tr)?`<span style="font-size:11px;color:var(--warn);font-style:italic">Your request – awaiting another admin</span>`
            :`<span style="font-size:11px;color:var(--txt3)">${tr.status==='approved'?'Executed on '+tr.approvedAt:'Denied on '+tr.deniedAt}</span>`}
          </td>
        </tr>`).join('')}</tbody>
      </table></div>`}
    </div>`;
  }

  // ── TAB: PLACEMENT HISTORY ─────────────────────────────────────
  else if(tab==='history'){
    html+=placed.length===0?`<div class="card"><div class="empty-state" style="padding:60px 20px">
      <div class="empty-ttl">No Placements Yet</div>
      <div class="empty-desc">Every completed transfer (release or assignment) will be logged here permanently for audit and network intelligence.</div>
    </div></div>`:`
    <div class="card" style="margin-bottom:14px">
      <div class="card-hd"><div class="card-ttl">Placement Log</div><span class="pill p-muted">${placed.length} records</span></div>
      <div style="overflow-x:auto"><table class="tbl tbl-static" style="min-width:620px">
        <thead><tr><th>Staff Member</th><th>Belt</th><th>From</th><th>To</th><th>Outcome</th><th>Released</th><th>Placed</th><th>By</th></tr></thead>
        <tbody>${placed.map(pl=>`<tr>
          <td class="fw7">${pl.faName||'--'}</td>
          <td>${beltBadge(pl.belt||'White')}</td>
          <td style="font-size:11.5px;color:var(--txt3)">${pl.fromFacName||'--'}</td>
          <td style="font-size:11.5px;font-weight:600;color:${pl.outcome==='placed'?'var(--ok)':'var(--txt2)'}">${pl.toFacName||'--'}</td>
          <td><span class="pill ${pl.outcome==='placed'?'p-ok':pl.outcome==='released'?'p-warn':'p-muted'}" style="font-size:10px">${(pl.outcome||'--').charAt(0).toUpperCase()+(pl.outcome||'--').slice(1)}</span></td>
          <td style="font-size:11.5px;color:var(--txt3)">${pl.releasedAt||'--'}</td>
          <td style="font-size:11.5px;color:var(--txt3)">${pl.assignedAt||'--'}</td>
          <td style="font-size:11.5px;color:var(--txt3)">${pl.assignedBy||'--'}</td>
        </tr>`).join('')}</tbody>
      </table></div>
    </div>
    <div style="background:var(--s2);border:1px solid var(--bdr);border-radius:var(--rs);padding:12px 16px;font-size:12px;color:var(--txt3)">
      This log is permanent and cannot be edited. Every placement is recorded at the time of approval for full audit traceability.
    </div>`;
  }

  el.innerHTML=html;
}

function openFreeAgentProfile(faId){
  const fa=DB.freeAgents.find(f=>f.id===faId);
  if(!fa){toast('Record not found.','err');return;}
  const pts=calcPoints(fa);
  const hist=fa.facilityHistory||[];
  const psStars=calcTotalPSStars(fa);
  const oipHtml=fa.oip&&fa.oip.completed&&fa.oip.primaryType?(()=>{
    const t=OIP_TYPES[fa.oip.primaryType];
    const s2=OIP_TYPES[fa.oip.secondaryType];
    return `<div style="display:flex;align-items:center;gap:10px;padding:10px 0">
      <div style="width:36px;height:36px;border-radius:8px;background:${t.bg};border:1.5px solid ${t.bd};display:flex;align-items:center;justify-content:center;font-size:20px">${t.icon}</div>
      <div><div style="font-size:13px;font-weight:700;color:${t.color}">${t.name} <span style="font-size:11px;color:#64748b;font-weight:400">(${s2?s2.name+' secondary':''})</span></div>
      <div style="font-size:11.5px;color:#94a3b8">${t.label}</div></div>
    </div>`;
  })():'<div style="font-size:12px;color:#64748b">OIP not completed</div>';

  openModal(`Free Agent Record \u2014 ${fullName(fa)}`,`
    <div class="modal-body">
      <div style="background:rgba(196,154,32,.06);border:1px solid rgba(196,154,32,.2);border-radius:var(--rs);padding:10px 12px;margin-bottom:14px;font-size:11.5px;color:#94a3b8">
        ${ICO.check} This is a SIPS-verified record. All belt certifications and history are authenticated by SIPS Healthcare Solutions.
      </div>
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:16px">
        <div style="width:52px;height:52px;border-radius:12px;background:${BELT_CLR[fa.belt]||'#888'}22;border:2px solid ${BELT_CLR[fa.belt]||'#888'};display:flex;align-items:center;justify-content:center;font-size:18px;font-weight:800;color:${BELT_CLR[fa.belt]||'#dde3f0'};flex-shrink:0">${userInitials(fa)}</div>
        <div><div style="font-size:18px;font-weight:800">${fullName(fa)}</div>
          <div style="font-size:12px;color:#94a3b8;margin-bottom:4px">${fa.role}</div>
          ${beltBadge(fa.belt)} <span style="font-size:12px;color:#64748b;margin-left:6px">${BELT_CERT[fa.belt]}</span>
        </div>
      </div>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-bottom:14px">
        <div class="irow"><div class="ilbl">Points</div><div class="ival" style="color:#c49a20;font-weight:800">${pts.toLocaleString()}</div></div>
        <div class="irow"><div class="ilbl">PS Stars</div><div class="ival" style="color:#eab308">${psStars>0?Array(psStars).fill('\u2605').join(' '):'None'}</div></div>
        <div class="irow"><div class="ilbl">Belt Since</div><div class="ival">${fa.since}</div></div>
        <div class="irow"><div class="ilbl">Released</div><div class="ival">${fa.releasedAt||'--'}</div></div>
        <div class="irow" style="grid-column:1/-1"><div class="ilbl">Release Reason</div><div class="ival">${fa.releaseReason||'Not specified'}</div></div>
      </div>
      <div class="section-lbl" style="margin-bottom:6px">OIP Operator Profile</div>
      ${oipHtml}
      <div class="section-lbl" style="margin-bottom:6px;margin-top:12px">Facility Employment History</div>
      ${hist.length?`<div class="tl">${hist.map(h=>`<div class="tl-item"><div class="tl-dot" style="background:rgba(96,165,250,.15);color:#60a5fa;font-size:9px">&#9679;</div><div><div class="tl-date">${h.from} \u2013 ${h.to}</div><div class="tl-txt">${h.facName}<span style="font-size:11px;color:#64748b;margin-left:6px">${h.loc||''}</span></div></div></div>`).join('')}</div>`:
      '<div style="font-size:12px;color:#64748b">No facility history recorded.</div>'}
      <div class="section-lbl" style="margin-bottom:6px;margin-top:12px">Full Assessment History</div>
      <div class="tl">${(fa.history||[]).length?(fa.history||[]).slice().reverse().map(h=>`<div class="tl-item"><div class="tl-dot" style="background:${h.res==='pass'?'rgba(34,197,94,.15)':'rgba(239,68,68,.15)'};color:${h.res==='pass'?'#22c55e':'#ef4444'}">${h.res==='pass'?ICO.check:ICO.x}</div><div><div class="tl-date">${h.dt} &bull; ${beltBadge(h.belt)}</div><div class="tl-txt">${h.type} \u2014 <strong style="color:${h.res==='pass'?'#22c55e':'#ef4444'}">${h.res==='pass'?'Pass':'Fail'}</strong>${h.note?' \u2014 '+h.note:''}</div></div></div>`).join(''):'<div style="font-size:12px;color:#64748b">No assessment history.</div>'}</div>
      <div style="margin-top:16px;padding-top:14px;border-top:1px solid var(--bdr)">
        <div style="font-size:11px;color:var(--txt3);margin-bottom:10px">View this free agent's complete staff report as it would appear on an active site assignment.</div>
        <button class="btn btn-gold" style="width:100%;justify-content:center" onclick="openFreeAgentFullReport('${fa.id}')">View Full Staff Report</button>
      </div>
    </div>
    <div class="modal-ft">
      <button class="btn btn-ghost" onclick="closeModal()">Close</button>
      <button class="btn btn-gold" onclick="closeModal();openAssignFreeAgentModal('${fa.id}')">Assign to Facility</button>
    </div>`,'modal-lg');
}

function openAssignFreeAgentModal(faId){
  const fa=DB.freeAgents.find(f=>f.id===faId);
  if(!fa){toast('Record not found.','err');return;}
  const opts=DB.facilities.filter(f=>f.active!==false).map(f=>`<option value="${f.id}">${f.name}${f.loc?` \u2014 ${f.loc}`:''}</option>`).join('');
  openModal(`Assign ${fullName(fa)} to Facility`,`
    <div class="modal-body">
      <div style="padding:10px 12px;background:rgba(34,197,94,.07);border:1px solid rgba(34,197,94,.2);border-radius:var(--rs);margin-bottom:14px;font-size:12px;color:#94a3b8;line-height:1.5">
        Assigning this staff member will transfer their complete belt record, assessment history, OIP profile, and Position School progress to the new facility. Their free agent status will be cleared.
      </div>
      <div class="form-group"><label class="form-label">Facility *</label>
        <select class="form-select" id="fa-assign-fid">${opts}</select>
      </div>
      <div class="form-group"><label class="form-label">Effective Date</label>
        <input type="date" class="form-input" id="fa-assign-date" value="${new Date().toISOString().slice(0,10)}">
      </div>
      <div class="form-group"><label class="form-label">Notes (optional)</label>
        <textarea class="form-textarea" id="fa-assign-notes" placeholder="Reason for placement, client notes..."></textarea>
      </div>
    </div>
    <div class="modal-ft">
      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-gold" onclick="executeFreeAgentAssign('${faId}')">${ICO.check} Confirm Placement</button>
    </div>`,'modal-md');
}

function executeFreeAgentAssign(faId){
  const fa=DB.freeAgents.find(f=>f.id===faId);
  if(!fa){toast('Record not found.','err');return;}
  const fid=document.getElementById('fa-assign-fid')?.value;
  const date=document.getElementById('fa-assign-date')?.value||new Date().toISOString().slice(0,10);
  const notes=document.getElementById('fa-assign-notes')?.value||'';
  if(!fid){toast('Please select a facility.','err');return;}
  const fac=getFac(fid);
  const adminName=(ST.user&&(ST.user.name||ST.user.email))||'Admin';

  if(!DB.pendingTransfers) DB.pendingTransfers=[];

  const transfer={
    id:'tr-'+Date.now(),
    type:'assignment',
    faId,
    staffName: fullName(fa),
    belt: fa.belt,
    fromFacId: null,
    fromFacName: 'Free Agent Pool',
    toFacId: fid,
    toFacName: fac?.name||fid,
    toFacLoc: fac?.loc||'',
    requestedBy: ST.user?.id||'admin',
    requestedByName: adminName,
    requestedAt: new Date().toISOString().slice(0,10),
    reason: 'Facility assignment',
    notes,
    effectDate: date,
    status:'pending',
    faSnapshot: {...fa}
  };

  DB.pendingTransfers.push(transfer);
  if(IS_LIVE){
    SB.assignFreeAgentRemote(transfer).catch(e => handleSyncError(e, 'Assign sync'));
  } else {
    /* saveDemoData() removed */
  }
  closeModal();
  toast(`Assignment request submitted for <strong>${fullName(fa)}</strong> to <strong>${fac?.name||fid}</strong>. Awaiting second-admin verification.`,'ok');
  updateFANB();
  renderAFreeAgents();
}

function confirmPurgeFreeAgent(faId){
  const fa=DB.freeAgents.find(f=>f.id===faId);
  if(!fa)return;
  openModal('Remove Free Agent Record',`
    <div class="modal-body">
      <div style="text-align:center;padding:8px 0 14px">
        <div style="width:48px;height:48px;border-radius:50%;background:var(--err-bg);border:2px solid var(--err-bd);display:flex;align-items:center;justify-content:center;margin:0 auto 14px">
          <svg width="20" height="20" viewBox="0 0 18 18" fill="none"><path d="M9 6v5M9 13v.5" stroke="var(--err)" stroke-width="1.8" stroke-linecap="round"/><path d="M7.5 2.5L2 14h14L10.5 2.5h-3z" stroke="var(--err)" stroke-width="1.5" stroke-linejoin="round"/></svg>
        </div>
        <div style="font-size:15px;font-weight:700;margin-bottom:6px">Remove ${fullName(fa)}?</div>
        <div style="font-size:12.5px;color:#94a3b8;line-height:1.6">This will permanently remove <strong>${fullName(fa)}</strong> from the Free Agent Registry. Their belt history and verified record will no longer be accessible through SIPS. This action cannot be undone.</div>
      </div>
    </div>
    <div class="modal-ft">
      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-err" onclick="executePurgeFreeAgent('${faId}')">${ICO.x} Remove Record</button>
    </div>`,'modal-sm');
}

function executePurgeFreeAgent(faId){
  const fa=DB.freeAgents.find(f=>f.id===faId);
  if(!fa)return;
  DB.freeAgents=DB.freeAgents.filter(f=>f.id!==faId);
  if(IS_LIVE){
    sbFetch(`/rest/v1/free_agents?id=eq.${faId}`,{method:'DELETE'}).catch(e => handleSyncError(e, 'Purge sync'));
  } else {
    /* saveDemoData() removed */
  }
  closeModal();
  toast(`${fullName(fa)}'s record removed from Free Agent Registry.`,'err');
  updateFANB();
  renderAFreeAgents();
}

// Called from staff profile  --  releases a staff member to the free agent pool
function releaseToFreeAgent(staffId){
  const s=getStaff(staffId);
  if(!s){toast('Staff record not found.','err');return;}
  const fac=getFac(s.fid);
  openModal(`Release ${fullName(s)} to Free Agent Registry`,`
    <div class="modal-body">
      <div style="padding:10px 12px;background:rgba(239,68,68,.07);border:1px solid rgba(239,68,68,.2);border-radius:var(--rs);margin-bottom:14px;font-size:12px;color:#94a3b8;line-height:1.5">
        <strong style="color:#ef4444">This removes the staff member from ${fac?.name||'the facility'}.</strong> Their complete belt record is preserved in the Free Agent Registry. They can be assigned to a new facility at any time.
      </div>
      <div style="display:flex;align-items:center;gap:12px;margin-bottom:14px;padding:12px;background:#131829;border-radius:var(--rs)">
        <div style="width:40px;height:40px;border-radius:10px;background:${BELT_CLR[s.belt]||'#888'}22;border:2px solid ${BELT_CLR[s.belt]||'#888'};display:flex;align-items:center;justify-content:center;font-size:14px;font-weight:800;color:${BELT_CLR[s.belt]||'#dde3f0'};flex-shrink:0">${userInitials(s)}</div>
        <div><div style="font-size:13.5px;font-weight:700">${fullName(s)}</div>
        <div style="font-size:11.5px;color:#94a3b8">${s.role} &bull; ${s.belt} Belt &bull; ${fac?.name||'--'}</div></div>
      </div>
      <div class="form-group"><label class="form-label">Release Date</label>
        <input type="date" class="form-input" id="fa-rel-date" value="${new Date().toISOString().slice(0,10)}">
      </div>
      <div class="form-group"><label class="form-label">Reason for Release</label>
        <select class="form-select" id="fa-rel-reason">
          <option value="Resignation">Resignation</option>
          <option value="Facility closure">Facility closure</option>
          <option value="Position elimination">Position elimination</option>
          <option value="Transfer request">Transfer request</option>
          <option value="Contract end">Contract end</option>
          <option value="Other">Other</option>
        </select>
      </div>
      <div class="form-group"><label class="form-label">Notes (optional)</label>
        <textarea class="form-textarea" id="fa-rel-notes" placeholder="Performance notes, re-hire recommendation, etc."></textarea>
      </div>
    </div>
    <div class="modal-ft">
      <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
      <button class="btn btn-err" onclick="executeReleaseToFA('${staffId}')">Release to Free Agent Registry</button>
    </div>`,'modal-md');
}

function executeReleaseToFA(staffId){
  const s=getStaff(staffId);
  if(!s){toast('Staff record not found.','err');return;}
  const fac=getFac(s.fid);
  const date=document.getElementById('fa-rel-date')?.value||new Date().toISOString().slice(0,10);
  const reason=document.getElementById('fa-rel-reason')?.value||'Other';
  const notes=document.getElementById('fa-rel-notes')?.value||'';
  const adminName=(ST.user&&(ST.user.name||ST.user.email))||'Admin';

  if(!DB.pendingTransfers) DB.pendingTransfers=[];

  const transfer={
    id:'tr-'+Date.now(),
    type:'release',
    staffId: s.id,
    staffName: fullName(s),
    belt: s.belt,
    fromFacId: s.fid,
    fromFacName: fac?.name||'--',
    toFacId: null,
    toFacName: 'Free Agent Pool',
    requestedBy: ST.user?.id||'admin',
    requestedByName: adminName,
    requestedAt: new Date().toISOString().slice(0,10),
    reason, notes,
    effectDate: date,
    status:'pending',
    staffSnapshot: {...s}
  };

  DB.pendingTransfers.push(transfer);
  if(IS_LIVE){
    SB.releaseToFreeAgentRemote(transfer).catch(e => handleSyncError(e, 'Release sync'));
  } else {
    /* saveDemoData() removed */
  }
  closeModal();
  toast(`Release request submitted for <strong>${fullName(s)}</strong>. Awaiting second-admin verification before execution.`,'ok');
  updateFANB();
  if(ST.aView==='a-facility') renderFacTab();
  else if(ST.aView) renderAView(ST.aView);
  if(ST.hView==='h-staff') renderHStaff();
}


