function confirmRemoveUser(uid){
  const u=DB.users.find(x=>x.id===uid);
  if(!u)return;
  // Hard block on protected SIPS Master Admins
  if(u.protected){
    openModal('Cannot Remove Protected Account',`
      <div class="modal-body">
        <div style="text-align:center;padding:8px 0 16px">
          <div style="width:48px;height:48px;border-radius:50%;background:rgba(196,154,32,.12);border:2px solid rgba(196,154,32,.4);display:flex;align-items:center;justify-content:center;margin:0 auto 14px">
            <svg width="22" height="22" viewBox="0 0 18 18" fill="none"><path d="M9 2l6 3v5c0 3.5-2.5 6-6 7-3.5-1-6-3.5-6-7V5l6-3z" stroke="#c49a20" stroke-width="1.5" stroke-linejoin="round"/></svg>
          </div>
          <div style="font-size:15px;font-weight:700;margin-bottom:8px;color:#c49a20">Protected System Account</div>
          <div style="font-size:12.5px;color:#94a3b8;line-height:1.7"><strong style="color:#dde3f0">${u.name}</strong> is a protected SIPS Master Admin. These accounts hold system-level authority and are hardcoded into the platform. They cannot be removed by any user, including other Master Admins.</div>
        </div>
      </div>
      <div class="modal-ft"><button class="btn btn-ghost" onclick="closeModal()">Close</button></div>`,'modal-sm');
    return;
  }
  const roleLabel={master_admin:'Master Admin',staff_admin:'Assessor',system_admin:'System Admin',hospital:'Hospital Manager',facility_admin:'Facility Admin',staff_member:'Staff Member'}[u.role]||u.role;
  openModal('Remove User',`
    <div class="modal-body">
      <div style="text-align:center;padding:8px 0 16px">
        <div style="width:48px;height:48px;border-radius:50%;background:var(--err-bg);border:2px solid var(--err-bd);display:flex;align-items:center;justify-content:center;margin:0 auto 14px">
          <svg width="20" height="20" viewBox="0 0 18 18" fill="none"><path d="M9 6v5M9 13v.5" stroke="var(--err)" stroke-width="1.8" stroke-linecap="round"/><path d="M7.5 2.5L2 14h14L10.5 2.5h-3z" stroke="var(--err)" stroke-width="1.5" stroke-linejoin="round"/></svg>
        </div>
        <div style="font-size:15px;font-weight:700;margin-bottom:6px">Remove ${u.name}?</div>
        <div style="font-size:12.5px;color:var(--txt2);line-height:1.6">This will permanently remove the <strong>${roleLabel}</strong> account for <strong>${u.email}</strong>. This action cannot be undone.</div>
      </div>
    </div>
    <div class="modal-ft"><button class="btn btn-ghost" onclick="closeModal()">Cancel</button><button class="btn btn-err" onclick="executeRemoveUser('${uid}')">${ICO.x} Remove Account</button></div>`,'modal-sm');
}

async function executeRemoveUser(uid){
  const u=DB.users.find(x=>x.id===uid);
  if(!u)return;
  if(u.protected){toast('This account is protected and cannot be removed.','err');return;}
  
  try {
    if(IS_LIVE){
      toast(`Removing ${u.name}...`, 'info');
      const res = await SB.syncUserClaims({action:'delete', userId:uid});
      // Edge function returns { error: '...' } on failure, { success: true, deleted: {...} } on success
      if(res && res.error) throw new Error(res.error);
      if(res && !res.success) throw new Error('Remove failed — unexpected response');
    }
    // Clean up local state: remove from users array
    DB.users=DB.users.filter(x=>x.id!==uid);
    // Also remove from staff array if linked (by auth_uid)
    if(u.authUid) DB.staff=DB.staff.filter(x=>x.id!==u.authUid);
    
    closeModal();
    toast(`${u.name}'s account has been removed.`,'ok');
    
    if(IS_LIVE) setTimeout(()=>initAppData(), 1500);
    renderAAdminUsers();
  } catch(e) {
    toast('Remove user failed: '+e.message, 'err');
  }
}

