// ─── Schedule CSV template ────────────────────────────────────────────────────
function downloadScheduleCSVTemplate(){
  const fid=ST.curFid||ST.hFid||DB.facilities[0]?.id;
  const st=staffOf(fid);
  const notes=[
    '# SBD Schedule Upload Template – SIPS Healthcare Solutions',
    '# date format: YYYY-MM-DD',
    '# shift: AM / PM / NOC (or any custom shift code for this facility)',
    '# first_name and last_name must match exactly the staff record name',
    '',
  ];
  const header='date,shift,first_name,last_name';
  const today=todayStr();
  const examples=st.slice(0,6).map((s,i)=>{
    const d=new Date(today+'T12:00:00'); d.setDate(d.getDate()+Math.floor(i/2));
    const shift=i%3===0?'AM':i%3===1?'PM':'NOC';
    return `${d.toISOString().slice(0,10)},${shift},${s.first},${s.last}`;
  });
  const csv=[...notes,header,...examples].join('\n');
  const blob=new Blob([csv],{type:'text/csv'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download='sbd_schedule_upload_template.csv'; a.click();
  URL.revokeObjectURL(url);
  toast('Schedule template downloaded.','ok');
}

