let _schedImportRows = [];

function parseScheduleCSV(text){
  const lines = text.split('\n').map(l=>l.trim()).filter(l=>l&&!l.startsWith('#'));
  if(!lines.length) return {rows:[],errors:['Empty file']};
  const header = lines[0].toLowerCase().split(',').map(h=>h.trim());
  const colDate  = header.indexOf('date');
  const colShift = header.indexOf('shift');
  const colFirst = header.indexOf('first_name');
  const colLast  = header.indexOf('last_name');
  if(colDate<0||colShift<0||colFirst<0||colLast<0){
    return {rows:[],errors:['Missing required columns: date, shift, first_name, last_name']};
  }
  const rows=[]; const errors=[];
  lines.slice(1).forEach((line,i)=>{
    const cols=line.split(',').map(c=>c.trim().replace(/^"|"$/g,''));
    const date=cols[colDate]||'';
    const shift=(cols[colShift]||'').toUpperCase();
    const first=(cols[colFirst]||'').toLowerCase();
    const last =(cols[colLast ]||'').toLowerCase();
    if(!/^\d{4}-\d{2}-\d{2}$/.test(date)){ errors.push(`Row ${i+2}: invalid date "${date}"`); return; }
    if(!shift){ errors.push(`Row ${i+2}: missing shift`); return; }
    rows.push({date,shift,first,last,_line:i+2});
  });
  return {rows,errors};
}

function previewScheduleCSV(fid){
  const file = document.getElementById('sched-csv-file')?.files[0];
  if(!file){ toast('Please select a CSV file first.','err'); return; }
  const reader=new FileReader();
  reader.onload=function(e){
    const {rows,errors}=parseScheduleCSV(e.target.result);
    const st=staffOf(fid);
    const previewEl=document.getElementById('sched-preview');
    const contentEl=document.getElementById('sched-preview-content');
    const errEl=document.getElementById('sched-errors');
    const importBtn=document.getElementById('sched-import-btn');
    _schedImportRows=[];

    // Match staff by name
    const matched=[], unmatched=[];
    rows.forEach(row=>{
      const staff=st.find(s=>s.first.toLowerCase()===row.first&&s.last.toLowerCase()===row.last);
      if(staff){ matched.push({...row,staffId:staff.id,staffName:fullName(staff)}); _schedImportRows.push({...row,staffId:staff.id}); }
      else { unmatched.push(row); }
    });

    // Preview table
    const previewRows=[...matched.slice(0,20),...unmatched.slice(0,5)].map(r=>{
      const isMatch=r.staffId;
      const tag=isMatch?' → <strong>'+r.staffName+'</strong>':'<span style="color:#ef4444"> NOT FOUND</span>';
      return '<div style="display:flex;gap:8px;padding:4px 0;border-bottom:1px solid var(--bdr);font-size:11px;align-items:center">'
        +'<span style="color:'+(isMatch?'#22c55e':'#ef4444')+';font-size:14px">'+(isMatch?'✓':'✗')+'</span>'
        +'<span style="min-width:80px">'+r.date+'</span>'
        +'<span style="min-width:40px">'+r.shift+'</span>'
        +'<span style="flex:1">'+r.first+' '+r.last+tag+'</span>'
        +'</div>';
    }).join('');

    if(previewEl) previewEl.style.display='block';
    if(contentEl) contentEl.innerHTML='<div style="font-size:11px;color:var(--txt3);margin-bottom:6px">'+matched.length+' matched &bull; '+unmatched.length+' unmatched</div>'+previewRows+(rows.length>25?'<div style="font-size:11px;color:var(--txt3);padding-top:6px">...and '+(rows.length-25)+' more rows</div>':'');
    if(errEl){
      errEl.style.display=errors.length||unmatched.length?'block':'none';
      errEl.innerHTML=errors.map(e=>'<div style="color:#ef4444;font-size:11.5px;padding:3px 0">⚠ '+e+'</div>').join('')
        +(unmatched.length?'<div style="color:#eab308;font-size:11.5px;margin-top:4px">⚠ '+unmatched.length+' staff not matched: '+unmatched.slice(0,3).map(r=>r.first+' '+r.last).join(', ')+(unmatched.length>3?'...':'')+'</div>':'');
    }
    if(importBtn) importBtn.disabled = matched.length===0;
  };
  reader.readAsText(file);
}

function importScheduleCSV(fid){
  if(!_schedImportRows.length){ toast('No matched rows to import.','err'); return; }
  const shifts=getFacilityShifts(fid);

  // Group by date+shift
  const grouped={};
  _schedImportRows.forEach(row=>{
    const key=`${row.date}::${row.shift}`;
    if(!grouped[key]) grouped[key]={date:row.date,shift:row.shift,staffIds:[]};
    if(!grouped[key].staffIds.includes(row.staffId)) grouped[key].staffIds.push(row.staffId);
  });

  let imported=0;
  Object.values(grouped).forEach(g=>{
    const existing=DB.schedule.find(s=>s.fid===fid&&s.date===g.date&&s.shift===g.shift);
    if(existing){ existing.assignedStaff=g.staffIds; }
    else {
      const bulkSched={id:'sch-'+DB.schNextId++,fid,date:g.date,shift:g.shift,assignedStaff:g.staffIds,publishedBy:ST.user?.id||'',notes:'CSV import'};
      if(IS_LIVE){ SB.createSchedule(mapScheduleToBackend(bulkSched)).catch(e => { if (e instanceof ReferenceError || e instanceof TypeError || e instanceof SyntaxError) throw e; }); }
      DB.schedule.push(bulkSched);
    }
    imported++;
  });

  closeModal();
  toast(`Schedule imported: ${_schedImportRows.length} assignments across ${imported} shifts.`,'ok');
  _schedImportRows=[];
  if(ST.portal==='h'){ if(ST.hView==='h-attendance') renderHAttendance(); else renderHSchedule(); }
  if(ST.portal==='x') renderXSchedule();
}

function processBulkUpload(){
  if(!_bulkStaffFile){
    toast('Please select a CSV file first.', 'warn');
    return;
  }
  const reader = new FileReader();
  reader.onload = async (e) => {
    const text = e.target.result;
    const lines = text.split(/\r?\n/);
    if(lines.length < 2) {
      toast('CSV appears empty or missing headers.', 'warn');
      return;
    }
    const headers = lines[0].toLowerCase().split(',').map(s => s.trim());
    
    // Map column names to indexes
    const colFac = headers.findIndex(h => h.includes('facility'));
    const colFirst = headers.findIndex(h => h.includes('first'));
    const colLast = headers.findIndex(h => h.includes('last'));
    const colBelt = headers.findIndex(h => h.includes('belt'));
    const colRole = headers.findIndex(h => h.includes('role'));
    const colSince = headers.findIndex(h => h.includes('since') || h.includes('start'));

    if(colFirst === -1 || colLast === -1) {
      toast('CSV must contain "First" and "Last" columns.', 'err');
      return;
    }

    const payload = [];
    for(let i=1; i<lines.length; i++){
      const rawRow = lines[i];
      if(!rawRow.trim()) continue; // skip blank
      // standard split by comma (ignoring quoted CSV features for simplicity as instructed by scope)
      const row = rawRow.split(',').map(s=>s.trim().replace(/^"|"$/g, ''));
      if(row.length < 2) continue;
      payload.push({
        facilityName: colFac>=0 ? row[colFac] : '',
        first: row[colFirst],
        last: row[colLast],
        belt: colBelt>=0 ? row[colBelt] : 'White',
        role: colRole>=0 ? row[colRole] : 'SPD Tech',
        since: colSince>=0 ? row[colSince] : ''
      });
    }

    toast('Uploading '+payload.length+' records...', 'info');
    closeModal();
    try {
      const res = await SB.bulkUploadStaff(payload);
      if(res.error) throw new Error(res.error || res.detail || 'Upload failed');
      const { successCount, failureCount, errors } = res;
      if(failureCount === 0) {
        toast('Bulk upload successful! Added '+successCount+' staff members.', 'ok');
      } else {
        console.error('Bulk Upload Errors:', errors);
        toast('Partial success. '+successCount+' added, '+failureCount+' failures. Check console.', 'warn');
      }
      setTimeout(()=>{ initAppData(); }, 2000); // refresh the entire application view cleanly
    } catch(err) {
      toast('Bulk Upload Error: '+err.message, 'err');
    }
  };
  reader.readAsText(_bulkStaffFile);
}



