/**
 * Opens a modal to link an existing facility to a hospital system.
 */
function openLinkFacilityModal(systemId, systemName) {
  const unlinkedFacs = DB.facilities.filter(f => !f.systemId || f.systemId === '');
  
  const content = `
    <div style="padding:24px">
      <div style="font-size:18px;font-weight:800;color:#f1f5f9;margin-bottom:6px">Link Facility to System</div>
      <div style="font-size:13px;color:#94a3b8;margin-bottom:24px">Associate an existing facility with <b>${systemName}</b>.</div>
      
      <div style="margin-bottom:20px">
        <label style="display:block;font-size:11px;font-weight:700;color:#64748b;margin-bottom:8px;text-transform:uppercase">Select Unlinked Facility</label>
        <select id="link-fac-id" style="width:100%;max-width:400px;background:#0e1328;border:1px solid rgba(255,255,255,0.1);border-radius:8px;padding:12px;color:#e2e8f0;font-size:14px;font-family:inherit;outline:none">
          <option value="">-- Choose a facility --</option>
          ${unlinkedFacs.map(f => `<option value="${f.id}">${f.name} (${f.dept || 'General'})</option>`).join('')}
        </select>
        ${unlinkedFacs.length === 0 ? `<div style="font-size:11px;color:#ef4444;margin-top:8px">No unlinked facilities available. All facilities currently belong to a system.</div>` : ''}
      </div>
      
      <div style="display:flex;justify-content:flex-end;gap:12px;margin-top:32px">
        <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
        <button class="btn btn-primary" id="link-btn" ${unlinkedFacs.length === 0 ? 'disabled' : ''} style="background:var(--gold);color:#000">Link Facility</button>
      </div>
    </div>
  `;
  
  openModal('Link Facility', content);
  
  // Wait for the modal DOM to be ready
  setTimeout(() => {
    const btn = document.getElementById('link-btn');
    if (btn) {
      btn.onclick = () => {
        const fid = document.getElementById('link-fac-id').value;
        if (!fid) return toast('Please select a facility', 'warn');
        linkFacilityToSystem(fid, systemId);
        closeModal();
      };
    }
  }, 100);
}

/**
 * Persists the facility-system association.
 */
async function linkFacilityToSystem(fid, systemId) {
  const fac = window.DB.facilities.find(f => f.id === fid);
  const sys = window.DB.hospitalSystems.find(s => s.id === systemId);
  if (!fac || !sys) return;

  const isOptimistic = systemId.startsWith('sys-');
  
  if (isOptimistic) {
    toast('Linking optimistically... will auto-commit when sync finishes.', 'info');
    
    // Store in pending links queue (Clear existing for this facility first)
    let pendingLinks = JSON.parse(localStorage.getItem('sbd_pending_links') || '[]');
    pendingLinks = pendingLinks.filter(l => l.facId !== fid);
    pendingLinks.push({ facId: fid, tempSysId: systemId, systemName: sys.name });
    localStorage.setItem('sbd_pending_links', JSON.stringify(pendingLinks));
  } else {
    toast('Linking facility...', 'info');
  }
  
  try {
    if (!isOptimistic && IS_LIVE && (window.SB || SB).updateFacility) {
      // ONLY Update Facility (Many-to-one relationship via system_id column)
      await (window.SB || SB).updateFacility(fid, { system_id: systemId });
    }
    
    // Optimistic update (Memory)
    fac.systemId = systemId;
    if (!sys.facilityIds) sys.facilityIds = [];
    if (!sys.facilityIds.includes(fid)) sys.facilityIds.push(fid);
    
    // Maintain legacy sync
    if (window.DB) {
      window.DB.systems = window.DB.hospitalSystems;
    }
    
    // Recalculate benchmarking stats
    if (typeof calcSystemStats === 'function') calcSystemStats(systemId);
    
    if (isOptimistic) {
      toast(`Facility linked to ${sys.name} (Pending Sync)`, 'ok');
    } else {
      toast('Facility linked successfully', 'ok');
    }
    
    closeModal();
    renderASystems();
    
  } catch (err) {
    console.error('Link Error:', err);
    toast('Error linking facility: ' + err.message, 'err');
  }
}

/**
 * Prompts user to unlink a facility using a styled modal.
 */
function promptUnlinkFacility(fid, facName, systemId) {
  if (window.SBD_INITIALIZING) return; 
  if (!ST.user) return;

  const fac = DB.facilities.find(f => f.id === fid);
  const staffCount = DB.staff.filter(s => s.fid === fid).length;
  const sys = DB.hospitalSystems.find(s => s.id === systemId);

  openModal('Unlink Facility', `
    <div style="padding:20px;text-align:center">
      <div style="width:60px;height:60px;background:var(--warn-bg);color:var(--warn);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 20px;font-size:24px">
        <svg width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M18.36 6.64a9 9 0 1 1-12.73 0"/><line x1="12" y1="2" x2="12" y2="12"/></svg>
      </div>
      <h3 style="margin-bottom:12px;color:var(--txt)">Unlink Facility?</h3>
      <p style="color:var(--txt2);font-size:14px;line-height:1.6;margin-bottom:24px">
        Are you sure you want to remove <strong>${facName}</strong> from the <strong>${sys ? sys.name : 'System'}</strong> network?<br><br>
        This location has <strong>${staffCount}</strong> staff members enrolled. They will remain in the facility but will no longer roll up to system-level analytics.
      </p>
      <div style="display:grid;grid-template-columns:1fr 1fr;gap:12px">
        <button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
        <button class="btn btn-primary" style="background:var(--warn);border-color:var(--warn)" onclick="executeUnlinkFacility('${fid}')">Yes, Unlink Facility</button>
      </div>
    </div>
  `, 'modal-sm');
}

/**
 * Executes the unlinking after modal confirmation.
 */
function executeUnlinkFacility(fid) {
  closeModal();
  unlinkFacilityFromSystem(fid);
}

/**
 * Confirms unlinking a facility from a system (Legacy wrapper).
 */
function confirmUnlinkFacility(fid, facName, systemId) {
  promptUnlinkFacility(fid, facName, systemId);
}

/**
 * Removes the facility-system association.
 */
async function unlinkFacilityFromSystem(fid) {
  const fac = DB.facilities.find(f => f.id === fid);
  if (!fac) return;
  
  const systemId = fac.systemId;
  const sys = systemId ? DB.hospitalSystems.find(s => s.id === systemId) : null;
  
  try {
    // --- CLEAR PENDING LINKS ---
    const pendingLinks = JSON.parse(localStorage.getItem('sbd_pending_links') || '[]');
    const remainingLinks = pendingLinks.filter(l => l.facId !== fid);
    if (pendingLinks.length !== remainingLinks.length) {
      localStorage.setItem('sbd_pending_links', JSON.stringify(remainingLinks));
    }
    
    if (IS_LIVE && (window.SB || SB).updateFacility) {
      // ONLY Clear Facility System ID
      await (window.SB || SB).updateFacility(fid, { system_id: null });
    }
    
    // Optimistic update
    fac.systemId = null;
    if (sys && sys.facilityIds) {
      sys.facilityIds = sys.facilityIds.filter(id => id !== fid);
    }
    
    // Maintain legacy sync
    DB.systems = DB.hospitalSystems;
    
    // Recalculate benchmarking stats if system exists
    if (systemId && typeof calcSystemStats === 'function') calcSystemStats(systemId);
    
    toast('Facility unlinked', 'ok');
    
    // Context-aware refresh
    if (ST.portal === 'system_admin') {
      renderXView('x-facilities');
    } else if (ST.aView === 'a-systems-dashboard') {
      renderASystemsDashboard(systemId);
    } else {
      renderASystems();
    }
    
  } catch (err) {
    console.error('Unlink Error:', err);
    toast('Error unlinking facility: ' + err.message, 'err');
  }
}

/**
 * Navigates to a specific Hospital System's dashboard.
 */
function goSystemDashboard(sid, name) {
  ST.curSystemId = sid;
  document.getElementById('a-topbar-title').textContent = name + ' Dashboard';
  renderAView('a-systems-dashboard');
}

/**
 * Calculates aggregate performance metrics for a hospital system.
 */
function calcSystemStats(systemId) {
  const facilities = DB.facilities.filter(f => f.systemId === systemId);
  const staff = DB.staff.filter(s => facilities.some(f => f.id === s.fid));
  
  if (staff.length === 0) return { n: 0, green: 0, greenPct: 0, avgPoints: 0, facCount: facilities.length };
  
  const green = staff.filter(s => beltIdx(s.belt) >= 2).length;
  const totalPoints = staff.reduce((sum, s) => sum + (s.pts || 0), 0);
  const avgPoints = Math.round(totalPoints / (staff.length || 1));
  
  return {
    n: staff.length,
    green,
    greenPct: Math.round((green / (staff.length || 1)) * 100),
    avgPoints,
    facCount: facilities.length
  };
}

