/**
 * Calculates aggregate network-wide stats for comparison.
 */
function calcNetworkStats() {
  const staff = DB.staff;
  if (staff.length === 0) return { greenPct: 0, avgPoints: 0 };
  const green = staff.filter(s => beltIdx(s.belt) >= 2).length;
  const totalPoints = staff.reduce((sum, s) => sum + (s.pts || 0), 0);
  return {
    greenPct: Math.round((green / (staff.length || 1)) * 100),
    avgPoints: Math.round(totalPoints / (staff.length || 1))
  };
}

