/**
 * Persists a new hospital system to the database.
 */
async function createHospitalSystem() {
  const name = document.getElementById('new-sys-name').value.trim();
  const errMsg = document.getElementById('sys-err-msg');
  const btn = document.getElementById('sys-create-btn');
  
  if (errMsg) errMsg.style.display = 'none';

  if (!name) {
    if (errMsg) { errMsg.innerText = 'Please enter a system name'; errMsg.style.display = 'block'; }
    return toast('Please enter a system name', 'warn');
  }
  
  if (btn) { btn.disabled = true; btn.innerText = 'Creating...'; btn.style.opacity = '0.7'; }
  toast('Creating system...', 'info');
  try {
    let newSys = null;
    if ((window.SB || SB).createHospitalSystem) {
      console.log('SBD Platform: Creating system...', name);
      const res = await (window.SB || SB).createHospitalSystem({ name });
      if (res.error) throw res.error;
      
      const raw = res[0] || res.data?.[0] || res; // Handle various return shapes
      if (raw && (raw.id || raw.ID)) {
        if (typeof mapHospitalSystemFromBackend === 'function') {
          newSys = mapHospitalSystemFromBackend(raw);
        } else {
          newSys = { id: raw.id, name: raw.name, facilityIds: [] };
        }
        console.log('createHospitalSystem: Backend ID received:', newSys.id);
      } else {
        console.warn('createHospitalSystem: No ID returned from backend. Falling back to optimistic.');
        // Trigger active resolution - we will generate the ID next
      }
    }
    
    // Update local state immediately
    if (!newSys) {
      const tempId = 'sys-' + Date.now();
      newSys = { id: tempId, name: name, facilityIds: [] };
      // Start the hunt for the real UUID
      resolveSystemUUID(tempId, name);
    }
    
    const targetDB = window.DB || (typeof DB !== 'undefined' ? DB : null);
    if (targetDB) {
      if (!targetDB.hospitalSystems) targetDB.hospitalSystems = [];
      const index = targetDB.hospitalSystems.findIndex(s => s.id === newSys.id);
      if (index === -1) {
        // Use reassignment to trigger reactivity if any, or just be safe with references
        targetDB.hospitalSystems = [...targetDB.hospitalSystems, newSys];
      } else {
        const updated = [...targetDB.hospitalSystems];
        updated[index] = newSys;
        targetDB.hospitalSystems = updated;
      }
      // Sync legacy
      targetDB.systems = targetDB.hospitalSystems;
      console.log('createHospitalSystem: State updated successfully in targetDB, count:', targetDB.hospitalSystems.length);
      
      // Persist to localStorage if still optimistic
      if (newSys.id.startsWith('sys-')) {
        const optimistic = JSON.parse(localStorage.getItem('sbd_optimistic_systems') || '[]');
        if(!optimistic.some(s => s.name === newSys.name)) {
          optimistic.push(newSys);
          localStorage.setItem('sbd_optimistic_systems', JSON.stringify(optimistic));
          console.log('createHospitalSystem: Persisted to localStorage:', newSys.name);
        }
      } else {
        // Clean up this name if it existed as optimistic before
        const optimistic = JSON.parse(localStorage.getItem('sbd_optimistic_systems') || '[]');
        const filtered = optimistic.filter(s => s.name !== newSys.name);
        localStorage.setItem('sbd_optimistic_systems', JSON.stringify(filtered));
      }
    }
    
    console.log('createHospitalSystem: Success. Local state updated. Item:', newSys);
    toast('System created successfully', 'ok');
    closeModal();
    renderASystems();
    
    // Background refresh - delayed to allow DB persistence
    if(typeof initAppData === 'function') {
      console.log('createHospitalSystem: Triggering background re-hydration...');
      setTimeout(() => initAppData(), 1500); // Increased delay
    }
    
  } catch (err) {
    if (btn) { btn.disabled = false; btn.innerText = 'Create System'; btn.style.opacity = '1'; }
    console.error('Create System Error:', err);
    let msg = err.message || 'Unknown error';
    if(msg.toLowerCase().includes('duplicate') || msg.includes('23505')) {
      msg = 'A system with this name already exists.';
    }
    if (errMsg) { errMsg.innerText = msg; errMsg.style.display = 'block'; }
    toast('Error creating system: ' + msg, 'err');
  }
}

