  document.getElementById('a-topbar-title').textContent = 'System Comparison Matrix';
  const container = document.getElementById('a-systems-dashboard');
  if (!container) return;
  
  renderAView('a-systems-dashboard'); 

  const stats = systems.map(s => ({
    name: s.name,
    ...calcSystemStats(s.id)
  }));
  
  const network = calcNetworkStats();

  container.innerHTML = `
    <div style="margin-bottom:24px">
      <button class="btn btn-ghost btn-sm" onclick="renderAView('a-systems')" style="margin-bottom:16px;padding-left:0">
        <svg viewBox="0 0 18 18" fill="none" width="14" height="14" style="margin-right:6px;vertical-align:middle"><path d="M11 14l-5-5 5-5" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"/></svg>
        Back to All Systems
      </button>
      <div style="display:flex;justify-content:space-between;align-items:flex-end">
        <div>
          <div style="font-size:24px;font-weight:900;color:var(--gold);letter-spacing:-0.02em">Benchmarking Matrix</div>
          <div style="font-size:13px;color:var(--txt3);margin-top:4px">Side-by-side comparison of hospital system performance</div>
        </div>
      </div>
    </div>

    <div class="card" style="overflow-x:auto">
      <table class="tbl" style="width:100%;min-width:800px">
        <thead>
          <tr>
            <th style="background:rgba(0,0,0,0.2);position:sticky;left:0;z-index:2">System Variable</th>
            ${stats.map(s => `<th style="text-align:center;min-width:150px">${s.name}</th>`).join('')}
            <th style="text-align:center;color:var(--txt3);background:rgba(255,255,255,0.02)">Network Avg</th>
          </tr>
        </thead>
        <tbody>
          <tr>
            <td style="font-weight:700;background:rgba(0,0,0,0.2);position:sticky;left:0">Total Facilities</td>
            ${stats.map(s => `<td style="text-align:center;font-weight:700;color:var(--blue)">${s.facCount}</td>`).join('')}
            <td style="text-align:center;color:var(--txt3)">-</td>
          </tr>
          <tr>
            <td style="font-weight:700;background:rgba(0,0,0,0.2);position:sticky;left:0">Green Belt %</td>
            ${stats.map(s => {
              const delta = s.greenPct - network.greenPct;
              const col = delta >= 0 ? 'var(--ok)' : 'var(--warn)';
              return `<td style="text-align:center;font-weight:700;color:${col}">${s.greenPct}%</td>`;
            }).join('')}
            <td style="text-align:center;font-weight:800;background:rgba(255,255,255,0.02)">${network.greenPct}%</td>
          </tr>
          <tr>
            <td style="font-weight:700;background:rgba(0,0,0,0.2);position:sticky;left:0">Avg Member Pts</td>
            ${stats.map(s => {
              const delta = s.avgPoints - network.avgPoints;
              const col = delta >= 0 ? 'var(--gold)' : 'var(--warn)';
              return `<td style="text-align:center;font-weight:700;color:${col}">${s.avgPoints.toLocaleString()}</td>`;
            }).join('')}
            <td style="text-align:center;font-weight:800;background:rgba(255,255,255,0.02)">${network.avgPoints.toLocaleString()}</td>
          </tr>
          <tr>
            <td style="font-weight:700;background:rgba(0,0,0,0.2);position:sticky;left:0">Staff Count</td>
            ${stats.map(s => `<td style="text-align:center;font-weight:700;color:var(--txt)">${s.n}</td>`).join('')}
            <td style="text-align:center;color:var(--txt3)">${DB.staff ? DB.staff.length : 0}</td>
          </tr>
        </tbody>
      </table>
    </div>

    <div style="margin-top:24px" class="stat-card">
      <div style="display:flex;align-items:center;gap:12px">
        <div style="font-size:24px">💡</div>
        <div style="font-size:13px;color:var(--txt2);line-height:1.5">
          <b>Benchmarking Insight:</b> ${(() => {
            if (stats.length === 0) return 'No data available for benchmarking.';
            const top = stats.reduce((prev, curr) => (prev.greenPct > curr.greenPct) ? prev : curr);
            return `System <b>${top.name}</b> is currently leading the network with <b>${top.greenPct}%</b> Green Belt density.`;
          })()}
        </div>
      </div>
    </div>
  `;
