/**
 * Executes the system archiving after modal confirmation.
 */
async function executeArchiveHospitalSystem(sid) {
  closeModal();
  await archiveHospitalSystem(sid);
}

/**
 * Handles the soft-archiving of a hospital system.
 */
async function archiveHospitalSystem(sid) {
  if (window.SBD_INITIALIZING) return;
  toast('Archiving system...', 'info');
  
  try {
    console.log('SBD Platform: Commencing system archival for:', sid);
    
    // Soft-Archive in Backend
    if (IS_LIVE && (window.SB || SB).updateHospitalSystem) {
      if (String(sid).startsWith('sys-')) {
        console.log('archiveHospitalSystem: Optimistic ID detected, skipping backend call.');
      } else {
        await (window.SB || SB).updateHospitalSystem(sid, { active: false });
        console.log('API System Archival Success');
      }
    }

    // Update Local State (Atomic)
    if (window.DB && window.DB.hospitalSystems) {
      const sys = window.DB.hospitalSystems.find(s => s.id === sid);
      if (sys) sys.active = false;
      
      // Legacy sync
      window.DB.systems = window.DB.hospitalSystems;
    }

    toast('System archived successfully', 'ok');
    renderASystems();
    
    // Background refresh
    if(typeof initAppData === 'function') initAppData(); 
    
  } catch (err) {
    console.error('Archive System Error:', err);
    toast('Error archiving system: ' + (err.message || 'Unknown error'), 'err');
  }
}

/**
 * Manually retries the synchronization for a timed-out system.
 */
function retryHospitalSystemSync(sid) {
  const systems = window.DB?.hospitalSystems || [];
  const sys = systems.find(s => s.id === sid);
  if (!sys) return;
  
  sys.syncFailed = false;
  sys.syncAttempt = 0;
  toast(`Retrying sync for ${sys.name}...`, 'info');
  renderASystems();
  resolveSystemUUID(sys.id, sys.name);
}

/**
 * Actively resolves a temporary system ID into a real UUID by polling the backend.
 * Uses a registry to prevent duplicate polling loops for the same system.
 */
async function resolveSystemUUID(tempId, name, attempts = 0) {
  // 0. Registry check to prevent duplicate loops
  if (!window.SIPS_RESOLVING) window.SIPS_RESOLVING = new Set();
  const regKey = `sys-res-${name}`;
  
  if (attempts === 0) {
    if (window.SIPS_RESOLVING.has(regKey)) {
      console.log(`resolveSystemUUID: Already resolving ${name}, skipping duplicate start.`);
      return;
    }
    window.SIPS_RESOLVING.add(regKey);
  }

  // Increased max attempts to 60 (~5 minutes) to handle slow Supabase indexing or cold starts
  if (attempts >= 60) {
    console.warn(`resolveSystemUUID: Failed to resolve ${name} after 60 attempts.`);
    window.SIPS_RESOLVING.delete(regKey);
    
    // Set failure state in DB for UI feedback
    if (window.DB && window.DB.hospitalSystems) {
      const idx = window.DB.hospitalSystems.findIndex(s => s.name === name);
      if (idx !== -1) {
        window.DB.hospitalSystems[idx].syncFailed = true;
        window.DB.hospitalSystems[idx].syncAttempt = 60;
        renderASystems();
      }
    }
    return;
  }

  console.log(`resolveSystemUUID: Attempt ${attempts + 1} for ${name}...`);
  try {
    // Try Case-Insensitive search first for maximum reliability
    const res = await (window.SB || SB).getHospitalSystemByNameIlike(name);
    const raw = res[0] || res.data?.[0] || res;
    
    if (raw && raw.id) {
      console.log(`resolveSystemUUID: Found UUID for ${name}: ${raw.id}`);
      
      // Update Global DB
      if (window.DB && window.DB.hospitalSystems) {
        const systems = [...window.DB.hospitalSystems];
        // Note: we match by name because the temp ID might have changed on refresh
        const idx = systems.findIndex(s => s.name === name && String(s.id).startsWith('sys-'));
        if (idx !== -1) {
          systems[idx] = { ...systems[idx], id: raw.id, syncing: false, syncAttempt: 0 };
          window.DB.hospitalSystems = systems;
          window.DB.systems = systems; // legacy
          
          // Cleanup localStorage
          const optimistic = JSON.parse(localStorage.getItem('sbd_optimistic_systems') || '[]');
          const filtered = optimistic.filter(s => s.name !== name);
          localStorage.setItem('sbd_optimistic_systems', JSON.stringify(filtered));
          
          console.log(`resolveSystemUUID: State synchronized successfully for ${name}`);
          
          // --- POST-SYNC COMMITMENT: Resolve any optimistic links for this system ---
          const pendingLinks = JSON.parse(localStorage.getItem('sbd_pending_links') || '[]');
          const toCommit = pendingLinks.filter(l => l.tempSysId === tempId || l.systemName === name);
          
          if (toCommit.length > 0) {
            console.log(`resolveSystemUUID: Committing ${toCommit.length} pending links for ${name}`);
            for (const link of toCommit) {
              const fac = window.DB.facilities.find(f => f.id === link.facId);
              if (fac) {
                // Update memory ID to real UUID
                fac.systemId = raw.id;
                
                // Push to backend
                if ((window.IS_LIVE || IS_LIVE) && (window.SB || SB).updateFacility) {
                  try {
                    await (window.SB || SB).updateFacility(link.facId, { system_id: raw.id });
                    console.log(`resolveSystemUUID: Linked facility ${link.facId} to ${raw.id}`);
                  } catch (commitErr) {
                    console.error('resolveSystemUUID: Failed to commit pending link:', commitErr);
                  }
                }
              }
            }
            
            // Cleanup pending links
            const remainingLinks = pendingLinks.filter(l => l.tempSysId !== tempId && l.systemName !== name);
            localStorage.setItem('sbd_pending_links', JSON.stringify(remainingLinks));
          }
          
          window.SIPS_RESOLVING.delete(regKey);
          renderASystems();
          toast(`System "${name}" synchronized and ready.`, 'ok');
        }
      }
    } else {
      // Logic: Update attempt count in memory for UI feedback
      if (window.DB && window.DB.hospitalSystems) {
        const idx = window.DB.hospitalSystems.findIndex(s => s.name === name);
        if (idx !== -1) {
          window.DB.hospitalSystems[idx].syncAttempt = attempts + 1;
          renderASystems(); // Re-render to show progress
        }
      }
      
      // Retry with exponential backoff
      const delay = Math.min(1000 * Math.pow(1.2, attempts), 4000); 
      setTimeout(() => resolveSystemUUID(tempId, name, attempts + 1), delay);
    }
  } catch (e) {
    console.warn('resolveSystemUUID: Polling error:', e);
    setTimeout(() => resolveSystemUUID(tempId, name, attempts + 1), 5000);
  }
}

/**
 * Manually purges all optimistic hospital system records from localStorage and window.DB.
 * Used for administrative recovery if a system becomes stuck or out of sync.
 */
function cleanOptimisticCache() {
  console.log('SBD Platform: Purging optimistic cache...');
  localStorage.removeItem('sbd_optimistic_systems');
  localStorage.removeItem('sbd_pending_links');
  
  if (window.DB && window.DB.hospitalSystems) {
    // Filter out any IDs starting with 'sys-'
    window.DB.hospitalSystems = window.DB.hospitalSystems.filter(s => !String(s.id).startsWith('sys-'));
    window.DB.systems = window.DB.hospitalSystems;
    
    // Clear resolving registry if any
    if (window.SIPS_RESOLVING) {
      window.SIPS_RESOLVING.clear();
    }
    
    renderASystems();
    toast('Optimistic cache cleared.', 'info');
  }
}

// Inline role change from the All Staff table dropdown
function changeStaffRoleInline(staffId, newRole){
  const s = getStaff(staffId);
  if(!s) return;
  if(s.role === newRole) return; // no change
  const oldRole = s.role;
  promoteStaffPosition(staffId, newRole, ST.user?.name||'Admin');

  // \u2500\u2500 Sync linked user account level \u2500\u2500
  // Map position titles to portal access roles
  const positionToAccess = {
    'SPD Technician I':'staff_member',  'SPD Technician II':'staff_member',
    'SPD Technician III':'staff_member',
    'Lead Technician':'hospital',       'Shift Supervisor':'hospital',
    'Department Supervisor':'facility_admin',
    'SPD Manager':'facility_admin',
    'Director of Sterile Processing':'facility_admin'
  };
  const newAccess = positionToAccess[newRole];
  if(newAccess){
    // Find linked user account(s) for this staff member
    const linkedUsers = DB.users.filter(u => u.sid === staffId);
    linkedUsers.forEach(u => {
      // Only upgrade/adjust accounts at staff_member or hospital level
      // Never downgrade system_admin, staff_admin, or master_admin
      const protectedRoles = ['master_admin','staff_admin','system_admin'];
      if(!protectedRoles.includes(u.role) && u.role !== newAccess){
        const oldAccess = u.role;
        u.role = newAccess;
        console.log(`[Role] Account ${u.email}: portal access ${oldAccess} \u2192 ${newAccess}`);
        if(IS_LIVE && typeof SB !== 'undefined' && SB.updateUserProfile) {
          SB.updateUserProfile(u.authUid, { role: newAccess })
            .then(() => { if(SB.syncUserClaims) SB.syncUserClaims({ userId: u.authUid, role: newAccess }); })
            .catch(e => console.warn('[Role] User sync failed:', e.message));
        }
      }
    });
  }

  // Sync to backend if live
  if(IS_LIVE && typeof SB !== 'undefined' && SB.updateStaff) {
    SB.updateStaff(staffId, { role: newRole })
      .then(() => SB.getAllStaff ? SB.getAllStaff() : null)
      .then(staffData => {
        if(staffData) {
          DB.staff = typeof mapStaffFromBackend === 'function' ? staffData.map(mapStaffFromBackend) : staffData;
          if(window._sv === 'a-allstaff') renderAAllStaff();
        }
      })
      .catch(e => console.warn('[Role] Sync failed:', e.message));
  }
  toast(`${fullName(s)}: role updated <strong>${oldRole}</strong> \u2192 <strong>${newRole}</strong>`,'ok');
  
  // Re-render optimistically (don't lose scroll position)
  if(window._sv === 'a-allstaff') renderAAllStaff();
}
